-- Poems batch 137
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('aaf1ba2c-c410-4e41-82c6-fa05a77edb37','芙蓉橋','梁介','宋','宋诗','song-poetry','','[]','法{澽刂}瘴癘鄉，六月旱爍石。',75,'全唐诗/poet.song.144000.json','["法{澽刂}瘴癘鄉，六月旱爍石。", "榆柳秋不枯，蛇虺冬不蟄。", "長橋坐清虛，足以度朝夕。", "汲井埋深盆，芙蕖間紅白。", "幽香自氳氛，南薰爲披拂。", "雖無十丈花，有藕亦如蜜。"]'),
('695a35f3-077a-4667-98a7-8a196e1a30cf','南定樓','梁介','宋','宋诗','song-poetry','','[]','堂堂百尺樓，製作極華麗。',72,'全唐诗/poet.song.144000.json','["堂堂百尺樓，製作極華麗。", "山圍與水遶，秀色相嫵媚。", "上無狐鼠窺，下有魚龍畏。", "賓友升清虛，夷落聳瞻視。", "南陲粗安堵，北鄙方舉燧。", "倚樓獨何爲，尚下憂國淚。"]'),
('02e8d5a8-27bb-497b-9741-25c08c59b22c','止水亭','梁介','宋','宋诗','song-poetry','','[]','驚濤渺半空，怒勢突千里。',72,'全唐诗/poet.song.144000.json','["驚濤渺半空，怒勢突千里。", "此豈水性哉，物有激之耳。", "方塘尋丈間，一泓清且泚。", "鏡面燭須眉，水壑絕塵滓。", "道人修浄觀，此心如此水。", "不從苦海中，更放波瀾起。"]'),
('d0e98a2c-8acd-40a7-b3d6-fb683d2957ff','整暇堂','梁介','宋','宋诗','song-poetry','','[]','是邦無征科，爲吏不勞力。',72,'全唐诗/poet.song.144000.json','["是邦無征科，爲吏不勞力。", "今年到官初，牒訴頗紛集。", "大家張空簿，小家稱倍息。", "棄責爾未能，義取猶可給。", "風曉便革心，老我多暇日。", "夢回黯空庭，小憩華胥國。"]'),
('da9f9a12-da28-49b7-a9b7-3156cd469f4d','籌邊堂','梁介','宋','宋诗','song-poetry','','[]','籌邊無它長，幸此歲有秋。',72,'全唐诗/poet.song.144000.json','["籌邊無它長，幸此歲有秋。", "吏無打門宣，民無失業憂。", "史君來此邦，不但肉食謀。", "有言天命之，爲汝消窮愁。", "夷蜑及生齒，各異風馬牛。", "一醉堂上罇，莫運機與籌。"]'),
('e32efbde-5446-4fac-833e-6c23246fd016','登卧龍山送酒','梁介','宋','宋诗','song-poetry','','[]','五馬携壺上卧龍，四夔聯騎與游從。',32,'全唐诗/poet.song.144000.json','["五馬携壺上卧龍，四夔聯騎與游從。", "山中古柏歲寒色，應爲清流作意濃。"]'),
('4779742d-7054-4f09-ae1f-b3984a2e2b9d','遊道場山','沈清臣','宋','宋诗','song-poetry','','[]','松篁十里綠成谿，短短籃輿入翠微。',32,'全唐诗/poet.song.144000.json','["松篁十里綠成谿，短短籃輿入翠微。", "回首青山已成迹，隴頭猶見白雲飛。"]'),
('91b6db16-566e-474a-ae10-7a721803f673','嚴灘懷古','沈清臣','宋','宋诗','song-poetry','','[]','桐廬之山屹如址，桐江之水清見底。',64,'全唐诗/poet.song.144000.json','["桐廬之山屹如址，桐江之水清見底。", "間關萬里却歸來，依舊此山如此水。", "子陵一節壽漢脈，名與高山俱不死。", "惜無陋巷爲邦學，禮樂不聞古人耳。"]'),
('14a0f868-1477-46e2-9e6e-73c6ff437066','浣花亭','沈清臣','宋','宋诗','song-poetry','','[]','亭近城隈瞰古塘，數行官柳間羣芳。',64,'全唐诗/poet.song.144000.json','["亭近城隈瞰古塘，數行官柳間羣芳。", "沿隄草色連雲色，隔岸山光映水光。", "竹影日篩華徑邃，桂花風暢畫橋香。", "他年木拱垂陰合，還有邦人戒剪棠。"]'),
('2cc3e42c-b89a-45bd-921a-c8c62506aafe','僕久客錢塘有吹笛月下者同旅聞之淒然皆有歸思屬令賦之','李遠','宋','宋诗','song-poetry','','["\u897f\u6e56"]','柯亭之椽不復得，蘄州黄竹今尚存。',199,'全唐诗/poet.song.144000.json','["柯亭之椽不復得，蘄州黄竹今尚存。", "蒼崖翠壁産脩榦，千頃蕭索烟雲昏。", "羌人眼力發天巧，長笛裁成鳳膺飽。", "老龍餘響出空星，欲噴炎天作秋曉。", "西湖夜寂涼風生，山頭一鉤新月明。", "商聲悽悲羽聲壯，行子忽忽難爲情。", "時無綠珠清音激皓齒，野王臨風三弄亦已矣。", "唯有愁端無古今，舉刀不斷東流水。", "深閨蘭燈照空牀，笛聲不如離恨長。", "曲終人散一惆悵，回首江山非故鄉。", "萬事浮雲過寥廓，且醉盃中琥珀薄。", "君不見玉管橫吹黄鶴樓，江城五月梅花落。"]'),
('f868f2c0-c050-4d7b-a08d-9c9ac824caae','贈寫御真李長史','李遠','宋','宋诗','song-poetry','','[]','玉座烟銷硯水清，龍髯不動彩毫輕。',64,'全唐诗/poet.song.144000.json','["玉座烟銷硯水清，龍髯不動彩毫輕。", "乍分隆準山河秀，初點重瞳日月明。", "宮女卷簾皆暗認，侍臣開殿盡遥驚。", "六朝天下應無敵，始覺僧繇浪得名。"]'),
('9e11d668-330b-4181-afe7-3898f79ddfcd','失鶴','李遠','宋','宋诗','song-poetry','','[]','秋風吹却九皋禽，一片閒雲萬里心。',64,'全唐诗/poet.song.144000.json','["秋風吹却九皋禽，一片閒雲萬里心。", "碧落有情應悵望，青天無路可追尋。", "來時白雪翎猶短，去日丹砂頂漸深。", "華表柱頭留語後，不知消息到如今。"]'),
('61f80b17-4d0c-4ae4-9526-90753c7eac25','詠壁魚','李遠','宋','宋诗','song-poetry','','["\u548f\u7269\u8bd7", "\u5199\u9c7c", "\u548f\u7269"]','鱗細粉光鮮，開書亂眼前。',48,'全唐诗/poet.song.144000.json','["鱗細粉光鮮，開書亂眼前。", "透窗疑漏網，落硯似流泉。", "潛穴河淵內，吞鈎乙字邊。", "莫言鬐鬣小，食盡白蘋篇。"]'),
('bea7c686-4586-45e6-a8e5-56b96194dd03','句  其一','李遠','宋','宋诗','song-poetry','','[]','長日惟消一局棋。',8,'全唐诗/poet.song.144000.json','["長日惟消一局棋。"]'),
('5ab59998-21be-4d2a-b1c9-14e1cc5e030f','句  其二','李遠','宋','宋诗','song-poetry','','[]','紅壓驛邊樓。',6,'全唐诗/poet.song.144000.json','["紅壓驛邊樓。"]'),
('fc04c95e-1d2c-4803-aa64-4d7786c16e11','句  其三','李遠','宋','宋诗','song-poetry','','[]','釵斜穿綵燕，羅薄剪春蟲。',12,'全唐诗/poet.song.144000.json','["釵斜穿綵燕，羅薄剪春蟲。"]'),
('9ad2ad34-6229-4695-989f-a9d445eec682','遊樵嵐','李明','宋','宋诗','song-poetry','','[]','禪林晝靜寶坊新，花木陰深別樣春。',32,'全唐诗/poet.song.144000.json','["禪林晝靜寶坊新，花木陰深別樣春。", "不是紅塵飛不到，只因無處著紅塵。"]'),
('cba33b0d-cb68-44e8-abaf-a62ebff8f564','贈賈司教','柯岳','宋','宋诗','song-poetry','','[]','春風桃李絳帳，朝日苜蓿空盤。',28,'全唐诗/poet.song.144000.json','["春風桃李絳帳，朝日苜蓿空盤。", "王公不志溫飽，鄭老豈爲饑寒。"]'),
('50264571-f064-4684-9c1a-e25a5f0bb897','寶巖寺','姚愈','宋','宋诗','song-poetry','','[]','浮圖插雲表，列嶂環古剎。',48,'全唐诗/poet.song.144000.json','["浮圖插雲表，列嶂環古剎。", "平湖眇澄波，萬態天光發。", "我來陟層巔，秀氣助毫末。", "扁舟返明月，萬頃玻璃滑。"]'),
('524ef586-6168-4b4c-9b50-5061edc8b148','浄土院','姚愈','宋','宋诗','song-poetry','','[]','勁節摩雲歲月深，冰霜不改舊時陰。',64,'全唐诗/poet.song.144000.json','["勁節摩雲歲月深，冰霜不改舊時陰。", "靜浮香篆度幽徑，冷滴翠光生茂林。", "明月滿窗橫好墨，清風入指接黄金。", "箇中領取西方意，夢落人間何處尋。"]'),
('717a6d5a-9652-4a6c-bedd-72ad8f04d302','漢炳丹山晚進知學以來嘗於文字中敬識先生矣試吏赤水偶逢先生經由爲龍多少駐行旆出三詩以賁之漢炳不揆荒拙勉繼嚴韻  其一','樊漢炳','宋','宋诗','song-poetry','','[]','天仙下寓人間世，愛欲都忘只愛山。',32,'全唐诗/poet.song.144000.json','["天仙下寓人間世，愛欲都忘只愛山。", "更向馮仙問陳跡，煙蘿深處勇躋攀。"]'),
('e1741c99-66eb-4977-bede-07cbd4a47f69','漢炳丹山晚進知學以來嘗於文字中敬識先生矣試吏赤水偶逢先生經由爲龍多少駐行旆出三詩以賁之漢炳不揆荒拙勉繼嚴韻  其二','樊漢炳','宋','宋诗','song-poetry','','[]','此山勝處非人境，長有烟雲撥不開。',32,'全唐诗/poet.song.144000.json','["此山勝處非人境，長有烟雲撥不開。", "信是天公慳絕勝，晴曦端爲使君來。"]'),
('8aee2949-33cd-491c-aecd-8ce35b3ea8f0','漢炳丹山晚進知學以來嘗於文字中敬識先生矣試吏赤水偶逢先生經由爲龍多少駐行旆出三詩以賁之漢炳不揆荒拙勉繼嚴韻  其三','樊漢炳','宋','宋诗','song-poetry','','[]','披露已諧平日志，開雲須信大賢能。',32,'全唐诗/poet.song.144000.json','["披露已諧平日志，開雲須信大賢能。", "只餘天道終堪倚，不問人間愛與憎。"]'),
('3c6719db-e559-4da5-98d8-080cd402ee73','白藕','黄文度','宋','宋诗','song-poetry','','[]','白藕花前一信風，颯然吹雨到梧桐。',32,'全唐诗/poet.song.144000.json','["白藕花前一信風，颯然吹雨到梧桐。", "可憐一段淒涼意，併入西窗客夢中。"]'),
('96e776dc-1d9c-4d63-ba61-05ec4f0fd222','壽益垣丙午中元日生','黄維之','宋','宋诗','song-poetry','','[]','天祐熙朝世産賢，承平舊事並今傳。',64,'全唐诗/poet.song.144000.json','["天祐熙朝世産賢，承平舊事並今傳。", "萊公少避中元日，潞國同生丙午年。", "翰墨獨傳千古祕，聲名倔在二公先。", "功成野服平原去，要伴靈龜巢碧蓮。"]'),
('7b55e23b-ff45-4ba1-8534-cb84473a62e2','句','黄維之','宋','宋诗','song-poetry','','[]','九日溪頭携酒去，萬安橋上折花歸。',16,'全唐诗/poet.song.144000.json','["九日溪頭携酒去，萬安橋上折花歸。"]'),
('9ef9b0ab-567b-4f04-ac2e-b19e12b46f3b','勸農十首  其一','熊克','宋','宋诗','song-poetry','','[]','雪漬冰濡土脈肥，趁時舉趾莫教違。',32,'全唐诗/poet.song.144000.json','["雪漬冰濡土脈肥，趁時舉趾莫教違。", "荷蓑早合衝煙去，負耒遲須带月歸。"]'),
('8e964e54-d557-437c-a834-83a09322b6bc','勸農十首  其二','熊克','宋','宋诗','song-poetry','','[]','低田傍海仰依山，雨即橫流旱即乾。',32,'全唐诗/poet.song.144000.json','["低田傍海仰依山，雨即橫流旱即乾。", "時决時潴能自力，轉成沃壤不爲難。"]'),
('7ebe779d-7347-46d7-904c-6fcfa29cd209','勸農十首  其三','熊克','宋','宋诗','song-poetry','','[]','百昌萌動戴芒芽，小廩先儲種自嘉。',32,'全唐诗/poet.song.144000.json','["百昌萌動戴芒芽，小廩先儲種自嘉。", "天暖地腴當亟播，好蠲甲穀潤田家。"]'),
('47aeab84-9ca7-46cb-b047-a8eded339d01','勸農十首  其四','熊克','宋','宋诗','song-poetry','','[]','凡農主客兩相依，以富資貧政所宜。',32,'全唐诗/poet.song.144000.json','["凡農主客兩相依，以富資貧政所宜。", "要彼力耕吾有望，借糧借種莫遲遲。"]'),
('b81d8bb2-9873-4c5d-b51a-a59e9bdcf13e','勸農十首  其五','熊克','宋','宋诗','song-poetry','','[]','己田自種樂爲農，不肯勤耕奉主翁。',32,'全唐诗/poet.song.144000.json','["己田自種樂爲農，不肯勤耕奉主翁。", "勸汝回心毋見錯，秋成獲利兩家同。"]'),
('9e273d68-50c0-495b-ad2b-88b8e6f2d66e','勸農十首  其六','熊克','宋','宋诗','song-poetry','','[]','黄巖出穀半丹邱，使指新疏萬壑流。',32,'全唐诗/poet.song.144000.json','["黄巖出穀半丹邱，使指新疏萬壑流。", "築堰未妨齊著力，旱天隨取灌高疇。"]'),
('43d3def9-8f85-4016-a950-688ea15893a7','勸農十首  其七','熊克','宋','宋诗','song-poetry','','[]','午村茅舍起炊煙，夫带兒耕餒在田。',32,'全唐诗/poet.song.144000.json','["午村茅舍起炊煙，夫带兒耕餒在田。", "赤飯黄羹須婦饁，往來莫憚走東阡。"]'),
('b3682034-a1f8-445f-a6a3-705adaa9696c','勸農十首  其八','熊克','宋','宋诗','song-poetry','','[]','蠶月農須雨及時，三眠纔起食嫌遲。',32,'全唐诗/poet.song.144000.json','["蠶月農須雨及時，三眠纔起食嫌遲。", "采桑風雨無辭苦，指日繅成白雪絲。"]'),
('7727b697-6912-4d49-b5c7-5c8205867255','勸農十首  其九','熊克','宋','宋诗','song-poetry','','[]','臘時得雪喜重重，春到而今雨又通。',32,'全唐诗/poet.song.144000.json','["臘時得雪喜重重，春到而今雨又通。", "麥自十分堪指擬，更當力穡順年豐。"]'),
('8ebd8c9f-4a6a-41e8-9d46-bed83a983d5c','勸農十首  其一○','熊克','宋','宋诗','song-poetry','','[]','唆伊爭訟真伊賊，勸你休和是你師。',32,'全唐诗/poet.song.144000.json','["唆伊爭訟真伊賊，勸你休和是你師。", "縱使勝來耕已廢，得便宜處失便宜。"]'),
('f87c6030-503f-44f9-8107-f7ba0a83f5a2','壽芮祕書三首  其一','熊克','宋','宋诗','song-poetry','','[]','帝調玉燭召春還，仙袂同時度九關。',32,'全唐诗/poet.song.144000.json','["帝調玉燭召春還，仙袂同時度九關。", "萬品欲霑何處得，東風今起道家山。"]'),
('80a88ffb-c7a1-476d-b783-e6b1b19de1c6','壽芮祕書三首  其二','熊克','宋','宋诗','song-poetry','','[]','歸來未對小延英，便向蓬萊作主人。',32,'全唐诗/poet.song.144000.json','["歸來未對小延英，便向蓬萊作主人。", "要督仙宮讐玉籍，却收衆妙入經綸。"]'),
('048d6789-2d35-4ca7-9fac-6a410dc57568','壽芮祕書三首  其三','熊克','宋','宋诗','song-poetry','','[]','冊府都無未見書，毫端萬斛瀉明珠。',32,'全唐诗/poet.song.144000.json','["冊府都無未見書，毫端萬斛瀉明珠。", "若爲池上星辰履，謾與瀛洲作畫圖。"]'),
('4b6d611c-ee8d-41b2-a437-0baeaa095fd4','韓魏公讀書堂','熊克','宋','宋诗','song-poetry','','[]','去郡五里安國寺，斷蓬荒蓧成丘墟。',96,'全唐诗/poet.song.144000.json','["去郡五里安國寺，斷蓬荒蓧成丘墟。", "郡人不置瓜李嫌，公亦甘與泉石居。", "想憎俗事敗人意，獨願打火勤三餘。", "今人不出如處女，陋室屋暗百不如。", "聞君讀書胡乃爾，政恐心地忘芟鋤。", "前輩渾厚應有此，難弟難兄俱可書。"]'),
('2d663643-ea0f-427c-8f98-74b0dc286854','訪艮齋先生講學之所','熊克','宋','宋诗','song-poetry','','[]','克齋從學艮齋地，溪友幸從詩友遊。',64,'全唐诗/poet.song.144000.json','["克齋從學艮齋地，溪友幸從詩友遊。", "泉響如聞讀書韻，山容猶带濟時憂。", "嗚呼道在人何在，籍甚名留迹不留。", "欲揖高風寧復得，歸歟□□□抔□。"]'),
('89893b43-9ab4-449c-aa70-67611c6d7e80','葛仙山','熊克','宋','宋诗','song-poetry','','[]','秋風吹我衣，秋水洗我心。',204,'全唐诗/poet.song.144000.json','["秋風吹我衣，秋水洗我心。", "乘風直上葛仙頂，仙家樓閣烟霞深。", "蓬萊何曾弱水隔，兜率有天纔咫尺。", "等閑拍手倚闌干，驚起蛟龍移窟澤。", "試劍石老蒼苔封，洗藥池在丹砂紅。", "老仙騎鶴去未還，投崖何處尋遺蹤。", "霏霏濛濛天欲霜，神州萬里何茫茫。", "昆明水淺劫灰冷，幾見東海成田桑。", "洞簫吹斷月滿堂，夢中恍惚侍玉皇。", "覺來兩袖携天香，是非憂樂俱兩忘。", "驂騏麟，翳鳳凰，得與爾，高翱翔。", "仙翁一笑白雲上，贈我長房青竹杖。", "明朝去向葛溪濱，莫遣風雷驚世人。"]'),
('d012d50e-7d71-4c4b-aa0d-1fbaff87ceb2','任安仁縣秩滿歸過餘干縣臺山住寺僧云疇昔之夜夢神人呵之曰可出郊迎知縣公賦一絕以紀其事云','黄棆','宋','宋诗','song-poetry','','[]','年來蹤跡歎飄然，一笑相逢莫匪緣。',32,'全唐诗/poet.song.144000.json','["年來蹤跡歎飄然，一笑相逢莫匪緣。", "多謝老僧勤記我，預將消息夢中傳。"]'),
('f1d7f8ef-145f-4256-b3d1-2692ebac4035','再題松明寺次前題壁間韻','黄棆','宋','宋诗','song-poetry','','[]','怪若奇峰巧若何，衣冠到此苦無多。',64,'全唐诗/poet.song.144000.json','["怪若奇峰巧若何，衣冠到此苦無多。", "自慚登覽非能賦，敢覬雕鎸尚不磨。", "古寺殘僧猶記憶，嵐煙嶂雨幾噓呵。", "舊題莫辨蒼苔跡，多謝梅仙爲翦摩。"]'),
('84712455-4dbb-4512-856d-67e68be951ca','元日待漏院會宰執詩','黄棆','宋','宋诗','song-poetry','','[]','喜陪仙仗禁門前，餞臘賓春啟玳筵。',64,'全唐诗/poet.song.144000.json','["喜陪仙仗禁門前，餞臘賓春啟玳筵。", "其聽金雞報新歲，忽聞玉漏惜殘年。", "故鄉此去三千里，丹扆相違咫尺天。", "待罪諫垣無補報，惟輸樸直體蕃宣。"]'),
('a2fab1b1-3852-4d6a-a4b6-4f9d314f3d10','和嚴侍御柟木詩','楊虞仲','宋','宋诗','song-poetry','','[]','兩蒼崖屹相應對，上面虬龍插崖背。',130,'全唐诗/poet.song.144000.json','["兩蒼崖屹相應對，上面虬龍插崖背。", "青銅爲柯石爲根，上有蟲書篆籀破蘚痕。", "詰屈盤根少態度，深鎖窮山煙雨暮。", "不願作材戹萬牛，驚世之文那肯露。", "人不滿百雪滿頭，一生憂患幾許愁。", "湛輩去逐翁仲遊，此樹森森春復秋。", "杜陵筆墨光萬丈，當時憾不同清賞。", "獨寄黄花九日詩，雲間聲作琳琅響。"]'),
('9603cb45-90b8-481a-9673-a19a99409621','題崇福寺羅漢閣','趙汝能','宋','宋诗','song-poetry','','[]','閣上殊因子細看，幻成羅漢幾多般。',64,'全唐诗/poet.song.144000.json','["閣上殊因子細看，幻成羅漢幾多般。", "休驚五百神通異，自是三千世界寬。", "粉壁龍蛇渾欲動，石橋雲水亦生寒。", "香消日晚僧歸去，無限奇光發夜闌。"]'),
('e5fa9b32-9ad9-4f91-8b82-0d05a9289e8e','漫成','曹逢時','宋','宋诗','song-poetry','','[]','學書須學顔真卿，作詩須作陶淵明。',32,'全唐诗/poet.song.144000.json','["學書須學顔真卿，作詩須作陶淵明。", "其它泚筆本骫骳，便有風骨非天成。"]'),
('7aeea662-c5bb-4cb3-8dfd-6859166b59b8','句','曹逢時','宋','宋诗','song-poetry','','[]','撩我思家第一篇。',8,'全唐诗/poet.song.144000.json','["撩我思家第一篇。"]'),
('76e8143e-4fce-49de-a9c2-26ea181b6c03','句','袁鳳','宋','宋诗','song-poetry','','[]','坐觀天下本無事，何必昌陽作引年。',16,'全唐诗/poet.song.144000.json','["坐觀天下本無事，何必昌陽作引年。"]'),
('afe3e918-7462-48c3-aeed-488c8ed69589','寄上蘇邛州兼呈八座','史堯弼','宋','宋诗','song-poetry','','[]','稽首仇池翁，歸住小有天。',156,'全唐诗/poet.song.144000.json','["稽首仇池翁，歸住小有天。", "葛公尚遠孫，岣嶁丹山傳。", "道骨亦有種，而今見嬋嫣。", "大小茅山君，霞襜兩聯翩。", "弟兄對譚道，舌本風雷旋。", "嗟哉空山子，妄意身飛翾。", "忍饑嚙草木，閲歲烹汞鉛。", "豈知至妙門，端在玄中玄。", "知公夙領此，妙契遺蹄筌。", "神凝物無疵，合侍虛皇前。", "我亦山澤臞，會了區中緣。", "滅沒望仙鞚，願言執風鞭。", "相將丹丘上，一笑三千年。"]'),
('b81d3d72-1e83-4586-a793-952c1789f0f5','遊洛陽寶蓋寺贈長老道瓊','史堯弼','宋','宋诗','song-poetry','','[]','一念落人境，世路分崩奔。',168,'全唐诗/poet.song.144000.json','["一念落人境，世路分崩奔。", "車輪戰黄埃，荏苒還自昏。", "安知摩尼珠，豈處濁水渾。", "今我雖糾纏，猶有故我存。", "雲山時獨往，一笑清心魂。", "舊聞寶蓋峯，氣壓羣山尊。", "拂衣事幽討，烟杉轉山根。", "道人素所懽，踴躍欣候門。", "清眸夾明鏡，眈眈老彪蹲。", "招邀語密室，歡頰生春溫。", "往往到極則，寂歷雙忘言。", "從今塵境空，冰銷了無痕。", "但覺江漢流，浩蕩旋其源。", "至道默相喻，不許諸方論。"]'),
('35a82d49-6364-4d31-b041-2bbaef997c94','送章孝偁歸荆南','史堯弼','宋','宋诗','song-poetry','','[]','峩岷西南橫，盤石含靈光。',192,'全唐诗/poet.song.144000.json','["峩岷西南橫，盤石含靈光。", "有蓄不得發，澒洞難卷藏。", "泄爲萬夫豪，聯翩鬰相望。", "緬懷嘉祐初，赫赫都官郎。", "著龜抱先識，虎豹披其章。", "幕府西陲開，挾策驅酋羌。", "喑啞竟莫吐，反被按劍防。", "青天徒昭昭，萬里自投荒。", "直氣終凜冽，身仆心難僵。", "高平伊周徒，奏疏排未央。", "忠義一朝振，朱鳥吞光芒。", "還知百歲後，生此雛鳳凰。", "粲粲五色羽，欲下虞廷翔。", "先民重世德，君子思不忘。", "祝君期無忝，追攀軼飛揚。", "會使坤南隅，氣象還蒼茫。"]'),
('f6c523ac-984d-453e-baa4-48619288a553','次友生杜應求韻送中巖印老往成都正法','史堯弼','宋','宋诗','song-poetry','','[]','原原臨濟孫，一一孤峯峻。',192,'全唐诗/poet.song.144000.json','["原原臨濟孫，一一孤峯峻。", "舊來正法眼，不許窺閫仞。", "古路人迹絕，况復遺轍軔。", "只今誰健者，公亦師子迅。", "倚天劍氣寒，掣電目光瞬。", "平生縛虎手，肯擊死蛇陣。", "如何鬧市裏，撒手乃勇進。", "前時老狐臊，腥氣存已僅。", "傾河看洗滌，餘刃聊斥擯。", "坐令會府地，圜悟宗復振。", "緬思中巖老，今代無此雋。", "喜聞親嫡子，高提曩真印。", "要知天人師，此位那可閏。", "好去露鞭影，廣道收駔駿。", "睠言清浄關，莫遣衆魔磷。", "願爲一事大，他物非所贐。"]'),
('99512717-217a-45de-9497-9c97edeccf16','醉卧至夜半半醒中若有所愧者聞空庭石渠流水㶁㶁清亮不覺心體頓舒醉卧俱失因賦其所感','史堯弼','宋','宋诗','song-poetry','','[]','吾生少懽娛，遇酒增慨慷。',204,'全唐诗/poet.song.144000.json','["吾生少懽娛，遇酒增慨慷。", "殷床惟一眠，萬慮幾消亡。", "半夜還有覺，惕然喟中腸。", "世故何足道，誠恐此志荒。", "人生苦爲樂，我豈醒而狂。", "孰爲見在心，勿正能勿忘。", "涓涓石渠溜，起予者卜商。", "泠然落枕寒，解渴不待嘗。", "坐令肝肺間，一一流天漿。", "須臾四體喻，髮膚了無癢。", "夢覺與醉醒，忽落俱亡羊。", "流水去不舍，此心湛如常。", "恍疑奏簫韶，儀鳳碧雲翔。", "眷此聽愈淡，杳誰見其鄉。", "乃知天宇中，一氣同蒼凉。", "平明視渠水，非笙亦非簧。", "矢詩以自歌，濁清付滄浪。"]'),
('6b310165-aeb8-452b-b346-dd6f5225f589','連州守王大寶元龜建雙溪閣於放生池上爲作詩以效頌祝','史堯弼','宋','宋诗','song-poetry','','[]','二流西北來，東迤方茫洋。',204,'全唐诗/poet.song.144000.json','["二流西北來，東迤方茫洋。", "斗岸蒼石裂，突兀森塹防。", "邦伯此經始，華榱壓崇岡。", "下俯古泓碧，上粲新高堂。", "恭惟繞樞辰，朱旛照滄浪。", "銀刀决網散，摇漾涵恩光。", "冠劍擁呼舞，穉耋紛歡康。", "我亦歌且謠，請祝天無疆。", "緬思長淮北，忽焉惄中腸。", "餘黎尚網罟，割烹燎其湯。", "戢戢生理微，豈足膏銛鋩。", "吁嗟中道呼，西江誰爲揚。", "湟流去沄沄，佇立東南望。", "安能挽溟渤，一洗濡沫場。", "八荒共靈沼，四海爲濠梁。", "帝力爾何知，江湖永相忘。", "陛下千萬壽，樂愷未渠央。"]'),
('8d3d837e-8b09-4666-aa6f-77f4f01124b3','同馮蓬州當可遊中巖分韻得林字','史堯弼','宋','宋诗','song-poetry','','[]','羲和轉日轂，北陸鞭窮陰。',156,'全唐诗/poet.song.144000.json','["羲和轉日轂，北陸鞭窮陰。", "天地不自持，年老去如駸。", "卉木浩萎垂，江山動蕭森。", "變化故不干，樂哉此幽尋。", "蓬州老摩詰，玉齒鏘璆琳。", "相携亦忘言，一笑孤雲岑。", "至人鷲峯來，分坐茲巖深。", "攝衣請從之，宛如在中林。", "聊欲薦清供，無物致所歆。", "端有白月輪，炯然碧潭心。", "賞會詎偶然，夙昔諒合簪。", "別去莫慘惻，渠無去來今。", "當有羲黄人，嘗識太古音。"]'),
('f82f2786-0a7f-4c4f-aeb6-b39c18bd0a56','再別譙宰','史堯弼','宋','宋诗','song-poetry','','[]','相逢恨不早，相別苦相逼。',120,'全唐诗/poet.song.144000.json','["相逢恨不早，相別苦相逼。", "相對若無言，相望恐相憶。", "夙期夫君深，寤寐先已識。", "歲晚飛雙鳬，此地見顔色。", "爲我作眼青，窈窕間心臆。", "誰言淡如水，有味寧忘得。", "塵裏詎可堪，高才未宜抑。", "平生趙魏優，教育儻其職。", "菁菁在中沚，行矣要封植。", "扶摇那知程，聊爾六月息。"]'),
('497ce945-148b-4cd7-b540-a8070b47524f','靜心堂','史堯弼','宋','宋诗','song-poetry','','[]','曲士懷軒裳，銖寸較得失。',288,'全唐诗/poet.song.144000.json','["曲士懷軒裳，銖寸較得失。", "紛紜戰寵辱，矛盾相撞抶。", "大方惟達人，天游寄虛室。", "卷舒儻由己，出處要無必。", "時來作砭針，一起當療疾。", "時去收龍蛇，夭矯自超逸。", "隠見了無礙，妙迹那可詰。", "我公天人姿，宿有補天術。", "心緣靜見理，心靜與天一。", "當年風雨會，黄道賓出日。", "乾坤方瘡痍，塗炭入憂恤。", "神鋒指幽燕，酋領將斧鑕。", "世數有長消，忽忽謝簪紱。", "歸來卧林藪，道自無伸屈。", "慶堂示餘彥，親洒銀筆述。", "聊遺郢人斤，千載斫妙質。", "定應山水觀，中與胸趣匹。", "仰看衡雲飛，雲靜山崒嵂。", "俯盼湘流水，舟楫空蕩潏。", "可憐天東北，狼烟暗鬰律。", "神州見蒼莽，悲風爲蕭瑟。", "再拜願有期，經綸勿韜鬰。", "天心酌民言，公再調鼎實。", "風霆驅八荒，遊戲須一出。"]'),
('06a241bd-d768-488a-93e0-6fc9b7667f8a','故仁壽簿張府君挽詩覽府君事狀見其居靖康國難時讀李晟傳慷慨不覺淚下衋然有感於中作詩哀之','史堯弼','宋','宋诗','song-poetry','','[]','羊肸與鬷蔑，雅好非宿敦。',216,'全唐诗/poet.song.144000.json','["羊肸與鬷蔑，雅好非宿敦。", "携手遽升堂，一語不待煩。", "物理適相感，豈用疏戚論。", "夫君今則亡，遺言空復存。", "乃能使余悲，覽之涕瀾翻。", "曩在歲丙午，烽烟塞天閽。", "四溟波蕩沃，公方卧山樊。", "忽撫西平傳，憤悶神飛鶱。", "尚想繡帽翁，凜凜躬櫜鞬。", "指顧還兩都，筍簴安陵園。", "唐家有遺黎，不識金鼓喧。", "掩卷淚如迸，汗簡猶班痕。", "平時閭閻中，聊乘下澤轅。", "豈知中激烈，感慨在元元。", "斯言當余意，爲慟聲復吞。", "但聞神州地，晝暝煙塵昏。", "故老不可得，華屋今丘墦。", "九原儻作興，余欲重與論。"]'),
('550b6640-6a2b-48f5-aa1f-297bf51d68ad','孫叔度挽詩','史堯弼','宋','宋诗','song-poetry','','[]','簡州古遺直，冰雪映當代。',120,'全唐诗/poet.song.144000.json','["簡州古遺直，冰雪映當代。", "茫茫幾回首，凜凜欲無對。", "居無屋漏愧，動必繩墨內。", "秋風看獨立，縹緲一蘭佩。", "從先大夫游，持此儻無悔。", "何意寥闃中，值此一門再。", "有馬誰千駟，曾無德與載。", "富貴饕一指，回首失肩背。", "夷惠百世師，曹李九泉輩。", "丘原餘慟哭，天地日蕪穢。"]'),
('e0722ac0-2be8-4769-acb2-c799314709f6','將至江州中流見庾樓慨然有感作庾樓行','史堯弼','宋','宋诗','song-poetry','','[]','江州江城赤如赭，江吞孤城去如瀉。',160,'全唐诗/poet.song.144000.json','["江州江城赤如赭，江吞孤城去如瀉。", "忽然華楹出城角，庾公之樓高照野。", "雲空翬飛粲丹雘，樹杪鱗差排碧瓦。", "行人轉盼居人誇，云道風流有存者。", "庾公當年志恢拓，神姿從來本夷雅。", "偶驅百萬攖虎狼，反旆南歸惟匹馬。", "如何倚欄向北顧，坐俯驚湍弄盃斝。", "豈知宗國風燈似，膏盡煙空欲煨炧。", "朅來撫事一悲慨，淚落清波爲誰灑。", "細思興替總人爲，有昊何能擅坯冶。"]'),
('0fe77d71-e56c-44c4-860c-7a771f98ea9b','東丁洞效江西體次知難韻','史堯弼','宋','宋诗','song-poetry','','[]','洞中滴瀝幾何深，猶有太古之遺音。',64,'全唐诗/poet.song.144000.json','["洞中滴瀝幾何深，猶有太古之遺音。", "我來一唱三嘆息，關雎之樂元非淫。", "無聲也復鳴東丁，入耳偏向幽人清。", "端勝惠山味甘好，奔走水驛煩瓶罌。"]'),
('513aebdb-4966-4531-96b0-ab37707eadef','春晚飲西湖上歸借榻吳山睡起偶作','史堯弼','宋','宋诗','song-poetry','','["\u897f\u6e56"]','旅愁底物堪破除，閒出西湖弄妍靡。',96,'全唐诗/poet.song.144000.json','["旅愁底物堪破除，閒出西湖弄妍靡。", "蒼山爲鬢水爲鑑，烟幕霓裳秀而綺。", "興酣劇飲醉如泥，妄意將湖比西子。", "傍人見之爲絕倒，謂我愚癡長康似。", "歸來寂歷竟何得，只有熏熏黑甜美。", "夢魂依舊過西湖，潮怒殷床驚不起。"]'),
('8ee783b3-1779-4c5e-af90-76bf3ada5fb2','謁周侍郎','史堯弼','宋','宋诗','song-poetry','','[]','大江之南英靈窟，瑰奇萬古輸不竭。',288,'全唐诗/poet.song.144000.json','["大江之南英靈窟，瑰奇萬古輸不竭。", "往年鼓柁窮壯觀，見公更覺人超越。", "當時持橐趨明光，徑度蓬山跨奉常。", "漢儀周典一朝重，斧藻皇度看翱翔。", "只今自合補衮闕，元有胸中絲五色。", "如何一麾渺江海，扶摇未嫌六月息。", "此邦齊魯伯仲間，鄉來文物餘班班。", "天遣儒宗作邦伯，風流正始應追還。", "老稚何知但呼舞，平易近民吾父母。", "悃愊無華兩京似，宴坐黄堂物安堵。", "小人不識衡氣機，况知道學窮精微。", "羲文孔聖演三畫，後來百代誰傳衣。", "圖書不見出河洛，禹箕九疇那復作。", "一時覆瓿笑迂闊，子雲太玄亦寂寞。", "振起此學非公誰，心匠妙處璣衡齊。", "定知數術本天授，無乃太一燃青藜。", "草玄遺編當不朽，還許侯芭傳業否。", "舊來嘗辱河南幸，從今肯在諸生後。"]'),
('3a3d5c16-7859-4eff-b9ea-373d2c47740b','留題丹經卷後','史堯弼','宋','宋诗','song-poetry','','[]','武陵郡西桃花源，水盩山厔蠻區連。',384,'全唐诗/poet.song.144000.json','["武陵郡西桃花源，水盩山厔蠻區連。", "秦人避秦久寓此，種桃千樹春風前。", "落紅滿地溪路斷，魚郎捨舟得洞天。", "瑞光浮動見宮室，桑竹交映膏腴田。", "蒼崖老木含太古，民物朴野天理全。", "男耕女織無租痛，鷄鳴犬吠通陌阡。", "東家西家走相問，客來何許今何年。", "歷將時事爲具言，二世不守嬴氏顛。", "人心歸漢沛公起，四百餘載瞞竊焉。", "迄今已復爲晉有，尚何懼死長城邊。", "豈知世態多廢興，聞之撫髀皆喟然。", "辭歸未許留數日，陳列俎豆如賓筵。", "生逢樂土自可樂，山林朝市非相懸。", "明朝棹開落塵境，恍如夢破陵谷遷。", "淵明一記故實在，世俗竟作神仙傳。", "裹糧問道不復往，大笑子驥真無緣。", "我今置酒嶂峰巔，醉袖起舞凌風烟。", "大還有訣誰所傳，始自廣成授黄髯。", "髯龍上征老聃出，谷神立說洪其源。", "陰符黄庭龍虎經，伯陽契易誠多端。", "况復後學如牛毛，支分派別徒紛然。", "先天一氣誰真知，來如陽德升九淵。", "疾雷破山坤軸裂，政要主者定力堅。", "前絃之後後絃前，藥物不可錙銖偏。"]'),
('68cf049e-7874-4d35-a72f-f94ea49c2a07','賀楊綿州除武陵守','史堯弼','宋','宋诗','song-poetry','','[]','越王樓前佳氣浮，涪翁江上恩波流。',128,'全唐诗/poet.song.144000.json','["越王樓前佳氣浮，涪翁江上恩波流。", "幾年結佩作邦相，萬物氣吐人歌謳。", "白鶴池邊嗟來暮，武陵溪畔桃花路。", "忽傳芝檢九天來，會擁朱旛兩輪去。", "轅攀蹬截無留停，痒爬垢櫛待蘇酲。", "仙人延貯一笑喜，探丸付授真長生。", "老成自合朝家用，未許三刀頻入夢。", "鶴髮行趨鴛鷺班，更作吾州九鼎重。"]'),
('04946887-f172-4fcd-8d5a-8a4ac6fb7229','送胡庭美解成都筦庫赴鳳州學宮','史堯弼','宋','宋诗','song-poetry','','[]','署鼓鼕鼕大府闢，斂板爭趨後先入。',64,'全唐诗/poet.song.144000.json','["署鼓鼕鼕大府闢，斂板爭趨後先入。", "歸來坐曹吏接肘，簿領埋頭課銖粒。", "學宮柳摇晝日長，清風卷舒編簡香。", "紛紛燕雀稻粱急，往聽鸑鷟鳴岐陽。"]'),
('126a501b-bb32-4724-8ef5-ccd7ed1b0656','大海水','史堯弼','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','大海湯湯水所積，太山巖巖雲所出。',68,'全唐诗/poet.song.144000.json','["大海湯湯水所積，太山巖巖雲所出。", "翻騰一俛仰，能爲雨三日。", "旱苗滋生物滋殖，田夫得耕女得績。", "式歌且謠拜手乞，泰山雲，勿紆鬰。", "大海水，無終極。"]'),
('f7fa8a09-260d-458d-b9bf-47c308eb86b1','題大光寺詩','史堯弼','宋','宋诗','song-poetry','','[]','百轉細落修蛇蟠，兩間螺髻巉青巒，其下碧澗流清寒。',168,'全唐诗/poet.song.144000.json','["百轉細落修蛇蟠，兩間螺髻巉青巒，其下碧澗流清寒。", "天旋路盡不復去，環爲絕嶂凌空攢。", "傖儜左右更折旋，攝伏犀虎蹲猊狻。", "忽然覆釜落山趾，化出寶宇中平寬。", "石床曩事知有無，猖狂欲往心渺漫。", "空憶盛時元壯觀，鳴鐘擊鼓侵雲端。", "天魔禠魄不敢干，那知劫災須臾間。", "淒涼瓦礫荒叢菅，但存四壁空青山。", "興亡一去寧復還，獨遣道者身苦難。", "我喟而作坐長歎，乞爲白雲千歲閑。"]'),
('c951fb8f-de0b-4b02-bf18-8463d2aa5bd0','贈友人','史堯弼','宋','宋诗','song-poetry','','[]','悼往不知籬菊芳，豈知籬外遊人忙。',128,'全唐诗/poet.song.144000.json','["悼往不知籬菊芳，豈知籬外遊人忙。", "寒暄節物覆手異，依然大樹堪彷徨。", "羨君真比道州政，間飲醇酒南山陽。", "遥想文殊造摩詰，玄妙深談舌廣長。", "中道相呼互濡沫，相忘各適遮無傷。", "要知風鬟太華女，夫豈秋思悲空房。", "智拙方疏漢陰圃，才多端謝鼂生囊。", "青天自不憎白眼，好在宗之快舉觴。"]'),
('f691d277-dda5-4859-b1f1-795d708804b0','癸亥秋陪張丞相遊西湖和周去華機宜韻二首  其一','史堯弼','宋','宋诗','song-poetry','','["\u897f\u6e56"]','天上辭魁柄，拂衣巖石間。',48,'全唐诗/poet.song.144000.json','["天上辭魁柄，拂衣巖石間。", "乾坤雙眼靜，日月一身閑。", "目極朝東水，心懷直北山。", "應憐沙際雁，亦解向陽關。"]'),
('e8a2b08d-1348-4e27-853b-f87df4dcd0a1','癸亥秋陪張丞相遊西湖和周去華機宜韻二首  其二','史堯弼','宋','宋诗','song-poetry','','["\u897f\u6e56"]','幸陪雙絕巘，偶念莽蒼間。',48,'全唐诗/poet.song.144000.json','["幸陪雙絕巘，偶念莽蒼間。", "野旱經時赤，行雲盡日閑。", "蕭蕭看脫木，悄悄對空山。", "幾欲兼忘去，江湖獨往還。"]'),
('ba1ecf40-e946-4242-9fc0-d39376f53432','重題湖上','史堯弼','宋','宋诗','song-poetry','','[]','林端落照盡，湖上遠風清。',48,'全唐诗/poet.song.144000.json','["林端落照盡，湖上遠風清。", "水榭芝蘭室，仙舟魚鳥情。", "人琴何寂寞，煙月足平生。", "一泛釣璜處，再吟鏘玉聲。"]'),
('fb2bf684-bce9-4a67-a54e-38def6955ffc','白雲閣','史堯弼','宋','宋诗','song-poetry','','[]','閣虛雲出沒，雲閣兩無心。',48,'全唐诗/poet.song.144000.json','["閣虛雲出沒，雲閣兩無心。", "旌旆千山立，笙竽萬籟深。", "相君聊暇日，籃輿得幽尋。", "徙倚天東北，狼煙猶爾侵。"]'),
('18d962c5-0cb9-4bf0-a58e-2057635b15d2','送青神宰樊允南解官次杜應求韻  其一','史堯弼','宋','宋诗','song-poetry','','[]','折腰真漫爾，掉鞅忽班如。',48,'全唐诗/poet.song.144000.json','["折腰真漫爾，掉鞅忽班如。", "心委身來去，人懷政卷舒。", "宦遊三釜計，臭味一編書。", "此道儻同趣，何曾有別歟。"]'),
('5b9e2d80-3b56-45dc-a823-f24f304df886','送青神宰樊允南解官次杜應求韻  其二','史堯弼','宋','宋诗','song-poetry','','[]','簿領侵尋地，淹留寄此鄉。',48,'全唐诗/poet.song.144000.json','["簿領侵尋地，淹留寄此鄉。", "相逢譚笑共，不覺歲年長。", "物色重陽近，秋高萬象藏。", "賦歸三徑裏，籬菊有餘香。"]'),
('69e4848a-679a-4056-8c36-fcf9c2c055ff','送青神宰樊允南解官次杜應求韻  其三','史堯弼','宋','宋诗','song-poetry','','[]','從昔安平易，無心問疾遲。',48,'全唐诗/poet.song.144000.json','["從昔安平易，無心問疾遲。", "纔知中自守，不逐世多岐。", "赫赫寧期譽，悠悠去有思。", "豐碑人口是，看取祖行詩。"]'),
('38993128-2fe9-4c76-9c97-9587a234d51a','送青神宰樊允南解官次杜應求韻  其四','史堯弼','宋','宋诗','song-poetry','','[]','並轡中巖寺，芳樽一破愁。',48,'全唐诗/poet.song.144000.json','["並轡中巖寺，芳樽一破愁。", "更寒譚衮衮，雲曉玉浮浮。", "會有相從樂，還如此地不。", "合離真有數，那敢作人謀。"]'),
('04577a69-c1c8-49ff-91ec-8639e7f1d94a','舟過黄州上赤壁因懷東坡偶題','史堯弼','宋','宋诗','song-poetry','','[]','赤壁今朝過，蒼梧幾日期。',48,'全唐诗/poet.song.144000.json','["赤壁今朝過，蒼梧幾日期。", "天旋疑水遠，風怒恐檣危。", "斷岸餘千丈，英雄只一時。", "多情雪堂老，月白夜探奇。"]'),
('74511f71-7cca-402b-93da-8778da3d1505','黄雀餉隠者文素翁其人有天文歷數之學','史堯弼','宋','宋诗','song-poetry','','[]','珍重文夫子，山林日月長。',48,'全唐诗/poet.song.144000.json','["珍重文夫子，山林日月長。", "譚天鄒衍口，痛飲伯倫鄉。", "宴坐看飛動，相呼死稻粱。", "黄腴風味好，聊足薦君觴。"]'),
('62de2815-265b-415e-939e-55bd820de4ee','古松','史堯弼','宋','宋诗','song-poetry','','[]','人之生也直，此物自長年。',48,'全唐诗/poet.song.144000.json','["人之生也直，此物自長年。", "霧雨晦深谷，風雲乘半天。", "扶危正須爾，得道亦超然。", "慘澹空回盼，長吁立暝烟。"]'),
('fbe87ec0-fe9d-4b71-9213-44fcd24d8cdf','贈別  其一','史堯弼','宋','宋诗','song-poetry','','[]','江湖聞遠役，風雨弄扁舟。',48,'全唐诗/poet.song.144000.json','["江湖聞遠役，風雨弄扁舟。", "邂逅逢吾子，周旋寫我憂。", "雲瞻三峽晦，波動五湖秋。", "恨別休驚鳥，相忘已兩鷗。"]'),
('f6c9a789-8945-4c36-a9f3-988bf7b8849f','贈別  其二','史堯弼','宋','宋诗','song-poetry','','[]','天地有佳處，岷峩橫翠微。',48,'全唐诗/poet.song.144000.json','["天地有佳處，岷峩橫翠微。", "茅廬介山趾，嵐色入書幃。", "共社公應可，論心我亦稀。", "他年能似約，江漢會思歸。"]'),
('cc0a2cdb-4e63-4748-861c-a8d30a43cd81','送譙允蹈解青神赴永康學官二首  其一','史堯弼','宋','宋诗','song-poetry','','[]','簿領塵埃地，淹回歲月闌。',48,'全唐诗/poet.song.144000.json','["簿領塵埃地，淹回歲月闌。", "青山應有素，去路肯留難。", "吏隠寧官冷，心清則體胖。", "不嫌時拄笏，三十六峯寒。"]'),
('ad9d71a2-4702-473e-8c0e-746b68ca12f7','送譙允蹈解青神赴永康學官二首  其二','史堯弼','宋','宋诗','song-poetry','','[]','亦有澹臺者，時升單父堂。',48,'全唐诗/poet.song.144000.json','["亦有澹臺者，時升單父堂。", "匆匆能幾見，忽忽兩相忘。", "明日舞雩地，薰風編簡香。", "策勳歸聖域，此道久微茫。"]'),
('91611905-5436-441c-b221-25773c017d58','挽故眉守張廷琛  其一','史堯弼','宋','宋诗','song-poetry','','[]','伊人湖海士，夙昔想風流。',48,'全唐诗/poet.song.144000.json','["伊人湖海士，夙昔想風流。", "决策元戎幕，宣威塞北秋。", "分遼空往恨，保蜀尚前籌。", "落寞三刀夢，真成取次休。"]'),
('aace318b-0526-4e9a-8a53-d11ade53b771','挽故眉守張廷琛  其二','史堯弼','宋','宋诗','song-poetry','','[]','碣石崢嶸歲，何如扣帝閽。',48,'全唐诗/poet.song.144000.json','["碣石崢嶸歲，何如扣帝閽。", "狼煙今晝晦，鯨海正波翻。", "遺恨公流涕，當時獨抗言。", "荒阡新宰木，誰酹曲江魂。"]'),
('67088ca3-5e89-4bd6-9fdd-8d38bd29e4fc','挽故眉守張廷琛  其三','史堯弼','宋','宋诗','song-poetry','','[]','公典吾州日，人懷不忍欺。',48,'全唐诗/poet.song.144000.json','["公典吾州日，人懷不忍欺。", "轅攀那復得，巷哭竟成悲。", "外祖松楸在，空山草木萎。", "魂遊儻來否，尚作凱風思。"]'),
('60921876-41ad-4552-852a-c82b1f53f9be','挽宋邑宰','史堯弼','宋','宋诗','song-poetry','','[]','充宇蠅頭字，寒更豹體膏。',48,'全唐诗/poet.song.144000.json','["充宇蠅頭字，寒更豹體膏。", "當時書雁塔，晚歲試牛刀。", "便作泉臺去，難酬雪案勞。", "鳳雛家學在，飛翥看秋高。"]'),
('48158d88-d827-4542-bd0a-8fc514fe555b','楊夫人挽詩','史堯弼','宋','宋诗','song-poetry','','[]','奉嬪歸盛族，觀奠及遺芳。',48,'全唐诗/poet.song.144000.json','["奉嬪歸盛族，觀奠及遺芳。", "藻已空南澗，萱應茂北堂。", "人間空墮驥，地下復鳴凰。", "慘慘聞吹棘，紛紛想斷腸。"]'),
('cb109636-c494-4fd7-a658-b0b546349973','挽程淳老  其一','史堯弼','宋','宋诗','song-poetry','','[]','宣和全盛日，經畧府潭潭。',48,'全唐诗/poet.song.144000.json','["宣和全盛日，經畧府潭潭。", "智出人千百，時資策二三。", "福星須爾往，邊瑣定誰堪。", "幾輩能華髮，猗歟北斗南。"]'),
('b99b41a4-c636-45b3-93ff-5de697434c83','挽程淳老  其二','史堯弼','宋','宋诗','song-poetry','','[]','戒定通前念，蘇黄早見期。',48,'全唐诗/poet.song.144000.json','["戒定通前念，蘇黄早見期。", "源流知衮衮，金印漫纍纍。", "白首風塵外，丹砂歲月遲。", "泉臺無復恨，喬木有餘悲。"]'),
('fc5ef326-6aff-4832-b3d5-52297bd44f3f','挽劉中遠侍郎  其一','史堯弼','宋','宋诗','song-poetry','','[]','神主多艱日，歸安九廟中。',48,'全唐诗/poet.song.144000.json','["神主多艱日，歸安九廟中。", "忌才終引去，退卧敢論功。", "未省真忘世，嘗疑數悟空。", "欲諮黄髮老，几杖合扶公。"]'),
('d5f2c9e4-71d5-406f-9cf7-174ef7b4a567','挽劉中遠侍郎  其二','史堯弼','宋','宋诗','song-poetry','','[]','精神曾感會，帝念老臣餘。',48,'全唐诗/poet.song.144000.json','["精神曾感會，帝念老臣餘。", "內閣陞嚴直，褒章賜命書。", "同時那得有，回首却成虛。", "露電從渠過，吾遊自物初。"]'),
('dcb193b2-a1be-48ec-b3e1-d7d519b104f1','挽劉中遠侍郎  其三','史堯弼','宋','宋诗','song-poetry','','[]','沄沄綠水邊，丈室一蕭然。',48,'全唐诗/poet.song.144000.json','["沄沄綠水邊，丈室一蕭然。", "顧陸留青箬，宗雷老白蓮。", "研朱看點易，摇麈聽談玄。", "忽忽風流盡，長懷晉宋前。"]'),
('b7cb059c-9491-4356-9a23-fe15b3b02e56','挽劉中遠侍郎  其四','史堯弼','宋','宋诗','song-poetry','','[]','故國餘喬木，蕭條今作哀。',48,'全唐诗/poet.song.144000.json','["故國餘喬木，蕭條今作哀。", "舂容思曩昔，懷抱復誰開。", "浩劫真難詰，微言不重陪。", "未忘吾里在，華表一歸來。"]'),
('b5fe0c18-623c-4e6c-a7a6-92f57cac899f','挽虞齊年運使  其一','史堯弼','宋','宋诗','song-poetry','','[]','曩把司農節，蠲民百萬資。',48,'全唐诗/poet.song.144000.json','["曩把司農節，蠲民百萬資。", "公今隨夜旦，誰與療瘡痍。", "貯羨時包匭，搥人吏剝肌。", "九原難再作，墮淚閲豐碑。"]'),
('cde4453d-e4a9-4611-ad86-d81ffdb1380e','挽虞齊年運使  其二','史堯弼','宋','宋诗','song-poetry','','[]','吁嗟先晚季，寂寞慨前修。',48,'全唐诗/poet.song.144000.json','["吁嗟先晚季，寂寞慨前修。", "斗仰公無幾，雲披我末由。", "扁舟方楚越，華屋已山丘。", "耆舊襄陽盡，歸來涕欲流。"]'),
('0facf8ac-b04d-4194-a15b-1b8330893b7b','孫致平尊人挽詩','史堯弼','宋','宋诗','song-poetry','','[]','再見書樓氏，風流繼六賢。',48,'全唐诗/poet.song.144000.json','["再見書樓氏，風流繼六賢。", "素輕千戶擬，還守一經傳。", "好學嗟亡矣，傷心爲衋然。", "郎君今二妙，早晚慰深泉。"]'),
('15f9195e-0102-44e8-9575-651fb3268185','離臨安道中有作','史堯弼','宋','宋诗','song-poetry','','[]','拂袖歸與喜欲奔，回瞻不覺鼻含辛。',64,'全唐诗/poet.song.144000.json','["拂袖歸與喜欲奔，回瞻不覺鼻含辛。", "有情猶作遲遲去，何事空餘咄咄頻。", "潁水舊來堪洗耳，西風當日苦多塵。", "人間觸處皆宜隠，不必桃源始問津。"]'),
('3313b593-5095-433b-ad90-2a892e4793f8','師伯渾至青神約訪而潜歸以詩相別因戲之','史堯弼','宋','宋诗','song-poetry','','[]','開門脫兔豈非癡，空費追亡急作詩。',64,'全唐诗/poet.song.144000.json','["開門脫兔豈非癡，空費追亡急作詩。", "雪月會知思戴老，棗瓜方欲問安期。", "夢魂莫逐人千里，遥夜還同月一規。", "此去相過吾得計，定應掎角待伊尼。"]'),
('d380b8b7-c61a-4688-86d2-ddf811b434ab','胡氏舊遊臨行贈別二章  其一','史堯弼','宋','宋诗','song-poetry','','[]','孤枕懷歸夜夜傾，閉關猶作旅人行。',64,'全唐诗/poet.song.144000.json','["孤枕懷歸夜夜傾，閉關猶作旅人行。", "絕知半路能遊客，難忍終年欲別情。", "雪裏梅花逢的皪，風前木葉任縱橫。", "一鞭明日三巖路，可是泠然馬足輕。"]'),
('41227cdb-329e-4d67-a4b8-bf1fd8f96241','胡氏舊遊臨行贈別二章  其二','史堯弼','宋','宋诗','song-poetry','','[]','妙契還從蓋始傾，無言與共四時行。',64,'全唐诗/poet.song.144000.json','["妙契還從蓋始傾，無言與共四時行。", "可堪歲晚倉皇別，多謝詩來繾綣情。", "最喜伊家三樹秀，故應我輩一經橫。", "人間定價如金玉，入眼那能較重輕。"]'),
('bfe69358-729a-4d32-9bc0-1ec85119ddbe','挽彥承知監','史堯弼','宋','宋诗','song-poetry','','[]','蚤年獨出棄繻關，肯作轅駒老故山。',64,'全唐诗/poet.song.144000.json','["蚤年獨出棄繻關，肯作轅駒老故山。", "澒洞烟塵嘗解難，從容矢石敢投艱。", "尚餘長短蘇張術，不值風雲楚漢間。", "還想湖湘對床酌，淚滂原草不勝斑。"]'),
('e840f88e-7f39-4d0f-a4a8-341ea0a2aab3','程隠君挽詩','史堯弼','宋','宋诗','song-poetry','','[]','武陽昔有埋輪使，慷慨風聲今未休。',64,'全唐诗/poet.song.144000.json','["武陽昔有埋輪使，慷慨風聲今未休。", "此老典刑餘故國，鄉來儀槩動殊州。", "曾無遺憾登三壽，忽循優閑卧一丘。", "招以哀詩追楚些，未忘吾里尚魂遊。"]'),
('6f40a8e9-dddd-4216-b509-4f9169ddcb13','挽李提刑久善  其一','史堯弼','宋','宋诗','song-poetry','','[]','絕知嗣法一枝香，作意開堂嗣雪堂。',64,'全唐诗/poet.song.144000.json','["絕知嗣法一枝香，作意開堂嗣雪堂。", "早悟錐沙傳筆畫，旋收珠玉入詩囊。", "卷藏人閟龍蛇字，炳蔚家餘虎豹章。", "衣鉢兩郎公不恨，班班文物未淒涼。"]'),
('82e121f9-4a1a-46b1-8224-c90867ab3f6d','挽李提刑久善  其二','史堯弼','宋','宋诗','song-poetry','','[]','大江南畔按澄初，兵弄潢池悉就俘。',64,'全唐诗/poet.song.144000.json','["大江南畔按澄初，兵弄潢池悉就俘。", "坐使奔鯨無脫網，當時懸鼓不鳴桴。", "後來盜起螺川震，却恨公歸蜀道趨。", "但使國僑長在鄭，定知賣劍化萑蒲。"]'),
('12040bcc-a97a-4440-b491-441c6f9f9546','挽李提刑久善  其三','史堯弼','宋','宋诗','song-poetry','','[]','曩持玉節問痌瘝，邂逅南昌一解顔。',64,'全唐诗/poet.song.144000.json','["曩持玉節問痌瘝，邂逅南昌一解顔。", "親見瘡痍摩手拊，夜深父子短檠間。", "行裝約束有琴鶴，道力較量無素蠻。", "自合明光將劍履，如何零落遂丘山。"]'),
('5ab4d1d0-3032-4243-8bb5-9d76059cb922','挽李提刑久善  其四','史堯弼','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','夢寐平生杖屨從，慣看高論吐長虹。',64,'全唐诗/poet.song.144000.json','["夢寐平生杖屨從，慣看高論吐長虹。", "滕王閣畔樽罍共，房琯湖中嘯詠同。", "忍鄉西州悲謝傅，空期斗酒酹橋公。", "緘詩髣髴招英爽，淚濕西風未有窮。"]'),
('875e58e0-e27c-48a0-9925-5456bed95a9f','挽邑令王公','史堯弼','宋','宋诗','song-poetry','','[]','君家家學有傳衣，事業如何只漫違。',64,'全唐诗/poet.song.144000.json','["君家家學有傳衣，事業如何只漫違。", "九萬鵬程終莫上，一雙鳬舄嘆頻飛。", "空傳是處棠陰布，倏作朝來薤露稀。", "楚些莫愁招不得，山頭騎鶴看來歸。"]'),
('1fb9d0fe-6a93-455a-bb25-d2b660775a64','挽湔江令何公','史堯弼','宋','宋诗','song-poetry','','[]','家在岷山第一流，世收科級萬人頭。',64,'全唐诗/poet.song.144000.json','["家在岷山第一流，世收科級萬人頭。", "同時看接才華盛，大夢真成頃刻休。", "尚憶依蓮王儉逸，空傳治縣次公優。", "茫茫螻蟻王侯盡，六六峰前汗漫遊。"]'),
('77dc4996-a8ce-40bf-bc8c-f75e259a6377','題無熱軒','史堯弼','宋','宋诗','song-poetry','','[]','飲水不救渴，利害成火攻。',24,'全唐诗/poet.song.144000.json','["飲水不救渴，利害成火攻。", "那知在人世，長夏有清風。"]'),
('1ba34968-f087-4622-aee4-1b2310cc0ac7','竹齋','史堯弼','宋','宋诗','song-poetry','','[]','樗櫟雖不才，亦各言其長。',24,'全唐诗/poet.song.144000.json','["樗櫟雖不才，亦各言其長。", "媿此萬丈夫，寐卧無何鄉。"]'),
('f37ebb58-65bb-4409-ae30-3eb8fe531ddd','山齋','史堯弼','宋','宋诗','song-poetry','','[]','禱公一邱壑，何似東山起。',24,'全唐诗/poet.song.144000.json','["禱公一邱壑，何似東山起。", "可憐丹青手，置之巖石裏。"]'),
('a6881bfb-e759-4c4d-a76f-9cd8dbbd3dc3','醉石','史堯弼','宋','宋诗','song-poetry','','[]','有時醉濁清，隨意眠小大。',24,'全唐诗/poet.song.144000.json','["有時醉濁清，隨意眠小大。", "何須酒池中，始了一生課。"]'),
('d3188449-b850-4b08-bd06-fb59e992098e','三老亭','史堯弼','宋','宋诗','song-poetry','','[]','可憐商山樂，黄綺不同歸。',24,'全唐诗/poet.song.144000.json','["可憐商山樂，黄綺不同歸。", "聞公有二老，晚節自離奇。"]'),
('bc7b22b7-88d4-40e2-890a-451a4323646f','寓齋','史堯弼','宋','宋诗','song-poetry','','[]','莊生十九言，妙處如筏喻。',24,'全唐诗/poet.song.144000.json','["莊生十九言，妙處如筏喻。", "我欲問公居，公心無所住。"]'),
('c46dd67e-bf30-4dd6-9a34-c97eb270e5b2','李文山讀書堂','史堯弼','宋','宋诗','song-poetry','','[]','堂上中聖賢，心醉百不理。',24,'全唐诗/poet.song.144000.json','["堂上中聖賢，心醉百不理。", "堂下笑糟粕，未知其趣爾。"]'),
('5ccd5819-96e8-49d5-873e-9a77531d7a7a','叢桂','史堯弼','宋','宋诗','song-poetry','','[]','秋風芳桂叢，的皪好顔色。',24,'全唐诗/poet.song.144000.json','["秋風芳桂叢，的皪好顔色。", "乃公欲盤旋，戒子勿剪伐。"]'),
('ce5c0d05-4957-43fb-89b8-93a873665c53','泛宅','史堯弼','宋','宋诗','song-poetry','','[]','四明有狂客，歸計亦風流。',24,'全唐诗/poet.song.144000.json','["四明有狂客，歸計亦風流。", "好激鑑湖水，泛君天上舟。"]'),
('f71d70d1-4a03-4bd4-9f26-2bbf6f6b949a','棗','史堯弼','宋','宋诗','song-poetry','','[]','后皇有嘉樹，剡棘森自防。',24,'全唐诗/poet.song.144000.json','["后皇有嘉樹，剡棘森自防。", "安得上摘實，貢之白玉堂。"]'),
('4e637b82-caf4-4a8e-9c1f-4265a8817dae','柔桑陌','史堯弼','宋','宋诗','song-poetry','','[]','姑待三年采，聊爲卒歲謀。',24,'全唐诗/poet.song.144000.json','["姑待三年采，聊爲卒歲謀。", "可憐齊魯俗，乃欲比封侯。"]'),
('886b49b6-5e12-43e7-99c2-e70dc393f7ee','虎川','史堯弼','宋','宋诗','song-poetry','','[]','暴虎須袒裼，馮河必褰裳。',24,'全唐诗/poet.song.144000.json','["暴虎須袒裼，馮河必褰裳。", "想公川上歎，誰與共行藏。"]'),
('dc49dba1-256d-4659-a15d-2d285a4defc6','賀宋嗣宗除岳陽守五絕  其一','史堯弼','宋','宋诗','song-poetry','','[]','暫駕湖山兩轂華，便應雲海去乘槎。',32,'全唐诗/poet.song.144000.json','["暫駕湖山兩轂華，便應雲海去乘槎。", "蓬萊弱水而今近，看上鼇峯判五花。"]'),
('db60253b-df41-48bb-b73e-93cc54d0793b','賀宋嗣宗除岳陽守五絕  其二','史堯弼','宋','宋诗','song-poetry','','[]','鼎就軒皇上白雲，遺音那復數韶韺。',32,'全唐诗/poet.song.144000.json','["鼎就軒皇上白雲，遺音那復數韶韺。", "湖山依舊魚龍在，要識當時奏樂聲。"]'),
