('e9ca840c-be13-4c2b-8a88-6a849ffe4b6d','賀蘇邛州移鼎州兼呈八座四絕  其二','史堯弼','宋','宋诗','song-poetry','','[]','何須萬里尋岣嶁，更問君王覓鑑湖。',32,'全唐诗/poet.song.144000.json','["何須萬里尋岣嶁，更問君王覓鑑湖。", "箭鏃玉床今在手，桃花流水去分符。"]'),
('3e9518d4-272d-4cfb-a450-c3893ab24d97','賀蘇邛州移鼎州兼呈八座四絕  其三','史堯弼','宋','宋诗','song-poetry','','[]','白鶴山頭留幾時，白鶴池畔歌來遲。',32,'全唐诗/poet.song.144000.json','["白鶴山頭留幾時，白鶴池畔歌來遲。", "浮邱伯去無消息，老眼而今儻見之。"]'),
('23855852-9b07-434f-98bf-9da94a29041a','賀蘇邛州移鼎州兼呈八座四絕  其四','史堯弼','宋','宋诗','song-poetry','','[]','雲海相望定渺然，已驚別夢不成圓。',32,'全唐诗/poet.song.144000.json','["雲海相望定渺然，已驚別夢不成圓。", "他年勝處煩推轂，此道滄洲好待看。"]'),
('dcd59dfc-9a8d-48c2-90f1-4f4e67fd947f','送青神丞劉平仲解官三絕  其一','史堯弼','宋','宋诗','song-poetry','','[]','多奇趙北燕南地，還喜超然出冀方。',32,'全唐诗/poet.song.144000.json','["多奇趙北燕南地，還喜超然出冀方。", "氣習敦龐今復見，餘風千載有陶唐。"]'),
('58399afe-3f7b-47cc-9791-441485ec1771','送青神丞劉平仲解官三絕  其二','史堯弼','宋','宋诗','song-poetry','','[]','笑譚裁割發硎餘，豈是丞能不負余。',32,'全唐诗/poet.song.144000.json','["笑譚裁割發硎餘，豈是丞能不負余。", "並舍過從無一事，坐看㶁㶁水循除。"]'),
('a2103f38-3756-4310-b155-e6dd26f40db9','送青神丞劉平仲解官三絕  其三','史堯弼','宋','宋诗','song-poetry','','[]','祖烈班班汗簡編，鄉來人物覺尤賢。',32,'全唐诗/poet.song.144000.json','["祖烈班班汗簡編，鄉來人物覺尤賢。", "轅攀耆老空遺恨，不受渠儂一大錢。"]'),
('3b4875e0-e76d-4e2b-a0eb-1dffaed92e13','甲子春過浙和周去華韻五絕  其一','史堯弼','宋','宋诗','song-poetry','','[]','遲回獨立湘江頭，湘江無情空自流。',32,'全唐诗/poet.song.144000.json','["遲回獨立湘江頭，湘江無情空自流。", "擬呼妃子弄雲瑟，一瀉胸中千斛愁。"]'),
('66ee1d37-07ac-460c-a7f7-5e986bdbf7bc','甲子春過浙和周去華韻五絕  其二','史堯弼','宋','宋诗','song-poetry','','[]','貪看衡麓數峯山，那覺江風獵獵寒。',32,'全唐诗/poet.song.144000.json','["貪看衡麓數峯山，那覺江風獵獵寒。", "吹亂衣巾都不記，橘洲沙上幾遺冠。"]'),
('332d1a2b-2aab-4e0e-b210-b2d70f5bc766','甲子春過浙和周去華韻五絕  其三','史堯弼','宋','宋诗','song-poetry','','[]','誰家花柳暗門邊，投憩同維藥玉船。',32,'全唐诗/poet.song.144000.json','["誰家花柳暗門邊，投憩同維藥玉船。", "醉卧黄鸝新弄舌，一聲喚起小窗眠。"]'),
('00e1c638-7665-4ec7-8e41-754a10e34dcc','甲子春過浙和周去華韻五絕  其四','史堯弼','宋','宋诗','song-poetry','','[]','滿眼殘紅正亂飛，端如棹入武林時。',32,'全唐诗/poet.song.144000.json','["滿眼殘紅正亂飛，端如棹入武林時。", "此身也是鷦鷯樣，乞與桃林借一枝。"]'),
('2e1df457-b437-4c75-ac04-21a4375ec9be','甲子春過浙和周去華韻五絕  其五','史堯弼','宋','宋诗','song-poetry','','[]','雙峯翠掃半天餘，遥想岷峩霽雪初。',32,'全唐诗/poet.song.144000.json','["雙峯翠掃半天餘，遥想岷峩霽雪初。", "足踏東南今已遍，却思歸卧舊時廬。"]'),
('f3c70e82-081e-40d3-acd9-c0d937523f7a','題南嶽方廣後洞五百羅漢所居二絕  其一','史堯弼','宋','宋诗','song-poetry','','["\u8861\u5c71"]','嶽勢扶輿峻莫攀，豈知深處鎖幽閑。',32,'全唐诗/poet.song.144000.json','["嶽勢扶輿峻莫攀，豈知深處鎖幽閑。", "千巖萬壑爭回互，別有乾坤藏此間。"]'),
('4c992e20-5d24-46d7-b335-24fd263be42a','題南嶽方廣後洞五百羅漢所居二絕  其二','史堯弼','宋','宋诗','song-poetry','','["\u8861\u5c71"]','山自周回溪自流，沉沉萬籟不勝幽。',32,'全唐诗/poet.song.144000.json','["山自周回溪自流，沉沉萬籟不勝幽。", "此間有句誰堪話，五百真人今在不。"]'),
('95d24c3c-5f4b-4b22-bc23-301d04e5d382','戲中書巖寶印師方丈  其一','史堯弼','宋','宋诗','song-poetry','','[]','寧墮眉毛出爲人，舌端雷電不無神。',32,'全唐诗/poet.song.144000.json','["寧墮眉毛出爲人，舌端雷電不無神。", "如今有口却掛壁，草木巖中元自春。"]'),
('e1fa2a5d-944a-497a-8516-8decc9b97d67','戲中書巖寶印師方丈  其二','史堯弼','宋','宋诗','song-poetry','','[]','放形漫浪蜀山西，只是人間一闡提。',32,'全唐诗/poet.song.144000.json','["放形漫浪蜀山西，只是人間一闡提。", "不擬將心覓安處，閑來洗脚玉泉溪。"]'),
('92077c8f-5c21-4bd4-a227-253a815f73b4','張府君挽詩  其一','史堯弼','宋','宋诗','song-poetry','','[]','頻年來往鄭公鄉，邂逅論文膝上郎。',32,'全唐诗/poet.song.144000.json','["頻年來往鄭公鄉，邂逅論文膝上郎。", "已訝樹風增感嘆，忽聞薤露送淒涼。"]'),
('962be478-5578-4c19-970e-0fbba1bd6e8b','張府君挽詩  其二','史堯弼','宋','宋诗','song-poetry','','[]','見說親顔晝日嬉，夜窗膏火對書詩。',32,'全唐诗/poet.song.144000.json','["見說親顔晝日嬉，夜窗膏火對書詩。", "功名底事身終悞，孝友平生政已施。"]'),
('b6df5380-05d0-4bb0-b030-c66c07b15187','張府君挽詩  其三','史堯弼','宋','宋诗','song-poetry','','[]','誠孝從來此物根，只今誰與踐斯言。',32,'全唐诗/poet.song.144000.json','["誠孝從來此物根，只今誰與踐斯言。", "夫君泉下儻無憾，大字壁間猶有痕。"]'),
('acf3fcbf-b350-40a5-ac3a-94f132472321','張府君挽詩  其四','史堯弼','宋','宋诗','song-poetry','','[]','驚起龍蛇忽夢歸，一朝脫屣萬緣非。',32,'全唐诗/poet.song.144000.json','["驚起龍蛇忽夢歸，一朝脫屣萬緣非。", "遥知月露寒松滴，不是波濤木葉飛。"]'),
('e5d4cf2f-9ea7-484f-a930-a0821156baf2','張府君挽詩  其五','史堯弼','宋','宋诗','song-poetry','','[]','氣象重歸金馬地，更看埋玉亂松楠。',32,'全唐诗/poet.song.144000.json','["氣象重歸金馬地，更看埋玉亂松楠。", "他年父老還能說，道上書生爲指南。"]'),
('965af14c-a015-4109-83f0-de8992e2e851','和衢守張舍人龍眠捉馬圖詩  其一','史堯弼','宋','宋诗','song-poetry','','[]','筆間幻出馬中龍，放牧平沙細草中。',32,'全唐诗/poet.song.144000.json','["筆間幻出馬中龍，放牧平沙細草中。", "亦有崑崙玄圃意，蕭騷駿尾欲生風。"]'),
('cd652d7b-be13-4535-8fb7-7c59f3599d5e','和衢守張舍人龍眠捉馬圖詩  其二','史堯弼','宋','宋诗','song-poetry','','[]','世間凡馬那知數，便覺從今一洗空。',32,'全唐诗/poet.song.144000.json','["世間凡馬那知數，便覺從今一洗空。", "不遣奚奴嚴玉勒，恐因風雨渺龍宮。"]'),
('d3124c7c-443d-46cb-9e26-deb21993021a','公肅在東南三有書來未報聞其除司直以詩寄賀且謝  其一','史堯弼','宋','宋诗','song-poetry','','[]','江北江南罷戰塵，兩階干舞作昇平。',32,'全唐诗/poet.song.144000.json','["江北江南罷戰塵，兩階干舞作昇平。", "河東五色真毛羽，九奏簫韶看一鳴。"]'),
('c7c7b19c-1813-491f-b928-cd24fc456b7a','公肅在東南三有書來未報聞其除司直以詩寄賀且謝  其二','史堯弼','宋','宋诗','song-poetry','','[]','小試猶爲天下平，惠文柱後要無刑。',32,'全唐诗/poet.song.144000.json','["小試猶爲天下平，惠文柱後要無刑。", "從今準擬子張傳，吾世常司汗簡青。"]'),
('8fe6fde6-4fba-4bda-a975-33a91d9e27d0','公肅在東南三有書來未報聞其除司直以詩寄賀且謝  其三','史堯弼','宋','宋诗','song-poetry','','[]','縱橫才力自時須，今代鵷行政要渠。',32,'全唐诗/poet.song.144000.json','["縱橫才力自時須，今代鵷行政要渠。", "亦有故人巖石裏，未嫌不奉子公書。"]'),
('da9944e8-4a3a-4895-a1fe-91da3c0bcc53','題墨花','史堯弼','宋','宋诗','song-poetry','','[]','元功初剪刻，妙處極玄玄。',24,'全唐诗/poet.song.144000.json','["元功初剪刻，妙處極玄玄。", "醉墨誰家筆，于今合自然。"]'),
('c64e14ca-bf68-418e-9b17-1b2c5b369c72','句','史堯弼','宋','宋诗','song-poetry','','[]','四歲尚少房玄齡，七步未饒曹子建。',16,'全唐诗/poet.song.144000.json','["四歲尚少房玄齡，七步未饒曹子建。"]'),
('fe8cdc34-0e13-4b1a-ba0e-74ecca956840','詠懷','喻良能','宋','宋诗','song-poetry','','[]','一夔方佐舜，二公還相周。',84,'全唐诗/poet.song.144000.json','["一夔方佐舜，二公還相周。", "三傑從高祖，四皓屈留侯。", "五龍翔日邊，六逸嘯溪頭。", "七賢傲竹林，八仙隠糟丘。", "九老山中卧，十友方外遊。", "百鍊竟不變，千載存風流。", "名節良足貴，萬事真悠悠。"]'),
('d6087393-18da-49d8-b85e-52739d1a60b6','豪士','喻良能','宋','宋诗','song-poetry','','[]','東海一豪士，西山兩逸民。',48,'全唐诗/poet.song.144000.json','["東海一豪士，西山兩逸民。", "涕唾棄周粟，談笑無秦軍。", "餓死骨仍香，辭封名益芬。", "至今千載下，不敢輕隠淪。"]'),
('0c7d5d45-bef5-42d0-8e68-3fea7bdc3002','雨後曉行','喻良能','宋','宋诗','song-poetry','','[]','宿雨曉初收，長天澹如洗。',48,'全唐诗/poet.song.144000.json','["宿雨曉初收，長天澹如洗。", "解带臨清流，泉聲細娛耳。", "有如到愚溪，還似遊栗里。", "人生若此少，貧賤非所恥。"]'),
('f546d58d-d694-4693-9e9b-cd5de1e8048e','新浴','喻良能','宋','宋诗','song-poetry','','[]','新浴換輕縠，披襟臨榧臺。',72,'全唐诗/poet.song.144000.json','["新浴換輕縠，披襟臨榧臺。", "好風知人意，爲我東南來。", "晚池雨草青，庶足充徘徊。", "呼兒具綠樽，聊進納涼杯。", "一酌暑氣消，再酌愁懷開。", "三爵竟酩酊，浩歌臨蒼苔。"]'),
('e76fa31f-d892-4d1d-a0b2-d1db4f368a6c','苦熱不寐獨起對月','喻良能','宋','宋诗','song-poetry','','[]','暑氣推不去，涼風挽不來。',48,'全唐诗/poet.song.144000.json','["暑氣推不去，涼風挽不來。", "中庭月色浄，攬衣起徘徊。", "夜久萬籟寂，秋近孤蛩哀。", "月墮玉繩低，此興真悠哉。"]'),
('5c489b29-ddef-4c7d-868c-9625c9ab85b4','秋暑熾甚忍饑偶作書季直弟以詩見嘲因次韻','喻良能','宋','宋诗','song-poetry','','[]','老夏雨既少，穉秋雲亦無。',48,'全唐诗/poet.song.144000.json','["老夏雨既少，穉秋雲亦無。", "枯池罷桔槔，蔫花委芙蕖。", "不糝漫藜藿，不爨空樵蘇。", "蘇州亦有言，家人笑著書。"]'),
('f40c2ae2-0d46-46cf-a350-8b4d0fe51fef','中秋望月偶誦唐歐陽詹翫月詩追和一首','喻良能','宋','宋诗','song-poetry','','[]','雲浄天既碧，境幽月逾光。',96,'全唐诗/poet.song.144000.json','["雲浄天既碧，境幽月逾光。", "未數鈷鉧潭，不羨桂子堂。", "霏霏香霧橫，藹藹明輝揚。", "冥搜興乍酣，徙倚夜未央。", "走兔望圓魄，飛鳥喜新涼。", "但知整綸巾，何用翻霓裳。", "芳尊聊自傾，玉盤欲誰將。", "美人何時來，渺渺天一方。"]'),
('715f9ad6-4103-4d6e-a757-57158c7cb714','望所居西山瀑布','喻良能','宋','宋诗','song-poetry','','[]','山居尠歡悰，理策事遨嬉。',120,'全唐诗/poet.song.144000.json','["山居尠歡悰，理策事遨嬉。", "嶔岑屬初霽，眺覽得所宜。", "懸崖有飛瀑，注壑從涼颸。", "濛濛噴霧雨，冉冉含烟曦。", "清泠詎可汰，駛激疇能陂。", "會心欣有得，徙倚不知疲。", "雁蕩境千里，香爐天一涯。", "平生未能矚，昏旦矧欲窺。", "何如茲山溜，若與幽人期。", "他年營菟裘，舍是將安之。"]'),
('b355b5ae-3bdc-46f4-88fb-cd77a2ddfc7e','月山諸峰','喻良能','宋','宋诗','song-poetry','','[]','平生固寡好，嗜石如奇章。',216,'全唐诗/poet.song.144000.json','["平生固寡好，嗜石如奇章。", "家無千金産，舁致窮澗岡。", "壽星來金華，衣冠何昂藏。", "屈肘據膝坐，風雨須眉蒼。", "松石産花溪，奇詭頗異常。", "鼻祖乃赤松，素質侔白羊。", "舞袖出烟霞，渾脫類大娘。", "想當虞韶成，率獸雜鳳蹌。", "觥觥石柱峯，孤峭仍軒昂。", "長不滿五尺，勢欲摩穹蒼。", "獅子來何許，俯首未騰驤。", "何時一噴薄，百獸走且僵。", "鴟尾由天成，畧不假斧斨。", "端宜侈繪事，詎止工厭禳。", "東坡小仇池，大筆流芬芳。", "康公醉道士，名篇粲煌煌。", "矧我此數峯，價重百琳琅。", "願締金石交，出處永不忘。"]'),
('6b8aad7c-44dc-48a1-973f-483bf5a3b456','近結茅屋數椽以可賦軒揭取子美可以賦新詩之義用沈約體賦詩一首','喻良能','宋','宋诗','song-poetry','','[]','安仁偃息處，之問讀書室。',120,'全唐诗/poet.song.144000.json','["安仁偃息處，之問讀書室。", "茅軒規昔人，聊可容吾膝。", "幽芳秀垣曲，翠篠蓊簷隙。", "松窗炯虛明，荆籬互疎密。", "淡月曉窺几，候蟲夕鳴壁。", "詩書後前陳，圖史左右秩。", "遐覽到三五，旁搜及堅白。", "一語偶有得，寸心欣自適。", "輪奐非所慕，茲焉頗放逸。", "淵明儻來過，真趣會能識。"]'),
('1e6d0e18-e4a2-4870-b64c-374803b29452','古風一首謝張漕子溫惠示詩卷','喻良能','宋','宋诗','song-poetry','','[]','前輩久零落，老成驚創見。',96,'全唐诗/poet.song.144000.json','["前輩久零落，老成驚創見。", "平生恥問津，如今真北面。", "胸中五色絲，織此錦繡段。", "見之心孔開，照眼光爛爛。", "我亦好吟詠，忍饑說芻豢。", "辛勤三十年，功效無一綫。", "偶茲得大嚼，味永不忍嚥。", "嘉惠詎敢忘，仁風敬揚扇。"]'),
('494c34c0-83e9-4a54-813b-d53f2d1781e1','伏日陪府公侍御登四望亭分韻得四字','喻良能','宋','宋诗','song-poetry','','[]','危亭壓層城，是中有佳致。',120,'全唐诗/poet.song.144000.json','["危亭壓層城，是中有佳致。", "面面看江山，水雲自相媚。", "使君暇日登，火老金正穉。", "杯盤瑩無塵，笑語清有味。", "快風千里來，暑氣三舍避。", "賦詩紅蓮幕，煎茶白衣吏。", "詼諧想割肉，摇扇笑疼臂。", "樂事古云少，能并今有四。", "茲游峴山同，千古知姓字。", "吾輩亦何爲，雖駑猶附驥。"]'),
('cc4013de-8f0e-400f-ab74-1ca23fedea0b','葉自强讀書堂','喻良能','宋','宋诗','song-poetry','','[]','退之宰陽山，暇隙唯讀書。',96,'全唐诗/poet.song.144000.json','["退之宰陽山，暇隙唯讀書。", "同年大雅姿，文史以爲娛。", "治劇逾整暇，日與竹素俱。", "頫首繙漢晉，高聲誦唐虞。", "不善吾所鑒，善者吾所摹。", "撐腸仍拄腹，何翅五千餘。", "似聞書带草，已復生庭除。", "願言飽經濟，舒之彌八區。"]'),
('7c783384-1d11-4774-a0f9-fdfc9ce39335','獄空','喻良能','宋','宋诗','song-poetry','','[]','公庭日將夕，吏報空獄岸。',48,'全唐诗/poet.song.144000.json','["公庭日將夕，吏報空獄岸。", "雖無春草鞠，已有蛛絲蔓。", "歡樂見鳥烏，呻吟絕鵝雁。", "諒非片言折，聊發一笑粲。"]'),
('30470d6e-cb2c-415b-92a8-cf1d0febf454','同從兄季弟游香山追和東坡端午游諸寺韻','喻良能','宋','宋诗','song-poetry','','[]','前車惟伯氏，後乘載阿連。',120,'全唐诗/poet.song.144000.json','["前車惟伯氏，後乘載阿連。", "相携青蓮界，共開白社筵。", "黄梅雨初歇，紅榴花正妍。", "浄境聊莞爾，妙興真悠然。", "偈言溢四方，經卷餘五千。", "長廊含清風，古潭摇蒼天。", "幅巾既蕭散，青鞋亦輕便。", "登臨自晨曦，談笑窮暮煙。", "衡宇開卷坐，僧房借榻眠。", "却憶蘇州語，喧靜兩皆禪。"]'),
('6acd617d-4753-41fb-9981-bc6eed6670bf','題張漕子溫貴希齋','喻良能','宋','宋诗','song-poetry','','[]','新營老先生，喜好一何異。',72,'全唐诗/poet.song.144000.json','["新營老先生，喜好一何異。", "端能友造物，直欲騎元氣。", "古貨今難賣，太羹元少味。", "陽春誰肯和，玄白人爭議。", "知己如晨星，一笑聊自慰。", "先民不云乎，有以少爲貴。"]'),
('81719a08-d3af-4ec3-bb38-e6f79a324b53','由下梅至資福估賣官産','喻良能','宋','宋诗','song-poetry','','[]','曉發下梅寺，霽色浮壠麥。',48,'全唐诗/poet.song.144000.json','["曉發下梅寺，霽色浮壠麥。", "崎嶇白楊岸，詰屈黄牛軛。", "野芳吐丰茸，山羽鳴格磔。", "驅車復前途，聊欲徧阡陌。"]'),
('646b164a-fc06-4efb-b3e4-ca12e70337e1','龍池寺','喻良能','宋','宋诗','song-poetry','','[]','發軔資福山，弭轡龍池寺。',48,'全唐诗/poet.song.144000.json','["發軔資福山，弭轡龍池寺。", "杪春新雨足，老紅圍穉翠。", "溪流素縠寒，山色青羅膩。", "拄頰坐移晷，此意誰能會。"]'),
('c33d6b36-98ad-40d6-b56d-8f840579c1a6','觀田家宴集','喻良能','宋','宋诗','song-poetry','','[]','村落秋氣高，涼飆泛林莽。',84,'全唐诗/poet.song.144000.json','["村落秋氣高，涼飆泛林莽。", "田家刈穫閒，斗酒勞良苦。", "甕甌間竹箸，殺雞仍具黍。", "昏昏燈火照，草草盃盤舉。", "初喧鵞雁聲，中靜兒女語。", "醉來或田歌，散去亦社舞。", "不信五侯家，軟盤薦肥羜。"]'),
('85c28a1c-3d2a-4269-9186-3db30159fdce','次韻周敏卿秋興三首  其一','喻良能','宋','宋诗','song-poetry','','[]','炎暑墮何許，涼風忽吹衣。',48,'全唐诗/poet.song.144000.json','["炎暑墮何許，涼風忽吹衣。", "野水映荒岸，寒叢秀疎籬。", "蕭蕭林影薄，杳杳鴻聲悲。", "秋禾亦既穫，聊足充吾饑。"]'),
('83186e31-0773-4128-a4e9-5088df06e2b7','次韻周敏卿秋興三首  其二','喻良能','宋','宋诗','song-poetry','','[]','團團巖中桂，移根籬舍間。',48,'全唐诗/poet.song.144000.json','["團團巖中桂，移根籬舍間。", "秋風一披拂，嫋嫋天香寒。", "對此徑須飲，把酒酬西山。", "浩歌何窮已，寧必素與蠻。"]'),
('1b5cff13-44c7-49d6-ba67-dd11141b6852','次韻周敏卿秋興三首  其三','喻良能','宋','宋诗','song-poetry','','[]','悠悠草根蟲，鳴聲近我牀。',48,'全唐诗/poet.song.144000.json','["悠悠草根蟲，鳴聲近我牀。", "皎皎林間月，亦已照我牆。", "感此動萬慮，聊復舉一觴。", "何以侑我酒，清嘯聞疎篁。"]'),
('5e85bfec-3fd1-4e0f-af2f-331fc6d55e30','星源縣齋書事','喻良能','宋','宋诗','song-poetry','','[]','冬仲弭征轡，歘焉及新春。',144,'全唐诗/poet.song.144000.json','["冬仲弭征轡，歘焉及新春。", "飽喫番陽飯，細治星源民。", "星源故自佳，民俗良易馴。", "不嫌聾丞愚，翻愛假令真。", "相與不忍欺，見謂無緇磷。", "牒訟日以簡，賦輸日以臻。", "遺我以暇隙，使得窺典墳。", "短檠一窗燈，孤諷至夜分。", "平明坐廳事，簾影清無塵。", "閭里頗熙熙，孰云民不淳。", "顧謂汝父老，辱愛亦已勤。", "爲我理歸櫂，吾久思吾親。"]'),
('48e9d076-b667-4145-950b-deb5aee7aa92','題圓通寺至樂亭次待制王公韻','喻良能','宋','宋诗','song-poetry','','[]','地偏境自佳，烟雲遶孤屋。',48,'全唐诗/poet.song.144000.json','["地偏境自佳，烟雲遶孤屋。", "寒聲渺疎松，翠影澹脩竹。", "林深桂花晚，微風度餘馥。", "特用永歲年，聊足媚幽獨。"]'),
('a0da2076-ce7a-49b9-957e-b3ce26dcff64','次韻侍御五月二十日閔雨','喻良能','宋','宋诗','song-poetry','','[]','使君慕丘禱，用志端不分。',48,'全唐诗/poet.song.144000.json','["使君慕丘禱，用志端不分。", "天高聽甚卑，深知使君勤。", "立致楚東雨，如開衡岳雲。", "頼此苗盡活，不然尪可焚。"]'),
('345612fa-68f6-4ccf-8528-47deea235394','鵝湖寺','喻良能','宋','宋诗','song-poetry','','[]','鵝王牧羣鵝，濁世肯下遊。',168,'全唐诗/poet.song.144000.json','["鵝王牧羣鵝，濁世肯下遊。", "積水近天關，有時戲沈浮。", "老禪天人師，領畧傾九州。", "初開選佛場，坐斷諸峯頭。", "當時江東西，海納吞衆流。", "歲晚徙山麓，華堂跨龍樓。", "至今韋公碑，照曜蒼崖幽。", "陳迹記往昔，登臨縱冥搜。", "重來歲月疾，俯仰五十秋。", "撫事一太息，何從問人牛。", "惟餘拱把木，百尺環道周。", "成壞各有時，干戈今少休。", "空懷三宿戀，爲爾半日留。", "鐘聲遠送客，霧雨昏林休。"]'),
('72551665-1d99-42de-86eb-69cf01dd2c4b','七峰亭獨坐','喻良能','宋','宋诗','song-poetry','','[]','雨霽失炎燠，新亭境清淑。',48,'全唐诗/poet.song.144000.json','["雨霽失炎燠，新亭境清淑。", "層波綠奫泫，疊嶂青陸續。", "風篁韻絲桐，烟柳開畫軸。", "澹然塵慮銷，庶足永曛旭。"]'),
('2cd81789-fdd8-432c-9993-95e3e2dc5c8b','侍御王公去饒饒之士民數千萬人遮道攀轅又相與斷城北橋以留之公不得已乃回城從間道遁去餘干主簿翁君畫斷橋圖作詩二十韻寄侍御求和侍御以和篇見示因次韻一首','喻良能','宋','宋诗','song-poetry','','[]','東嘉老先生，文字繼坡谷。',240,'全唐诗/poet.song.144000.json','["東嘉老先生，文字繼坡谷。", "治饒如京兆，三王豈其族。", "政成無一事，澹若處幽獨。", "追蹤古循吏，清浄非碌碌。", "每以坐嘯餘，時出陽春曲。", "風流化邦人，吟詠成國俗。", "乙酉秋七月，天地正炎燠。", "有詔帥夔門，引道不淹宿。", "境內聞公行，倉皇守牙纛。", "攀轅人填咽，遮道車擊轂。", "已去復挽回，出入成重複。", "橋斷蜂腰分，巷擁魚鱗矗。", "竟從間道去，復許誰追逐。", "子母若弟昆，相顧皆嚬蹙。", "吾父既往矣，疇能繼英躅。", "孟嘗附商船，千古垂簡牘。", "偷席廣文氈，使者爲標目。", "去思聞九重，盛事傳西蜀。", "先生美無度，推誠置人腹。", "畫圖照人間，斯民記恩育。"]'),
('e75435cc-f11f-4029-bdea-0b1b1b8fa939','石鐘山','喻良能','宋','宋诗','song-poetry','','[]','南北兩石鐘，上下一水側。',120,'全唐诗/poet.song.144000.json','["南北兩石鐘，上下一水側。", "造物妙鎔冶，蜚廉巧撞擊。", "鏜鞳仍噌吰，歌鐘與無射。", "豐山吾焉知，蒲牢爾何力。", "咨余久願遊，偶此事行役。", "時秋風颼颼，日暮水激激。", "初如鈞天鳴，乍若金奏寂。", "入耳粹而清，洗心欣以懌。", "怪奇有如此，遊覽誰能測。", "發端示來今，注經人姓酈。"]'),
('efedd79f-4ade-4ac7-90ee-9cf71dc14fb3','題淵明醉石','喻良能','宋','宋诗','song-poetry','','[]','平生憶淵明，偶此訪遺跡。',48,'全唐诗/poet.song.144000.json','["平生憶淵明，偶此訪遺跡。", "柴桑僅未泯，栗里猶可識。", "寒溜澹泠泠，孤烟輕羃羃。", "撫事良多感，西風生醉石。"]'),
('89ac39fa-0e77-4506-b694-9e1670210e1c','媿陶','喻良能','宋','宋诗','song-poetry','','[]','淵明在彭澤，到任八十日。',144,'全唐诗/poet.song.144000.json','["淵明在彭澤，到任八十日。", "雖營三徑資，未穫公田秫。", "珍重千金腰，不爲督郵折。", "拂衣賦歸來，何異自投劾。", "我生本樗散，山林久蟠蟄。", "雖非淵明儔，頗亦慕幽迹。", "偶然得一第，遂竊升斗秩。", "未書藍田考，已捧錦溪檄。", "荒縣饒逋負，催科費鞭抶。", "彊顔簿領間，忽復彌數月。", "心焉媿淵明，俯首三歎息。", "番江何時還，哦松聊自適。"]'),
('40b3a17b-6137-4c3b-adfa-4f47d24922e9','送呂憲帥維揚','喻良能','宋','宋诗','song-poetry','','[]','讀我宋實錄，元豐治明昌。',288,'全唐诗/poet.song.144000.json','["讀我宋實錄，元豐治明昌。", "五年九月中，上特開天章。", "從容謂輔臣，邊民疲可傷。", "呂獨爲朕言，他人終未嘗。", "已乃命正獻，由定帥維揚。", "學士加大稱，庸以示寵光。", "移鎮未去久，趣歸總臺綱。", "爾來九十年，誰其踵遺芳。", "我公嫡孫行，祖烈蔚載揚。", "持節古閩粵，攝事今福唐。", "仁風雜和氣，盎盎如春陽。", "甿謠玉律響，圜扉春草長。", "英聲飛九重，御屏書益詳。", "廣陵大都會，經理須才良。", "擁麾往鎮之，非公諒誰當。", "延閣陞寶書，恩綸湛洋洋。", "左符分淮海，西顧寬巖廊。", "想見入境初，快覩爭星凰。", "折衝向樽俎，宣威謝金湯。", "行看有鋒召，衮衣侍虞皇。", "賤子一何幸，竊庇逾兩霜。", "誤蒙剡薦牘，名徹凝旒傍。", "受恩未知報，肝膽徒激昂。", "唯祈轉洪鈞，復立弟子行。"]'),
('24fc766c-f31a-47c2-8845-ab92297b206c','偶題','喻良能','宋','宋诗','song-poetry','','[]','少陵五十六，負暄候樵牧。',48,'全唐诗/poet.song.144000.json','["少陵五十六，負暄候樵牧。", "我今年與齊，而亦處幽獨。", "小亭數椽浄，新月半鈎曲。", "聊將萬斛愁，付與一盃綠。"]'),
('45712687-41ce-484a-ad09-4e10c05f6b19','十月五日從兄四弟三姪侍太孺人賞菊亦好園以賞心樂事爲韻分得賞字','喻良能','宋','宋诗','song-poetry','','[]','霜天豁澄明，水日共清朗。',144,'全唐诗/poet.song.144000.json','["霜天豁澄明，水日共清朗。", "西園足甘菊，歡言事幽賞。", "板輿奉慈顔，華發森少長。", "一笑喜團欒，千枝迷俯仰。", "黄英浥露繁，翠蔓緣籬上。", "雄蜂與雌蝶，採擷紛還往。", "逸興既中酣，佳致仍外奬。", "未多彭澤賢，不羨天隨廣。", "憶昔吏江東，王事困鞅掌。", "及今處閭里，暇日娛塏爽。", "殽酒雖不豐，獻酬非或强。", "分韻先阿連，作詩真技癢。"]'),
('6aed4b36-9d97-4f33-be86-2627b894c6dd','閎中堂','喻良能','宋','宋诗','song-poetry','','[]','危簷覆虛明，景趣清且長。',48,'全唐诗/poet.song.144000.json','["危簷覆虛明，景趣清且長。", "曲池散漣漪，珍木含葱蒼。", "離離荔子丹，冉冉茉莉香。", "有堂既足佳，無氈庸何傷。"]'),
('50780cec-c9fc-4e38-a9a7-a461b30cf8b2','次韻提舉王正言寒食游茶焙','喻良能','宋','宋诗','song-poetry','','[]','摘山勝煮海，財貨所源流。',216,'全唐诗/poet.song.144000.json','["摘山勝煮海，財貨所源流。", "建焙甲天下，賦入十倍收。", "國計頗頼之，貢輸何時休。", "擇人爲提領，得賢從宛丘。", "文章脫吏腕，風味登瀛洲。", "佐職亦已久，再見春草抽。", "郊原富槍旗，歲事日以修。", "撫民端若子，疾惡信如讐。", "驅車向鳳山，父老觀道周。", "青春行畫圖，佳處時一留。", "風前耳潺湲，雨後目纖柔。", "酒酣已勝賞，珠唾揮釣鈎。", "咨予素么麽，受恩猶未酬。", "銘心雖甚堅，撫己徒懷羞。", "平生困坎壈，暮年尚依劉。", "投公一紙書，遠寄粵王州。", "書傳得妙帖，想像寒食游。", "終防好事人，豪奪或巧偷。"]'),
('30291410-69e7-4596-8da5-a583b843b00f','題紅雲島','喻良能','宋','宋诗','song-poetry','','[]','紅雲覆絕島，望之心神開。',48,'全唐诗/poet.song.144000.json','["紅雲覆絕島，望之心神開。", "弱水不負舟，何由至蓬萊。", "吾欲煩巨鼇，爲載三山來。", "不然騎鯨去，一醉流霞杯。"]'),
('61560b50-0fe5-4399-873c-ea2cc74d2219','道旁松','喻良能','宋','宋诗','song-poetry','','[]','鬰鬰千丈松，誰栽蔭脩路。',48,'全唐诗/poet.song.144000.json','["鬰鬰千丈松，誰栽蔭脩路。", "年祀寖綿邈，斧斤時謬誤。", "皇華重憐惻，霜根辱調護。", "他日比甘棠，流風繼行露。"]'),
('fbeb9914-0d4d-4719-8f00-63ee8a478f61','夜宿天章寺','喻良能','宋','宋诗','song-poetry','','[]','蘭亭負崇岡，脩竹翳寒綠。',120,'全唐诗/poet.song.144000.json','["蘭亭負崇岡，脩竹翳寒綠。", "囂煩隔人境，爽氣森佛屋。", "薄暮行役罷，言就上方宿。", "是時秋崢嶸，西風響巖谷。", "越蘭不可見，浩歌想餘馥。", "右軍恨何許，禊序空三復。", "夜久百蟲絕，燈花媚幽獨。", "蕭然四壁靜，一洗塵萬斛。", "何當脫羈鞅，陰巖事卜築。", "聊復得此遊，澹然心賞足。"]'),
('fe5b5ba9-086e-49c6-b3a7-76a56d0b9d9f','華峰亭','喻良能','宋','宋诗','song-poetry','','[]','華峰抱紫翠，茲亭瞰清幽。',48,'全唐诗/poet.song.144000.json','["華峰抱紫翠，茲亭瞰清幽。", "春林羅畫屏，新月吐玉鈎。", "宛如東屯居，恍若南澗游。", "信美吾亦樂，特用慰淹留。"]'),
('c44e814d-eaaa-441e-91b4-1be5d73f61c5','己亥中秋','喻良能','宋','宋诗','song-poetry','','[]','二七月皎皎，三五雲沈沈。',48,'全唐诗/poet.song.144000.json','["二七月皎皎，三五雲沈沈。", "終然露半璧，亦復牽孤吟。", "夜久羣動息，唯有寒蛩音。", "長年重節序，感慨非獨今。"]'),
('e6add640-be8f-41ee-a141-7117c842ea36','勿言魯酒薄爲史端叔作也端叔同寮於越未終更求奉中都祠歸丞相侍傍作是詩以送之','喻良能','宋','宋诗','song-poetry','','[]','同寮雖云多，交友未易結。',120,'全唐诗/poet.song.144000.json','["同寮雖云多，交友未易結。", "臭味一小異，肝膽便楚越。", "君侯宰相子，風度何翩翩。", "四偕計吏貢，春銓復褎然。", "一見蓋爲傾，相逢豈在早。", "白髮與紅顔，論交非草草。", "君才若杞梓，真能世其家。", "顧我如駑駘，祇堪服鹽車。", "心情過中年，何翅數日惡。", "徑須釂一樽，勿言魯酒薄。"]'),
('f2f608c3-d4d4-4840-bc56-61307232e419','大雪追和退之辛卯年雪韻','喻良能','宋','宋诗','song-poetry','','[]','太皞亦已至，玄冥猶未歸。',120,'全唐诗/poet.song.144000.json','["太皞亦已至，玄冥猶未歸。", "茫茫天壤間，浪闊銀山圍。", "玉龍橫梅度，皓鶴漫空飛。", "白帝有所適，飄飄揚旌旂。", "從者一何繁，縞席仍練衣。", "招邀姑射仙，逢迎廣寒妃。", "祥耶時令耶，疇能測天機。", "饑人凍欲死，賞玩理則非。", "安得萬裘褐，寒者或庶幾。", "願言均此惠，不知身賤微。"]'),
('b393747a-536a-4f3c-a49a-bf141cdfdf4e','次韻奉酬刑部王嘉叟侍郎書戲綵集後','喻良能','宋','宋诗','song-poetry','','[]','制作參易經，不用草玄準。',204,'全唐诗/poet.song.144000.json','["制作參易經，不用草玄準。", "眼空天壤間，誰得並捷敏。", "鴻文翻水就，未省苦吟吻。", "齊梁逮陳隋，衆作付一哂。", "南國容本冶，西子髮更鬒。", "混然真天成，寧復分域畛。", "飛上青雲端，秋空擊鷹隼。", "豈唯持荷橐，已復班玉笋。", "雖未究所長，要亦攄素藴。", "大手秉綸綍，至音發簴簨。", "嗟予墮詩窮，政坐無鉛粉。", "數奇祇自憐，多忤誰汲引。", "有賦難逐貧，無詩不招隠。", "明公獨深憐，不嫌邊幅窘。", "謂雖敝帚如，或可充貢箘。", "恃此以無恐，枚臯窮久忍。", "儻復念菅蒯，庶免辱荆槿。"]'),
('139055fe-c3a9-4f46-a4c7-4019065785a9','次韻宗郎中師仁見示古風','喻良能','宋','宋诗','song-poetry','','[]','平生癖於詩，業債餘清浄。',216,'全唐诗/poet.song.144000.json','["平生癖於詩，業債餘清浄。", "但已心孔開，敢誇筆鋒勁。", "疾書或欹斜，所向必雅正。", "顧慚非晉人，出語那韻勝。", "亦好三畝園，松竹互掩映。", "門闌雖間啟，俗客未省迎。", "豈唯愜幽情，頗復動詩興。", "朅來古泮宮，未諳麋鹿性。", "何處更有詩，抗走足不定。", "宗英出大篇，重此綠綺贈。", "未應費推敲，詎止工競病。", "此作不爲妙，妙處知難更。", "吟壇將風雅，瑣尾宜退聽。", "賀白真雁行，離騷可奴命。", "熟復句中眼，如對麈尾柄。", "迷途獲指南，從此識畦徑。", "自應形贊歎，誰復獻嘲評。", "佳處未易知，當有識者證。"]'),
('ffd4ee3b-b72c-4d76-9066-9ce6aeaa98f3','送高炳如倅天台','喻良能','宋','宋诗','song-poetry','','[]','高侯吾所畏，學問覷壺奧。',120,'全唐诗/poet.song.144000.json','["高侯吾所畏，學問覷壺奧。", "秋水瑩精神，春華麗詞藻。", "三館朅來游，兩鬢青未皓。", "何心翫歲月，刻意事探討。", "二志既崇成，八書可偕考。", "烏臺竚風采，綸闈須典誥。", "引疾遽有祈，勇退一何早。", "丹丘非大名，泥軾僅小好。", "會看有詔追，豈必俟身到。", "行矣即輕安，愷悌神所勞。"]'),
('f4317649-7864-4001-9e68-95d2f00120c0','張持荷示詩編次韻一篇爲謝','喻良能','宋','宋诗','song-poetry','','[]','先唐詩道昌，萬象繞吟筆。',144,'全唐诗/poet.song.144000.json','["先唐詩道昌，萬象繞吟筆。", "長吉窮嶮怪，奚囊銷永日。", "一洗齊梁陋，古澹見摩詰。", "詰齋妙入神，二者無一失。", "遊戲唾成珠，所至動盈帙。", "長篇雜短詠，朱絃響玉律。", "脫身聲利場，宴坐心更逸。", "高眠聽松聲，清話剝芡實。", "聲名笑山王，任達景嵇畢。", "時發孤鳳鳴，不作寒蛩唧。", "人譏雕肺肝，悠然非所恤。", "編成客未佳，櫝藏謹勿出。"]'),
('f06cd167-6f66-4948-82d5-4e2a61359f57','王丞相生辰','喻良能','宋','宋诗','song-poetry','','["\u897f\u6e56"]','皇宋十一葉，時清風俗淳。',216,'全唐诗/poet.song.144000.json','["皇宋十一葉，時清風俗淳。", "實維元首明，亦繄股肱純。", "煌煌冀國公，自昔抱經綸。", "初掌黄麻誥，黼黻同卿雲。", "繼處宥密地，五兵驅精神。", "一品坐黄扉，十載轉洪鈞。", "雍容陪都俞，黽勉承華勛。", "鏡浄滄海波，烟銷紫塞塵。", "伊傅堪並驅，蕭曹真下陳。", "柔兆歲若午，協洽寅在辰。", "入夢一玉燕，持鑪兩天人。", "二十四書考，八千歲爲春。", "西湖爲酒醴，南屏爲膳珍。", "萬口均一詞，共祝柱石臣。", "一祝錫難老，再祝長同寅。", "百祝配遼鶴，千祝如大椿。", "國壽箕翼齊，洎公永無垠。", "貴名與鴻烈，日新日日新。"]'),
('c2051daa-cc6f-4eb7-9059-62ec4ff70752','次韻奉酬趙景明法曹見贈','喻良能','宋','宋诗','song-poetry','','[]','宗英賀白儔，肯從野人遊。',48,'全唐诗/poet.song.144000.json','["宗英賀白儔，肯從野人遊。", "相見各失喜，胡爲俱皇州。", "孤燈照清談，新詩澹牢愁。", "明日却分袂，獨往濤江頭。"]'),
('4056bf8c-ddff-4963-9609-e988ca872e2e','齋宿昭慶院祀南嶽南海','喻良能','宋','宋诗','song-poetry','','["\u8861\u5c71"]','秉檄奉中祀，驅車出重關。',48,'全唐诗/poet.song.144000.json','["秉檄奉中祀，驅車出重關。", "曉風鐵葉嶺，烟雨南屏山。", "瀹茗澡塵慮，褰簾飫孱顔。", "精意孚海嶽，清聲摇珮環。"]'),
('cc81242d-085f-4af3-b218-63181eead51a','留別直院莫子齋少卿','喻良能','宋','宋诗','song-poetry','','[]','鬰鬰千丈松，植根在崇岡。',108,'全唐诗/poet.song.144000.json','["鬰鬰千丈松，植根在崇岡。", "清陰亙十畝，直幹凌穹蒼。", "好風一披拂，聲韻諧宮商。", "古來成大厦，此物宜棟梁。", "不待歲月久，共看柱明堂。", "微木有石植，枯崖飽風霜。", "三百甲子餘，圍纔拱把强。", "大楹分難充，一桷庶可當。", "儻容附松末，雖晚庸何傷。"]'),
('a3b5ab44-392c-4dc6-8b2e-c467cd9561bb','留別王嘉叟檢正  其一','喻良能','宋','宋诗','song-poetry','','[]','初寮久已往，今誰主文盟。',72,'全唐诗/poet.song.144000.json','["初寮久已往，今誰主文盟。", "王公有嫡孫，見者服且驚。", "胸中九雲夢，筆端三折肱。", "招致道山中，掉頭不肯譍。", "論事常山蛇，持身玉壺冰。", "平生謝先容，要津真自登。"]'),
('dca0b7cc-120d-4885-8ce4-9ef7b08ca3f0','留別王嘉叟檢正  其二','喻良能','宋','宋诗','song-poetry','','[]','四海望霖雨，一人須股肱。',72,'全唐诗/poet.song.144000.json','["四海望霖雨，一人須股肱。", "我本田家子，蹉跎將暮齡。", "相逢豈在早，一見蓋已傾。", "謂我雖禿犀，敝帚亦足稱。", "持獻先簵箘，長篇有明徵。", "公乎儻踐言，庶爲老親榮。"]'),
('f3d57e84-1131-4b25-a92f-890c040f0837','送參議林郎中','喻良能','宋','宋诗','song-poetry','','[]','人孰不識面，相知貴知心。',168,'全唐诗/poet.song.144000.json','["人孰不識面，相知貴知心。", "唯我與夫子，傾蓋成斷金。", "疇昔居京邑，庀職偶相臨。", "肯紆鍾期聰，俯聽牙弦琴。", "講說三百篇，一一蒙賞音。", "朅來鍾山旁，休沐同搜吟。", "聯鑣照湖側，携手天衣岑。", "飛鳴互嚶嚶，和樂長愔愔。", "無詩不屬和，有酒相與斟。", "餉我破羌帖，佳妙同來禽。", "復遺先聖像，摹寫自孔林。", "二年如巨蛩，一旦辰與參。", "襟期自茲遠，詩盟幾時尋。", "願言蚤盍簪，無爲徒滯淫。"]'),
('cf7e43d5-4de2-45be-967c-501c01d99292','游鹿田三洞','喻良能','宋','宋诗','song-poetry','','[]','東西兩鹿田，上下三洞天。',48,'全唐诗/poet.song.144000.json','["東西兩鹿田，上下三洞天。", "苔徑劣容足，石門低及肩。", "乳竇斷還滴，天窗皓仍玄。", "何當出樊籠，悠哉聊永年。"]'),
('4d1d295a-836d-461c-9cfb-09de0ff0844e','次韻鞏憲見示桐柏瀑布之作','喻良能','宋','宋诗','song-poetry','','[]','昔聞孫興公，嘗賦飛流水。',120,'全唐诗/poet.song.144000.json','["昔聞孫興公，嘗賦飛流水。", "至今福庭地，猶屬羽人里。", "瀑泉天半來，界道見清泚。", "迢迢白虹貫，隠隠玉龍起。", "宇宙雖云寬，壯觀知能幾。", "谷簾信有之，界圖寧辨此。", "清秋饒爽氣，朱夏絕埃滓。", "何當振金策，逍遥山之趾。", "眺覽既愜適，嘯歌何窮已。", "青鞋未成往，撫己空自鄙。"]'),
('ec220a16-724c-4b7c-994d-b36327294415','月橋詩','喻良能','宋','宋诗','song-poetry','','[]','天逈月逾晶，地偏人亦靜。',48,'全唐诗/poet.song.144000.json','["天逈月逾晶，地偏人亦靜。", "簫然尋丈橋，寄此綠浄境。", "洗盞薦寒光，掬泉弄清影。", "塵遠耳目醒，令人發深省。"]'),
('b6a4a5aa-b934-44ff-b3f8-49d02f5f560e','約季野九日登雲黄不果季野有詩因次韻','喻良能','宋','宋诗','song-poetry','','[]','青山如候蟲，可賞不可戀。',72,'全唐诗/poet.song.144000.json','["青山如候蟲，可賞不可戀。", "胡爲謝康樂，遊覽乃欲徧。", "縱登最高頂，過眼猶掣電。", "何如菊花天，周遶籬落畔。", "對面黄雲峯，未妨籬下見。", "相携凌紫霞，更約東風便。"]'),
('20cd52f1-9b65-4236-84ea-b2c2c0fd0ffd','送晏伯安','喻良能','宋','宋诗','song-poetry','','[]','古綢於今婺，蓋亦一壯縣。',144,'全唐诗/poet.song.144000.json','["古綢於今婺，蓋亦一壯縣。", "劇繁號難理，百令無一健。", "英英晏伯安，年壯政則練。", "咄嗟掃宿弊，談笑了宿案。", "公庭坐無事，自可名道院。", "老眼空四海，於公驚創見。", "今公賦歸歟，敢以一語餞。", "邊陲正驛騷，朝野未閒燕。", "公才浩縱橫，敵可受八面。", "要須詣明光，上書還自薦。", "口伐或箸籌，收功在不戰。", "不然飛芻粟，坐使軍儲羨。"]'),
('0ad9bbab-c610-452a-b650-45bf87a88fc8','次韻伯壽兄殘春即事','喻良能','宋','宋诗','song-poetry','','[]','屏居事幽潛，親故成久別。',96,'全唐诗/poet.song.144000.json','["屏居事幽潛，親故成久別。", "茅簷翳濃綠，酴醿墮香雪。", "山氣清涼國，溪聲廣長舌。", "但須賢人酒，安用長者轍。", "吟腸繞碧雲，醉臉暈紅纈。", "奴耕穀可徯，兒書筆難掣。", "地偏塵不到，心境兩清絕。", "嘯歌何窮已，未覺處身拙。"]'),
('5f57efc2-7b8b-41ad-b60b-d6d684449abd','爲何監獄題種德堂','喻良能','宋','宋诗','song-poetry','','[]','作堂備登覽，既作扁其顔。',168,'全唐诗/poet.song.144000.json','["作堂備登覽，既作扁其顔。", "扁顔固云易，踐名良獨難。", "我友何水曹，築堂水雲間。", "瞰臨擅奇絕，佳氣何鬰盤。", "橫以數畝池，繚以四面山。", "石楠間女貞，青士依蒼官。", "紛紛雜花卉，栽植日以繁。", "豈獨秀春融，未應凋歲寒。", "憑欄試游目，皎皎萬慮寬。", "張公江海客，一見顔爲歡。", "嘉名揭種德，寓意固有存。", "期君宴游日，內照時返觀。", "善性益培壅，蕪累須一刪。", "木老德亦熟，無忘老坡言。"]'),
('7e8f9849-2061-4f98-b8f3-1b6d5caa1772','何茂宏茂恭携酒見過復侑以詩次韻一首','喻良能','宋','宋诗','song-poetry','','[]','薄雲漏朝曦，積雨霽中夏。',192,'全唐诗/poet.song.144000.json','["薄雲漏朝曦，積雨霽中夏。", "白波涵磬湖，清影漾茆舍。", "輪蹄絕還往，文史富閒暇。", "畏友有機雲，英標凜王謝。", "喜尋范張約，偕命嵇呂駕。", "豈徒貴密邇，聊亦重姻婭。", "戲彩膝纔容，亦好草可藉。", "瓦盌薦谿毛，竹箸羞雞炙。", "劇談掌屢抵，糲食咽亦下。", "晚凉過古剎，明月耀脩架。", "蒲團語上方，篝火耿良夜。", "凌晨一瘦藤，支徑雙不借。", "長嘯陟雲嶺，清吟探石罅。", "嶔岑近明目，湍激深沒胯。", "別袂余力摻，歸鞍子傭跨。", "何時許重臨，倒屣肅邀迓。"]'),
('0bfa2f16-70f4-48e4-850f-4fd2524b4372','謝葉致政送芍藥','喻良能','宋','宋诗','song-poetry','','[]','佳葩如美人，豔態妖且閒。',87,'全唐诗/poet.song.144000.json','["佳葩如美人，豔態妖且閒。", "葉園美無度，有花字雌丹。", "晨粧謝膏沐，秀色若可餐。", "芳根裹春泥，舉贈不作難。", "𦾏{華栥}照池亭，一洗儒生酸。", "從今杜陵眼，不復嗟長寒。", "何以報嘉惠，作詩當琅玕。"]'),
('6bb22260-fa8a-4ea2-9f40-d4fe196bf9ab','秋曉野步','喻良能','宋','宋诗','song-poetry','','[]','幽居邇郊原，出戶目已瞭。',84,'全唐诗/poet.song.144000.json','["幽居邇郊原，出戶目已瞭。", "閒携一枝竹，散步及秋曉。", "寒煙引輕雲，澹澹縈木杪。", "矯首矚層穹，轉盼失飛鳥。", "野潦浄荒陂，驚飈泛枯篠。", "世態徒營營，此心殊了了。", "佳處誰與論，聊用付清醥。"]'),
('c0056213-8133-457d-a6de-f2cdc04e6abd','次韻伯壽兄海棠','喻良能','宋','宋诗','song-poetry','','[]','無情長笑杜陵老，不識海棠春意好。',112,'全唐诗/poet.song.144000.json','["無情長笑杜陵老，不識海棠春意好。", "東坡作意賞東風，爲愛輕綃映肉紅。", "枝頭點綴知多少，貪睡今年開不早。", "含情欲開還未開，紫蝶黄蜂亦懶回。", "可憐熟視明人目，長恨年年看不足。", "曉來風定雨霏霏，減却春光一片飛。", "多愁更被花相惱，寧惜春衫同藉草。"]'),
('fb6890f8-90b7-4389-87e7-390c4dea137e','潘淑妃','喻良能','宋','宋诗','song-poetry','','[]','東昏當日寵容華，潘妃步步生蓮花。',48,'全唐诗/poet.song.144000.json','["東昏當日寵容華，潘妃步步生蓮花。", "閲武堂前種楊柳，玉兒雪腕親沽酒。", "蓮花不見楊柳空，蒼烟白露雜悲風。"]'),
('81697349-1736-4a3c-a487-755fc368be7d','張麗華','喻良能','宋','宋诗','song-poetry','','[]','張家女兒號麗華，十歲選入君王家。',64,'全唐诗/poet.song.144000.json','["張家女兒號麗華，十歲選入君王家。", "君王一見念玉雪，喚作後庭瓊樹花。", "臨風結綺香風度，自謂朝朝兼暮暮。", "那知夢斷金井欄，往事茫茫墮煙霧。"]'),
('c6f4e94f-1ca8-4569-8fe1-54391f9b0908','廣信試院追和東坡催試官考校韻','喻良能','宋','宋诗','song-poetry','','[]','深院鎖涼秋，西風坐間好。',120,'全唐诗/poet.song.144000.json','["深院鎖涼秋，西風坐間好。", "几凈窗明塵不飛，似躡紅雲至三島。", "數枝淡淡桂新香，千带垂垂柳初老。", "此邦天下秀，多士鄒魯無。", "負薪或解談王道，被褐無非懷璧夫。", "五兵奪目庫觀武，大嚼快意門過屠。", "誰言扳才古難必，披沙求金要須得。", "回思裹飯然脂燭，一心敢擬思鴻鵠。"]'),
('b06737c5-388b-41f5-a30c-26a923eb36da','吉老手刃凶人爲母報仇詩以紀之','喻良能','宋','宋诗','song-poetry','','[]','卧冰叱馭全忠孝，王氏多賢今古同。',160,'全唐诗/poet.song.144000.json','["卧冰叱馭全忠孝，王氏多賢今古同。", "公乎孝行驚創見，落落豈特漢晉風。", "凶人夜半發丘隴，敢爾殘暴不畏公。", "古來刃讐不共天，痛貫肝膂何時窮。", "刳心設祭久自許，何况臨機敢不武。", "拔刀斷賊血模糊，袍笏雍容詣官府。", "忍恥貪生真可羞，退之諄諄言復讐。", "請衣一擊當報怨，豫子猶能致嘉傳。", "如公壯志今已伸，他日定爲忠義臣。", "行看氣節動天子，詔書一洗泉下恥。"]'),
('d48684c2-519a-4ff9-acd3-035df38ca5cc','木狀元惠示近詩一卷作詩爲謝','喻良能','宋','宋诗','song-poetry','','[]','洪都通守詞華溢，漢殿文章元第一。',64,'全唐诗/poet.song.144000.json','["洪都通守詞華溢，漢殿文章元第一。", "萬卷落落蟠胸中，三江衮衮懸吟筆。", "贈我玉佩聯玦環，未數大鵬兼小山。", "欲知風味不能盡，此卷長留天地間。"]'),
('af51afd6-c139-4da6-9f09-3f1f4c2dfd5a','向伯章通判請賦畫扇','喻良能','宋','宋诗','song-poetry','','[]','晴天萬頃浮烟水，小艇鳴榔烟水裏。',48,'全唐诗/poet.song.144000.json','["晴天萬頃浮烟水，小艇鳴榔烟水裏。", "一聲欵乃西風起，滿輪明月蓼花秋。", "富貴於我真浮漚，世間何事不悠悠。"]'),
('7af5f21d-8743-4763-b44f-3bfb7ad03725','爲周提宮題尚友堂','喻良能','宋','宋诗','song-poetry','','[]','先生高節昭流俗，未應名宦能羈束。',64,'全唐诗/poet.song.144000.json','["先生高節昭流俗，未應名宦能羈束。", "歸來卜築傍泉石，灑落軒楹照山谷。", "外羅君子六千人，中有插架三萬軸。", "我嘗一日坐其間，至今清興猶堪掬。"]'),
('e3dfa628-d503-4e4d-8ebe-d0112a8210d0','題晚節香亭','喻良能','宋','宋诗','song-poetry','','[]','周侯人中英，爲文若翻水。',88,'全唐诗/poet.song.144000.json','["周侯人中英，爲文若翻水。", "苦節凌雪霜，香名馥蘭芷。", "考槃在幽谷，篁竹富清美。", "竹邊兩桂樹，碧葉光薿薿。", "扁堂曰節香，欲以規業履。", "竹桂日以茂，業履日以修。", "一觴一詠知未稱，願續離騷賦遠遊。"]'),
('8a3f36d0-5ec9-45c0-a7bb-d226224d1552','丫頭巖','喻良能','宋','宋诗','song-poetry','','[]','自有宇宙有此山，萬八千歲須臾間。',80,'全唐诗/poet.song.144000.json','["自有宇宙有此山，萬八千歲須臾間。", "亭亭造天屹石壁，雨淋日爍逾堅頑。", "且無泉瀑美裙帨，肯以草木媚容顔。", "丫頭得名良未稱，那有巨手梳髻鬟。", "會當呼作陸砥柱，長與羲娥閲往還。"]'),
('e15eaf43-52c7-46f6-99b1-37f38a58bc27','侍御宴僚屬于番江樓以卧病不克與分韻得四字','喻良能','宋','宋诗','song-poetry','','[]','使君自是廊廟器，五馬一麾聊爾耳。',192,'全唐诗/poet.song.144000.json','["使君自是廊廟器，五馬一麾聊爾耳。", "今年清凈獄既空，去歲豐登米不貴。", "郡中九賢政可十，京兆三王何足四。", "乘閒領客宴江閣，對景題詩忘肉味。", "坐間僚屬總文采，筆下波瀾更源委。", "夏木陰陰啼鳥喧，烟波渺渺輕帆駛。", "錯落觥籌略達尊，從容笑語窮幽意。", "嗟予薄命捩翻羹，卧病空齋吟擁鼻。", "畫㦸凝香不同賦，白衣送酒猶霑醉。", "追攀逸韻苦無才，想像清歡欲生翅。", "蘭亭被罰定非佳，金谷望塵吁可媿。", "他年江左仰遺風，應有畫圖傳盛事。"]'),
('7cd27122-14d2-4f6c-9ccf-356b7f107729','題楞伽寺李公山房藏書閣','喻良能','宋','宋诗','song-poetry','','[]','小閣崢嶸在空谷，云是先生讀書屋。',64,'全唐诗/poet.song.144000.json','["小閣崢嶸在空谷，云是先生讀書屋。", "不見善和數千卷，空聞鄴侯三萬軸。", "先生一去幾經年，山色依然爲誰綠。", "只今頼有衛夫人，壁上蕭蕭數竿竹。"]'),
('923289d7-1c47-4f6e-8bcd-6cac0877facd','春晚遣興','喻良能','宋','宋诗','song-poetry','','[]','乳鴨池塘春水滿，秋千院落東風暖。',64,'全唐诗/poet.song.144000.json','["乳鴨池塘春水滿，秋千院落東風暖。", "簾間燕子語雖忙，葉底黄鸝啼更緩。", "長大何如年少時，雕鞍駿馬踏芳菲。", "閉門不覺庭花落，顛倒殘紅作地衣。"]'),
('bde7184e-68c2-4e7a-814c-9cc7ee32b0fa','次韻王侍郎寄題亦好園','喻良能','宋','宋诗','song-poetry','','[]','磬湖鷗鷺自相親，湖邊山園步步新。',64,'全唐诗/poet.song.144000.json','["磬湖鷗鷺自相親，湖邊山園步步新。", "魚鳥細看自足樂，芋栗可收猶未貧。", "我覺有園貧亦好，人笑此園何太小。", "他年便擬當菟裘，不羨蓴鱸歸計早。"]'),
('cb091b1f-a28c-41d2-a638-6f4231557ed0','種菊','喻良能','宋','宋诗','song-poetry','','[]','子猷借宅亦種竹，淵明荒徑猶存菊。',64,'全唐诗/poet.song.144000.json','["子猷借宅亦種竹，淵明荒徑猶存菊。", "九日黄英凜碎金，三冬翠幹森寒玉。", "亦好纔圍一畝寬，恨無九畹養芳蘭。", "聊種寒花一百本，要伴此君秋後看。"]'),
('83d375ba-b652-4693-8873-14b8927903c0','僕坐釣磯季野弟寄詩來因次韻','喻良能','宋','宋诗','song-poetry','','[]','湖岸柳根半欹側，柳邊仍有陂陀石。',144,'全唐诗/poet.song.144000.json','["湖岸柳根半欹側，柳邊仍有陂陀石。", "不因斧鑿成漁磯，燕坐未妨鈎餌垂。", "磬湖寧待他山錯，白波分影涵翠幄。", "翠幄陰中千結藤，對面好山羅畫屏。", "遥岑無雲明入眼，遣我爛如巖下電。", "平生不憂臭於銅，俗氛安能蔽重重。", "興來散策饑來食，起居無時惟其適。", "詩窮吾師杜少陵，一杯未用身後名。", "他年掛冠不待老，歸來從君乞身早。"]'),
('efe60165-5764-4973-8a54-226c808ce4f7','新居成茂恭以詩見賀次韻奉酬','喻良能','宋','宋诗','song-poetry','','[]','子美堂工始上元，斷手乃在寶應年。',128,'全唐诗/poet.song.144000.json','["子美堂工始上元，斷手乃在寶應年。", "顧我無能爲杜役，有此屋廬差不難。", "欲移脩竹梅花亞，暮靄朝烟迷上下。", "室遠地偏來者誰，時有相思稽老駕。", "平生願足不願餘，底用虛名更著書。", "雖無拄腹五千卷，且有山陽宅一區。", "海內長句君最好，辱致新篇爲善禱。", "雞豚社酒幸不遠，來往他年成二老。"]'),
('c480e6a4-064f-4d86-8b9c-2a11487a0708','蚊','喻良能','宋','宋诗','song-poetry','','[]','慢膚秋來困撲緣，手不勝拍身聽旃。',48,'全唐诗/poet.song.144000.json','["慢膚秋來困撲緣，手不勝拍身聽旃。", "昨夜獰飆愜人意，一掃天宇何澄鮮。", "蚊子蚊孫與蚋伯，飛鳴適意須明年。"]'),
('932dcffe-e85b-4cac-a7eb-c00dfa35d826','題葉省幹見示詩卷次韻一篇','喻良能','宋','宋诗','song-poetry','','[]','微官詎足施才具，每向閒中有佳句。',96,'全唐诗/poet.song.144000.json','["微官詎足施才具，每向閒中有佳句。", "要同秦系下長城，却笑屈原無聖處。", "穿天出月摘清芬，煎膠續絃唯有君。", "命題探韻儕輩分，昂昂野鶴在雞羣。", "綠髮才名今白首，未數凴虛與烏有。", "會當載酒擘鸞牋，共試吟邊三昧手。"]'),
('7fd2b52d-2cd7-4c23-831e-213eaa4916cc','謝君植矮梅百許株蟠屈如輪臘至皆著花灑灑可愛','喻良能','宋','宋诗','song-poetry','','[]','孤竹低回首陽下，許由偃蹇箕山巔。',64,'全唐诗/poet.song.144000.json','["孤竹低回首陽下，許由偃蹇箕山巔。", "謝君雅有林泉趣，種得江梅如二賢。", "南州臘月溫和早，頼有冰花除熱惱。", "鱗差百樹夾徑明，似過山陰雪中道。"]'),
('f3fb4599-74b9-48cf-ba12-5b22677e4394','試院一首','喻良能','宋','宋诗','song-poetry','','[]','南國諸侯老賓客，霜葉青衫頭雪白。',128,'全唐诗/poet.song.144000.json','["南國諸侯老賓客，霜葉青衫頭雪白。", "繡衣使者急搜賢，又向文場三捧檄。", "全閩多士如鄧林，大厦度材慚匠石。", "細看太白日萬言，時取武成二三策。", "清心期識璞三獻，過眼敢迷目五色。", "只今雖無衣鉢傳，向來未省原天覓。", "更長寧辭燭屢秉，漏下何啻夜十刻。", "回思前日踏槐花，忍使青袍輕飲墨。"]'),
('4fbbb17b-5689-4267-9189-a8218c132202','余同年由試院積俸給買馬而歸中路幾逸戲作長句贈之','喻良能','宋','宋诗','song-poetry','','[]','知君幾作東野畢，瘦馬田間風欲逸。',64,'全唐诗/poet.song.144000.json','["知君幾作東野畢，瘦馬田間風欲逸。", "圉人白汗似翻珠，暫爾奔騰未爲失。", "歸家須辦紫游韁，玉轡紅纓摇鬧裝。", "一鞭嘶風映垂楊，要試寧川春草長。"]'),
('18edeb6c-b978-4e5d-b603-3ef61bc57c4a','安撫開府史丞相誕辰','喻良能','宋','宋诗','song-poetry','','[]','一年好處橘初綠，雨後秋容凈如沐。',192,'全唐诗/poet.song.144000.json','["一年好處橘初綠，雨後秋容凈如沐。", "潭潭大府忠孝家，黄堂正奏千秋曲。", "揮毫落紙妙卿雲，千佛經中蚤致身。", "橫飛直上九萬里，金魚玉带真天人。", "籌邊利國知誰似，直節長才堪重寄。", "手扶杲日照乾坤，力轉洪鈞陶品彙。", "櫜兜㦸纛粲煌煌，紫極聯休衮繡光。", "暫向閩都分帥閫，再歸天闕致時康。", "鯫生才業等襪線，昔辱甄收今論薦。", "喜看太白應長庚，樂頌燕公符玉燕。", "舊聞莊叟說大椿，八千爲秋八千春。", "願將眉壽同長久，永作王家柱石臣。"]'),
('ece170e8-1867-4bd5-959d-d5882d6bef49','參議李郎中惠示古律詩兩巨軸次韻首篇奉酬','喻良能','宋','宋诗','song-poetry','','[]','鄴中七雄迹既掃，謝樓夢斷池塘草。',160,'全唐诗/poet.song.144000.json','["鄴中七雄迹既掃，謝樓夢斷池塘草。", "仙李詩人麻竹多，佳句唯傳杜陵老。", "省郎句法專後來，壓盡今世詩流才。", "并刀翦水有佳致，月中聚雪無纖埃。", "穿天出月餘四紀，捉月風流今不死。", "從教人售一杯水，自信筆挾風霜字。", "次山風味喚仍回，老文猶未磨蒼崖。", "收拾明珠百餘斛，寒光入夜闔復開。", "我得公詩興嘆慨，千古長留詩卷在。", "祇恐天官下取將，人間古貨今崖賣。"]'),
('64bc5116-1203-424a-876f-ccc159f95a8e','八月十五夜翫月','喻良能','宋','宋诗','song-poetry','','[]','前年磬湖新雨歇，獨繞湖邊待明月。',128,'全唐诗/poet.song.144000.json','["前年磬湖新雨歇，獨繞湖邊待明月。", "夜深雲散月華來，疑是山陰踏晴雪。", "去年鎖宿校羣英，冰娥於人亦有情。", "仰看一鏡緣雲上，俯聽春蠶食葉聲。", "今年廣文在官舍，亦復開樽臨月榭。", "慈顔一笑綵衣輕，誰云官冷孤清夜。", "酒闌月色更徘徊，捲簾開戶真佳哉。", "懸知明年應更好，扁舟正泊雙溪隈。"]'),
('a6e7c936-117b-462e-ac01-87daed93b8b2','予由中都還至暨陽道中聞禽鳴云明朝早起插田作詩識之','喻良能','宋','宋诗','song-poetry','','[]','溝塍雨新足，䆉䅉秧正綠。',56,'全唐诗/poet.song.144000.json','["溝塍雨新足，䆉䅉秧正綠。", "林間鳥聲喧，明朝起插田。", "明朝插田起須蚤，謝汝殷勤勸畦稻。", "禽聲禽聲亦不惡，大勝人歌金縷曲。"]'),
('f0859f50-100a-49d1-b686-6eb95627ad70','送劉孟冶司令之官四明','喻良能','宋','宋诗','song-poetry','','[]','先生行孝人莫攀，平生急祿怡親顔。',64,'全唐诗/poet.song.144000.json','["先生行孝人莫攀，平生急祿怡親顔。", "三千曲禮髮已白，七十老萊衣尚斑。", "秋容新沐江涵天，潘輿低昂御花間。", "憑誰爲喚吳道子，一寫畫圖連越山。"]'),
('ea4be52a-8d06-4705-a48d-364b54d93e16','若耶曲','喻良能','宋','宋诗','song-poetry','','[]','若耶溪上凉如許，五月清風不知暑。',64,'全唐诗/poet.song.144000.json','["若耶溪上凉如許，五月清風不知暑。", "半空濃翠接蒼烟，滿眼輕陰覺疎雨。", "織女潭邊深復深，繞門山畔石成林。", "紅粧蕩槳誰家女，笑入荷花無處尋。"]'),
('fab2f2a8-f5d0-4afc-9cdf-0204f2ea0ba6','點檢朝陵內人頓遞至西興道中紀事','喻良能','宋','宋诗','song-poetry','','[]','平湖瀲灧摇春風，扁舟輕駛如飛鴻。',240,'全唐诗/poet.song.144000.json','["平湖瀲灧摇春風，扁舟輕駛如飛鴻。", "垂楊萬縷長青茸，倚岸崇桃醉臉紅。", "滿空烟雨霏濛濛，柯橋精廬聞午鐘。", "平疇麥苗青芃芃，崇峯秀岑紛玲瓏。", "圖經未看名叵窮，雨葩烟葉交朦朧。", "吾欲圖之誰其工，妙語却思六一翁。", "解道山色有無中，薄暮艤舟依竹叢。", "夜深點滴聽孤篷，天明利涉浮梁雄。", "錢清雖小炊烟重，我生之辰今適逢。", "一杯不暇緣匆匆，聊以新詩娛老悰。", "龕山西北水溶溶，白鶴橋邊小梵宮。", "海天茫茫空復空，放眸一望日本東。", "蕭山小邑河陽同，桃李漫山如錦幪。", "谿旁驛亭名夢筆，故居知是江文通。", "西興浦口天連水，滿眼長安紫翠濃。"]'),
('a885b104-b470-41cb-9e45-a2d648992e54','四月二十九日坐直廬讀山谷效東坡作薄薄酒二章慨然有感追賦一首','喻良能','宋','宋诗','song-poetry','','[]','薄薄酒，勝獨醒。',186,'全唐诗/poet.song.144000.json','["薄薄酒，勝獨醒。", "醜醜婦，勝鰥煢。", "笙歌鼎沸不須羨，松風滿耳自足聽。", "前遮後擁未必樂，邀月對影堪娛情。", "晚食有味可當肉，衡宇無災勝列屋。", "魯東門外聽鐘鼓，齊宣堂下狀觳觫。", "何如巢林一枝，飲河滿腹。", "水磑多至三十具，胡椒滿貯八百斛。", "何如濁酒一杯，彈琴一曲。", "子平爲富不如貧，子方稱賤能驕人。", "高明之家鬼可瞰，網射納稅官不嗔。", "中山醇醪醉千日，文君遠山致消渴。", "不如茆柴百錢可一斗，荆釵白頭長相守。"]'),
('6c55d037-4691-468e-a24d-0d2f6c3dd2a7','次韻王待制讀東坡詩兼述韓歐之美一首','喻良能','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','文章端與時高下，列國有風周有雅。',336,'全唐诗/poet.song.144000.json','["文章端與時高下，列國有風周有雅。", "建安氣質混不傷，齊梁紛紛堪斗量。", "先唐詩人子韓子，落筆洗空千古士。", "篇章杼軸自己出，正派猶能傳六一。", "作詩餘事真詩仙，騎麟被髮何翩然。", "韻寬泛押入傍近，窄韻宜搜期押盡。", "鈎章棘句未多郊，古諷新題寧數稹。", "五季詩流喜穿鑿，蟬噪蛙鳴嗟衆作。", "皇朝天人歐與蘇，星鳳初見人驚呼。", "醉翁句法到勝處，紆餘條暢今古無。", "鋪張揚厲詞藻挾，雅稱金泥兼玉檢。", "一篇妙絕廬山高，幾首清新寫鬰陶。", "造化機緘富狀彙，豈獨文星南斗避。", "如何妄評味短長，自古羣兒喜嘲議。", "雪堂羈窮如牧之，得非天欲昌其詩。", "平生古律三千首，無媿清風白雪詞。", "才如太白更無敵，文似子長兼愛奇。", "江西宗派不足進，自鄶以下曾無譏。", "流傳海內皆珠玉，到處逢人俱願學。", "不須酬唱說西崑，宋有歐蘇唐有韓。", "二文邈乎其杖几，一編且誦蘇夫子。"]'),
('525204bd-969e-4020-b94c-83ba776bfbf0','古風一首奉送淳叟太博通守豫章','喻良能','宋','宋诗','song-poetry','','[]','劉侯精神秋隼緊，高論懸河傾不盡。',160,'全唐诗/poet.song.144000.json','["劉侯精神秋隼緊，高論懸河傾不盡。", "至尊動色嗟諤諤，權倖切齒畏謇謇。", "致君未覺賈誼疎，濟時尚嫌馬周窘。", "三年博士向見治，萬卷蟠胸一何敏。", "歘然大起故鄉思，自請題輿佐旟隼。", "笑指江城欲載馳，輕棄斑列誰能挽。", "羨君去騎日駸駸，顧我朝行猶蠢蠢。", "語離寧憚十觴連，惜別不知雙淚隕。", "贈言見意乏珠玉，作詩餞行少鉛粉。", "從今數日待君歸，握手修門未爲晚。"]'),
('4f1a484d-11dd-4c2e-84b1-71d6ab5afffa','都丞李侍郎叔永和予小園二十六詩因成古風一首奉謝','喻良能','宋','宋诗','song-poetry','','[]','黄昏兀坐對疎竹，歘有寒光臨蔀屋。',96,'全唐诗/poet.song.144000.json','["黄昏兀坐對疎竹，歘有寒光臨蔀屋。", "焚香發軸得新詩，炯炯驪珠二十六。", "三唐妙音久已斷，輞川麗藻今能續。", "報瓜何必枉瓊華，抵鵲奚須費明玉。", "韓豪蘇仙吁可畏，白俗元輕何足錄。", "從此磬湖三畝園，絕勝李愿一盤谷。"]'),
('645078dd-5d32-4fe7-8457-83b7d2b62a00','都丞侍郎再和屋字韻詩次韻奉酬','喻良能','宋','宋诗','song-poetry','','[]','小園五畝依篁竹，中有茆茨數椽屋。',96,'全唐诗/poet.song.144000.json','["小園五畝依篁竹，中有茆茨數椽屋。", "小橋度水既窈窕，側徑穿花仍曲六。", "慣看翠碧羽差池，時聽黄鸝聲斷續。", "詩成持鼓過雷門，誰信拋磚能引玉。", "長篇麗句爲藩飾，小草么花蒙著錄。", "懸知家世以詩鳴，壓倒平泉與昌谷。"]'),
('d5188a18-99f7-4df0-aac5-02c6757f9455','李侍郎三和屋字詩次韻爲謝','喻良能','宋','宋诗','song-poetry','','[]','衛武文章比淇竹，閉閣著書欣仰屋。',96,'全唐诗/poet.song.144000.json','["衛武文章比淇竹，閉閣著書欣仰屋。", "胸蟠載籍餘萬卷，爲家五百九十六。", "詞華爾雅騷可奴，議論淵源經可續。", "筆端凜凜挾風霜，齒頰泠泠潄冰玉。", "久知廣大端可法，自顧么微何足錄。", "願同湛輩附羊公，庶比江西派山谷。"]'),
('bfb35f8e-b9ef-4199-8836-1f848a5c41ec','何司業和屋字詩見詒次韻奉酬','喻良能','宋','宋诗','song-poetry','','[]','亦好園林富松竹，愛山堂上書連屋。',96,'全唐诗/poet.song.144000.json','["亦好園林富松竹，愛山堂上書連屋。", "恨無妙語爲題品，空對奇峯有十六。", "先生佳句落泉石，杜詩韓筆端能續。", "有如妙響發朱絃，恰似清音動寒玉。", "須知小圃辱提撕，何異寒門被收錄。", "從今草木有光輝，盎盎春溫入鄒谷。"]'),
('053d2c25-1061-4d2b-8b16-56250fe6aad2','寄湖口劉少魏主簿求皂湖石','喻良能','宋','宋诗','song-poetry','','["\u592a\u6e56"]','平生愛石似奇章，老矣一拳猶未致。',64,'全唐诗/poet.song.144000.json','["平生愛石似奇章，老矣一拳猶未致。", "夜來夢繞太湖側，萬玉嶙峋清有味。", "夢回身復落紅塵，聞道皂湖山可人。", "幸致一峯爲我壽，爲君作詩傳不朽。"]'),
('70e84c12-8772-4363-971e-0096ed9305a7','伯琬明府年兄和予致字韻詩舉英石見遺謹次來韻以報盛貺  其一','喻良能','宋','宋诗','song-poetry','','[]','久聞英石空流涎，意欲得之無力致。',64,'全唐诗/poet.song.144000.json','["久聞英石空流涎，意欲得之無力致。", "士衡東頭富玲瓏，染指獨許嘗鼎味。", "明窗凈几拂蛛塵，尤物定自能移人。", "報惠慚無百金壽，贈公相好無時朽。"]'),
('457b6419-1f01-49a4-891d-7676704ce6da','伯琬明府年兄和予致字韻詩舉英石見遺謹次來韻以報盛貺  其二','喻良能','宋','宋诗','song-poetry','','[]','公家一峯如終南，須信是中有佳致。',64,'全唐诗/poet.song.144000.json','["公家一峯如終南，須信是中有佳致。", "對之忘饑亦忘愁，豈待聲色兼臭味。", "嗜好蕭然迥出塵，同年要是我輩人。", "世間何物如石壽，墨妙與之俱不朽。"]'),
('935cf6f1-a357-4b30-a568-7b8288ff1b55','周希稷見示詩卷作詩爲謝','喻良能','宋','宋诗','song-poetry','','[]','周郎列宿胸中羅，筆端有口如懸河。',64,'全唐诗/poet.song.144000.json','["周郎列宿胸中羅，筆端有口如懸河。", "贈我明珠六十八，一一照乘圓無頗。", "我學穀梁失也短，君才士衡患其多。", "中興功業要紀述，浯溪石崖當往磨。"]'),
('336652d3-a7bd-4be1-b77c-f4d26009069f','次韻楊廷秀浣花圖歌','喻良能','宋','宋诗','song-poetry','','[]','詩翁銜袖出清詩，醉墨淋漓驚乍寫。',104,'全唐诗/poet.song.144000.json','["詩翁銜袖出清詩，醉墨淋漓驚乍寫。", "明珠炯炯照戶牖，恍疑驪龍睡遺者。", "彌明高唱詩云云，此翁一掃如飛蚊。", "詩狂克念酒作聖，樽前笑殺劉師命。", "李白張旭稱世賢，姓名優入少陵編。", "平生我亦忝詞客，自得此詩輕尺璧，他年別去長相憶。"]'),
('8af44407-078e-4402-a1f2-7345eff54f36','王樞使生辰','喻良能','宋','宋诗','song-poetry','','[]','金華千古赤松宅，中有初平叱羊石。',224,'全唐诗/poet.song.144000.json','["金華千古赤松宅，中有初平叱羊石。", "雙溪衮衮瀉蒼波，三洞潭潭接天碧。", "鍾英孕粹昴星精，文章蚤歲瑞王廷。", "橫飛直上九萬里，紅顔兩鬢何青青。", "金鑾疇昔揮毫處，嘗草尺書招贊普。", "職親孰聽玉宸鐘，夜分更秉金蓮炬。", "只今右府冠樞衡，坐運精神驅五兵。", "一烽莫覩狼烟燧，四海不聞金革聲。", "蒼生顒顒待霖雨，黄屋便蕃頒異數。", "姓名久已覆金甌，東街行築沙堤路。", "江左夷吾望更尊，二十四考何足論。", "已見威棱動蠻貊，會看勳業照乾坤。", "六十門生焚蕙炷，再拜祝公如衛武。", "柱石皇家不計年，長容礦質入陶甄。"]'),
('dd83d438-e08e-495e-b5b1-500b54fc7648','題旌忠廟次王龜齡韻','喻良能','宋','宋诗','song-poetry','','[]','睢陽截然當賊中，嬰城既久糧食空。',168,'全唐诗/poet.song.144000.json','["睢陽截然當賊中，嬰城既久糧食空。", "矢死不降有二公，青史皎皎書其忠。", "國家涵養自建隆，上至鵷鷺下羆熊。", "一節一義皆獲通，無不昭然簡宸衷。", "建炎多難誰奮躬，開門納降何匆匆。", "達官尚爾况困窮，嗟嗟唐侯一何雄。", "抽甎擊敵甘命終，願以頸血污刃紅。", "精誠貫日亙雲穹，上徹九重達堯聰。", "詔令血食居鎮東，激昂臣子忠勇風。", "嘉名千古齊華崧，王仙作詩美抗戎，豈比爾雅詁魚蟲。"]'),
('262200dc-97c9-43e9-a35b-67600fc03e68','次韻王龜齡侍御不欺室','喻良能','宋','宋诗','song-poetry','','[]','與玄雖非童九齡，向來亦既許攀鱗。',96,'全唐诗/poet.song.144000.json','["與玄雖非童九齡，向來亦既許攀鱗。", "從容撰屨飽言論，我知公直社稷臣。", "此心炯炯貫白日，何止不欺尋丈室。", "霜臺白簡凜乘驄，史館誅姦森直筆。", "紫巖先生子張子，百世一人嗟已死。", "室中八十四驪珠，千載流芳同信史。"]'),
('ffafc973-aae1-4308-8ee1-3b3eecec1771','飲餞王共父分韻得轉字','喻良能','宋','宋诗','song-poetry','','[]','子猷風味最諸王，墨妙文工眼如電。',160,'全唐诗/poet.song.144000.json','["子猷風味最諸王，墨妙文工眼如電。", "慣吟疎雨滴梧桐，解道澄江凈如練。", "去年落筆中書堂，姓名高徹蓬萊殿。", "至尊動色催除目，俾向蘭臺參俊彥。", "要成遠業待時須，故遣讀書破萬卷。", "夫何歸思動岷峨，自請題輿近鄉縣。", "學省諸公悵別離，擊鮮載酒開芳燕。", "欲澆胸次數日惡，剩作林亭百壺餞。", "落花送酒舞繽紛，亂絮催詩飛眩轉。", "臨歧那用賦銷魂，但要修門重會面。"]'),
('67213182-2008-41da-931c-ef92597f3f04','題愍孝廟次王龜齡韻','喻良能','宋','宋诗','song-poetry','','[]','曹娥卓行傳豐碑，越人往往貴女兒。',272,'全唐诗/poet.song.144000.json','["曹娥卓行傳豐碑，越人往往貴女兒。", "建炎蔡氏有孝子，事比孝子尤瓌奇。", "自從結髮讀書史，倜儻不受靮與羈。", "迺翁詿誤落囹圄，疚心疾首泣以悲。", "胡能安坐視父繫，朝暮哀訴當旌麾。", "府公儻許贖父罪，名隸卒伍所不辭。", "不然奮身事征討，赳赳勇力猶可施。", "黄堂沈深身則微，雖有誠懇無人知。", "歸來靜默心語口，此事感悟當以屍。", "臨河勇决不復顧，純孝寧不由天資。", "緹縈上書解刑網，言雖迫切身無虧。", "文本理寃由一賦，孰與捐命如含飴。", "殺身成仁古所罕，殆類餓踣齊與夷。", "事聞黄屋亦動色，亟詔立祠河水湄。", "嗟嗟玄應固不朽，萬口至今皆一詞。", "東嘉夫子好事者，作歌登載仍吁嘻。", "異時國史編宋雅，人間重見白華詩。"]'),
('2576bb1f-7fd9-4d3f-a0df-ad73bba057ff','二月二十四日楊廷秀郎中諸友約遊西湖余以小疾不至分韻得子字','喻良能','宋','宋诗','song-poetry','','["\u897f\u6e56"]','都城西頭二月尾，湖水平堤縠紋起。',128,'全唐诗/poet.song.144000.json','["都城西頭二月尾，湖水平堤縠紋起。", "南北山光罨畫中，淺深草色裙腰裏。", "羣仙領客泛艅艎，黄帽劈波驚鰋鯉。", "中流劇談聞兩岸，闔坐題詩動盈紙。", "如澠自足醉朋從，餘瀝猶能霑走史。", "當年曲水迹已陳，此日渼陂歡莫擬。", "蹇予小疾獨不至，詩伯索詩殊未已。", "筆已老矣何能爲，但誦西湖比西子。"]'),
('a68242d9-725a-4fdc-bea4-613010f44010','王丞相生辰','喻良能','宋','宋诗','song-poetry','','[]','金華千仞摩穹蒼，雙溪迢迢碧流長。',240,'全唐诗/poet.song.144000.json','["金華千仞摩穹蒼，雙溪迢迢碧流長。", "清淑之氣從風翔，霜縑霧縠不足當。", "真賢挺生金玉相，上擷屈豔薰班香。", "疇昔視草居明光，鴻文大冊壓常楊。", "既陞紫樞兵氣揚，運籌決勝如子房。", "鴻鈞一氣轉混茫，相吉崇璟何足方。", "直與夔龍爲雁行，烟火萬里俱耕桑。", "冠带百蠻走梯航，玉皇案前勤贊襄。", "坐令我宋如虞唐，中書事業殊未央。", "二十四考嗤汾陽，北堂西母壽而康。", "榮封大國富井疆，錦衣命服粲煌煌。", "麻姑一半鬢未霜，亭亭玉樹階蘭芳。", "徽獻凝操書道昌，向來王謝今祇王。", "十倍江左浩莫量，四海同詞祝壽觴。", "願公壽比赤松强，永作一柱扶明堂。"]'),
('d63e24b8-2a0c-4c36-beb0-834c6f6ed3b7','次韻王龜齡狀元西湖賞梅','喻良能','宋','宋诗','song-poetry','','["\u897f\u6e56"]','乘閒選勝真悠哉，正見千樹冰花開。',128,'全唐诗/poet.song.144000.json','["乘閒選勝真悠哉，正見千樹冰花開。", "天寒日暮湖面凈，疎影著水清無埃。", "杏桃畏寒不敢吐，春榜占作羣花魁。", "廣平無人何遜死，睥睨欲賦嗟無才。", "東嘉夫子一何妙，筆端游戲成瓊瑰。", "繁英麗句鬭清好，不用白鷺雙飛來。", "要令奚囊出佳什，故遣漁唱傳清杯。", "西湖處士骨雖槁，一喚暗香風味回。"]'),
('122fd806-7ce5-45f1-9dd3-0e0f58db0dd0','次韻逢使君寺丞見贈','喻良能','宋','宋诗','song-poetry','','[]','冰花零亂飛庭戶，夜色晶瑩似三五。',64,'全唐诗/poet.song.144000.json','["冰花零亂飛庭戶，夜色晶瑩似三五。", "詩仙曉贈白雪篇，便覺清風追吉甫。", "區區五斗不知疲，故園應有北山移。", "凍冷不暇搜佳句，千里歸心到鄉樹。"]'),
('67762f35-41f4-41c1-88fc-d109b11b3a0a','贈神童林公滋公澤女神童幼玉','喻良能','宋','宋诗','song-poetry','','[]','一英二孺同一家，衮衮誦書幾五車。',64,'全唐诗/poet.song.144000.json','["一英二孺同一家，衮衮誦書幾五車。", "語音婭姹春簾燕，稚齒清便蘭砌芽。", "聯茵並載驚都市，萬里青雲從此始。", "兩駒應佩金削刀，雙鬟會作女博士。"]'),
('f5ddbe65-e842-4bac-a838-9c40e5e7ea19','二月二十一日何司業集客于張園玉牒給事命予賦詩紫微舍人左史舍人亦以見委因成七言十韻一首','喻良能','宋','宋诗','song-poetry','','[]','寒食初過天氣佳，帝城名園綠藏鴉。',160,'全唐诗/poet.song.144000.json','["寒食初過天氣佳，帝城名園綠藏鴉。", "白綿紅雨互飄泊，鶑啼燕哢紛交加。", "司成領客當暇日，不惜醉臉生紅霞。", "坐中賓客皆賢豪，一一圭璧無纖瑕。", "夕郎風采照今古，封駁不貸姦與衺。", "紫微筆語妙天下，文鋒凜凜森莫邪。", "左史聲名動六合，豈特疇昔傳三巴。", "一朝櫻筍德星聚，離騷可奴玉可衙。", "蘭亭觴詠僅堪比，金谷歌舞徒能奢。", "我有一匹好東絹，誰爲作圖千古誇。"]'),
('b16335c3-181e-461f-b068-cc482107103e','送楊飛卿國錄','喻良能','宋','宋诗','song-poetry','','[]','楊侯作錄來成均，野鶴昂昂端不羣。',64,'全唐诗/poet.song.144000.json','["楊侯作錄來成均，野鶴昂昂端不羣。", "一朝議論不入意，棄擲祿位如浮雲。", "羣公挽衣留不住，直入苕霅親耕耘。", "惜吾無力叫帝閽，不能以侯直諒聞。"]'),
('5061afcc-9489-41a9-b0ac-6565129a20ce','丙午仲春西湖舟中作','喻良能','宋','宋诗','song-poetry','','["\u897f\u6e56"]','春陰將近一百六，絮擘晴雲新雨足。',112,'全唐诗/poet.song.144000.json','["春陰將近一百六，絮擘晴雲新雨足。", "烟邊芳草碧如茵，籬畔海棠紅映肉。", "相携逗曉出城西，城西風景如杜曲。", "兩岸雲光罨畫濃，一湖春水蒲萄綠。", "坐中豪俊雜吳蜀，磊落羣書紛拄腹。", "掀髯一笑浪波間，淋漓衣袂尋碁局。", "他年想像此風流，應作生綃圖一幅。"]'),
('96b72e2f-e724-42f5-95c1-0a62c7f49b53','天台歌','喻良能','宋','宋诗','song-poetry','','[]','涉海神仙誇蓬萊，登陸勝地稱天台。',384,'全唐诗/poet.song.144000.json','["涉海神仙誇蓬萊，登陸勝地稱天台。", "天台枕海連四明，萬峯千嶺相縈迴。", "赤城繡出綺霞色，瀑布界破瑶山青。", "神仙居處寸步有，遊人白日迷杳冥。", "剡溪昔年有二客，五月此山同采摘。", "只知采采不盈筐，不覺行行失歸陌。", "龜腸蟬腹忽鳴饑，傾壺進食欲令誰。", "山桃一顆垂林畔，共食歘然肌骨換。", "下山得水澗石中，以手飲之還濯盥。", "又見蕪菁出山腰，一杯圓轉中流漂。", "二人相顧却相謂，此地去人應不遥。", "過溪水深四尺許，又度一山逢二女。", "韶顔艷色世所無，南國東鄰何足數。", "笑喚劉晨阮肇名，相識渾如舊有情。", "問郎若箇來何晚，遂即殷勤相奉迎。", "入戶幔帷殊不惡，錯落珍珠與瓔珞。", "只將左右幾青衣，也勝人間誇綽約。", "逡巡進脯飯胡麻，瓊杯片片斟流霞。", "不知仙客來何處，各把宮桃慶女家。", "歌吹嘈嘈張內樂，顔色有歡情有樂。", "金鴉飛入向虞淵，客散虛堂掩簾箔。", "夜深各擁一仙娥，泛泛鴛鴦在綠波。", "和鳴乍自秦簫起，行雨初從楚夢過。", "瞥然一留因半載，天氣常如三月在。"]'),
('e843d7e3-a675-4bfa-8c32-1e8df1978b1d','重陽','喻良能','宋','宋诗','song-poetry','','[]','一年秋節重陽濃，園林上下皆清風。',272,'全唐诗/poet.song.144000.json','["一年秋節重陽濃，園林上下皆清風。", "遠山百里削寒玉，平湖十畝磨青銅。", "亦好茂樹蓊西北，露枝霜葉紛青紅。", "枝頭寂寂少啼鳥，天外隠隠飛征鴻。", "弄月基蟠綠凈中，東南况有小垂虹。", "潭清潦盡境更好，水落石出摹難工。", "愛山堂前花作叢，疎疎楊柳瘦毛同。", "紅蕉碧桂互掩映，蘆花蓼穟交蒙茸。", "新亭爽塏瞰空闊，賃欄一目連七峯。", "烟霏霧靄掃欲盡，但見突兀撐晴空。", "携筇更登月山椒，嶙峋怪石高玲瓏。", "香爐近出陂陁側，雲黄復在南山東。", "水聲激激來澗曲，颼颼風響生樛松。", "菊英萸實籬可採，山肴野䔩盤能供。", "作詩頗類臺戲馬，吹帽未減山名龍。", "良辰美景樂心賞，四者偶并今始逢。", "明朝不問蝶愁絕，更飲黄花琥珀醲。"]'),
('2b4e4a56-e5d7-4d30-8182-815ccb8afa5b','次韻茂恭見寄','喻良能','宋','宋诗','song-poetry','','[]','中書一揮千萬言，有如水懸呂梁間。',160,'全唐诗/poet.song.144000.json','["中書一揮千萬言，有如水懸呂梁間。", "奔逸絕塵不可及，蹇欲從之良獨難。", "如君文字可華國，胡爲猶在南湖側。", "樊川昌谷縱多才，欲以比君那可得。", "君家紅杏連白榆，似向君王得鑑湖。", "水光溶溶浸山色，樓臺上下如冰壺。", "磬湖蕭瑟逢秋令，男呻女吟貧非病。", "阿奴碌碌僅自全，伯氏今亡嗟短命。", "恨我不如大小山，徒爾思苦仍辭艱。", "既無擊鉢揮毫敏，空愧詩筒數往還。"]'),
('475d6542-fea0-46cf-b01c-dffe2630c4c0','題李氏擁萬堂','喻良能','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','我如王恭讀書少，君如鄴侯藏書多。',182,'全唐诗/poet.song.144000.json','["我如王恭讀書少，君如鄴侯藏書多。", "排籤插架三萬軸，知從何處能網羅。", "上自先秦下五季，奧帙隠篇皆略備。", "不同邢邵嬾校讐，丹墨精研吁可貴。", "君不見廬山先生子李子，白石房中富文史。", "胸蟠萬卷筆如神，事業文章俱兩美。", "又不見西蜀劉公少常伯，平生醢芹嗜圖籍。", "傾貲盡寫中秘書，隨身卷軸車連軛。", "邇來置書事經綸，論思獻納日日新。", "君今堂中書汗牛，願君學李兼學劉。", "盡攬英華歸肺腑，一鳴便作沖天舉。"]'),
('993fef20-a171-4fd4-9a5d-8722a7e14958','月窗以所畫觀音見遺爲賦一篇','喻良能','宋','宋诗','song-poetry','','[]','白衣仙人雲海上，肉眼欲看唯想像。',64,'全唐诗/poet.song.144000.json','["白衣仙人雲海上，肉眼欲看唯想像。", "月窗道人心孔開，貌得人天行道相。", "吾聞伯時晚畫佛，妙處不減王摩詰。", "龍眠久矣寂無人，安得却有伯時筆。"]'),
('95c6e4ae-7b40-496a-8d14-851c087f4d3f','硯屏','喻良能','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江遠浪連天碧，岸柳垂垂臨斷石。',64,'全唐诗/poet.song.144000.json','["長江遠浪連天碧，岸柳垂垂臨斷石。", "漁舟一葉白頭翁，獨把釣絲待魚食。", "我身猶是紅塵客，對此無言三歎息。", "安得輪竿入手來，與君共釣消長日。"]'),
('73c62a57-0acc-43e1-abf2-554e60c86dcf','以春盂送茂恭蒙以古詩爲謝次韻奉酬','喻良能','宋','宋诗','song-poetry','','[]','我家古甕彭亨腹，十年貯酒色如玉。',64,'全唐诗/poet.song.144000.json','["我家古甕彭亨腹，十年貯酒色如玉。", "傾瀉惟須老瓦盆，精器便成蛇著足。", "花瓷脆薄誰能携，遣送君家保不虧。", "雖然金盌未伯仲，儻與椰樽相等夷。"]'),
('ff90d012-afd6-44bd-9448-d2e17a6426a2','悲夏畦','喻良能','宋','宋诗','song-poetry','','[]','悲夏畦，南畝苗未長，東皋草已齊。',68,'全唐诗/poet.song.144000.json','["悲夏畦，南畝苗未長，東皋草已齊。", "旋令嫗婦辦餉饁，獨引丁男耘稗稊。", "悲夏畦，炎天炙背如爇雞，渴來不得飲清溪。", "寧知水榭冰山裏，猶自頻嫌日未西。"]'),
('7ec12336-3858-4f69-8328-792eb72f58df','題三洞','喻良能','宋','宋诗','song-poetry','','[]','千古巢仙地，嵌空本自然。',48,'全唐诗/poet.song.144000.json','["千古巢仙地，嵌空本自然。", "一看三嘆息，十步九留連。", "似入華陽洞，疑通小有天。", "何時洗塵垢，來作枕流眠。"]'),
('6294b7ea-6da7-45d8-95a1-6bb82f37343f','三月六日宴李家園亭','喻良能','宋','宋诗','song-poetry','','[]','林園過元巳，流水遶芳藂。',48,'全唐诗/poet.song.144000.json','["林園過元巳，流水遶芳藂。", "略彴半尋影，酴醿一扇風。", "杯盤花氣裏，枕簟鳥聲中。", "公子敬愛客，月明樽未空。"]'),
('62936120-515c-4e8f-a258-f43aab775e4f','郊行','喻良能','宋','宋诗','song-poetry','','[]','散策林塘路，秋深別有光。',48,'全唐诗/poet.song.144000.json','["散策林塘路，秋深別有光。", "晦明雲聚散，濃淡樹青黄。", "晚覺衣襟冷，風吹橘柚香。", "菊花何處有，聊欲試重陽。"]'),
('823ba747-a1d7-4e80-9efb-ccba260a7217','次韻季野弟蠟梅','喻良能','宋','宋诗','song-poetry','','[]','媚色全勝柳，孤標半似梅。',48,'全唐诗/poet.song.144000.json','["媚色全勝柳，孤標半似梅。", "蘂寒金粉膩，香重麝臍開。", "徐筆那能畫，并刀未易裁。", "扶頭中酒味，安得一枝來。"]'),
('89649c4d-8308-43d1-83ad-5b1f1d584079','讀書','喻良能','宋','宋诗','song-poetry','','[]','傍砌看黄嬭，臨池誦子虛。',48,'全唐诗/poet.song.144000.json','["傍砌看黄嬭，臨池誦子虛。", "顧慚雖耗忘，聊復惜居諸。", "屋上兩鸜鵒，波間雙鯉魚。", "疑他不識字，何事也聽書。"]'),
('0d93a50f-6eda-4543-84be-6bab9a2f4466','讀玉局集','喻良能','宋','宋诗','song-poetry','','[]','曉讀蘇僊集，披翻未覺勞。',48,'全唐诗/poet.song.144000.json','["曉讀蘇僊集，披翻未覺勞。", "衙官視宋玉，奴僕命離騷。", "赤壁清風遠，黄樓逸興高。", "獨嗟生苦晚，不得侍揮毫。"]'),
('d83fde38-2279-42a5-8b53-aa2a5679d57c','留別伯壽兄','喻良能','宋','宋诗','song-poetry','','[]','相過不憚遠，相迎慰所思。',48,'全唐诗/poet.song.144000.json','["相過不憚遠，相迎慰所思。", "須知對床處，絕勝陟岡時。", "夜雨論疇昔，秋風惜別離。", "明年楚東景，準擬共題詩。"]'),
('dcdf7586-b2a4-4277-bdab-52c3b3042408','之官桐川道中口占','喻良能','宋','宋诗','song-poetry','','[]','登道重逢驛，離家再及晨。',48,'全唐诗/poet.song.144000.json','["登道重逢驛，離家再及晨。", "雲輕山色曉，寒淺鳥聲春。", "碧澗梅花老，銀杯竹葉新。", "前途風日好，持用悅慈親。"]'),
('18eb2a7b-eb2a-4361-b90a-0998c75b3f08','戲綵堂有作','喻良能','宋','宋诗','song-poetry','','[]','捧檄及偏親，斑衣聊效顰。',48,'全唐诗/poet.song.144000.json','["捧檄及偏親，斑衣聊效顰。", "旨甘貧有味，溫凊靜無塵。", "北戶足萱草，南風宜棘薪。", "版輿多喜色，庶不愧安仁。"]'),
('3a06faec-8bc2-4ea8-bb86-a28c816bb14a','次韻趙景明呈許明府','喻良能','宋','宋诗','song-poetry','','[]','卜晝開英集，瑶林映珷玞。',48,'全唐诗/poet.song.144000.json','["卜晝開英集，瑶林映珷玞。", "顧慚梅隠吏，繆接范萊蕪。", "官柳春猶淺，江梅韻亦孤。", "他年想風味，應有汭川圖。"]'),
('3a529912-4cec-4eba-a758-14517b02d6d6','對鏡芙蓉二嶺相望僅三十里高不知幾百尺十步九折殆不啻蜀道之難也己卯孟秋沿檄過之僕夫告痡己亦罷極因成小詩','喻良能','宋','宋诗','song-poetry','','[]','石鏡寧堪對，芙蓉不是花。',48,'全唐诗/poet.song.144000.json','["石鏡寧堪對，芙蓉不是花。", "險中多虎跡，平處少人家。", "曲六蛇行迥，欹危鳥道斜。", "白雲宜入望，不怕亂山遮。"]'),
('537880af-33da-4768-bbc7-ecd790a6a68e','九日同尤司戶舟行遊梅山','喻良能','宋','宋诗','song-poetry','','[]','令節逢重九，相携鑑上遊。',48,'全唐诗/poet.song.144000.json','["令節逢重九，相携鑑上遊。", "扁舟浮舴艋，左手把蝤蛑。", "紅葉明青眼，黄花重白頭。", "晚來風色好，歸棹得夷猶。"]'),
('3f5d41ce-21ad-4845-9005-2b3d136637ed','題聽雨軒','喻良能','宋','宋诗','song-poetry','','[]','小軒在官舍，不與囂塵并。',48,'全唐诗/poet.song.144000.json','["小軒在官舍，不與囂塵并。", "清池浸窗檻，修篁礙簷楹。", "幾當迢迢夜，聽此瀟瀟聲。", "懷哉對床約，輾轉難爲情。"]'),
('59abd5e7-1cae-4ddf-bd13-75537c7acf8d','晚行竹山道中','喻良能','宋','宋诗','song-poetry','','[]','山瘦溪如練，丹青見亦稀。',48,'全唐诗/poet.song.144000.json','["山瘦溪如練，丹青見亦稀。", "亂鴉將影過，孤鶩带霞飛。", "秋色此時老，故園何日歸。", "西風吹獨立，搔首怯征衣。"]'),
('68e9e541-86b0-4a96-8ae3-7738c4068949','始生之日黎明以職事出郊','喻良能','宋','宋诗','song-poetry','','[]','征鞍隨曉色，重露濕衣巾。',48,'全唐诗/poet.song.144000.json','["征鞍隨曉色，重露濕衣巾。", "誰謂懸弧日，翻爲執轡辰。", "野花工笑客，啼鳥故窺人。", "呼酒澆孤悶，何心作好春。"]'),
('4321bf75-4b9c-439f-aa14-4c53b11cee51','朝爽之前瑞竹忽生','喻良能','宋','宋诗','song-poetry','','[]','好竹逾千箇，數莖忽發生。',48,'全唐诗/poet.song.144000.json','["好竹逾千箇，數莖忽發生。", "月明連理影，風細合歡聲。", "矯矯雙鴛舉，翛翛兩鳳鳴。", "祇應三昧手，綵筆畫難成。"]'),
('978ab5c5-f878-40d0-bf51-d0c9c46ed66c','端午至太平寺','喻良能','宋','宋诗','song-poetry','','[]','客裏逢端午，僧廊雨氣凉。',48,'全唐诗/poet.song.144000.json','["客裏逢端午，僧廊雨氣凉。", "篔簹千箇碧，薝蔔六花香。", "魯頖程尤遠，潘輿興自長。", "糝蒲傾美酒，笑入醉中鄉。"]'),
('eb628e97-bc6a-45b2-9098-3863714eac44','題九華山用太白聯句韻','喻良能','宋','宋诗','song-poetry','','["\u4e5d\u534e\u5c71"]','千古池陽郡，九峰應最華。',48,'全唐诗/poet.song.144000.json','["千古池陽郡，九峰應最華。", "明珠絢晨露，麗綺粲晴霞。", "嶺頭過子晉，巖腹憩洪崖。", "謫仙無復見，空想夏侯家。"]'),
('2a733c7d-8804-49ae-99fe-ed28fc7cb051','題建德驛用經略張舍人壁間韻','喻良能','宋','宋诗','song-poetry','','[]','殘暑塗山去，凉風至德來。',48,'全唐诗/poet.song.144000.json','["殘暑塗山去，凉風至德來。", "吟餘秋色老，客裏菊花開。", "傳舍全依石，中庭半是苔。", "張公有佳句，三復興悠哉。"]'),
('2cc81c05-8375-41f6-9f4b-779c899154a1','新安遇雪','喻良能','宋','宋诗','song-poetry','','[]','寒色今朝異，屯雲萬里同。',48,'全唐诗/poet.song.144000.json','["寒色今朝異，屯雲萬里同。", "定知花翦水，不是絮因風。", "薄宦翻成旅，愁吟未易工。", "白頭親八十，留滯楚江東。"]'),
('bf2d1b1c-28fc-4055-9ffa-7e71ade6b2af','次韻謝子良詠雪','喻良能','宋','宋诗','song-poetry','','[]','晚來寒氣重，景物故撩人。',48,'全唐诗/poet.song.144000.json','["晚來寒氣重，景物故撩人。", "不厭詩雕腎，寧辭酒入唇。", "恍驚殘夜月，疑夢故園春。", "欲倩何人畫，紛紛飛玉塵。"]'),
('55a36f3a-b9bd-401e-a140-5bf4e2b6fac2','青巖道中','喻良能','宋','宋诗','song-poetry','','[]','寒食江村路，東風野渡航。',48,'全唐诗/poet.song.144000.json','["寒食江村路，東風野渡航。", "一篙春水碧，兩岸落花香。", "飛絮匆匆遠，青山故故長。", "茲遊自奇絕，底用更尋芳。"]'),
('e9143477-1846-440a-b123-76f7c44bc45e','周少府由姑熟送余同宿于玩鞭亭','喻良能','宋','宋诗','song-poetry','','[]','相別古桃郡，相逢南豫州。',48,'全唐诗/poet.song.144000.json','["相別古桃郡，相逢南豫州。", "五年勞望眼，一笑失離愁。", "碧水溪橋暮，西風野店秋。", "追隨成夜宿，不爲玩鞭留。"]'),
('ca396826-b3fc-4131-a367-72422a4d6ba6','寄陳孟容二首  其一','喻良能','宋','宋诗','song-poetry','','[]','先生湖海士，餘子詎能班。',48,'全唐诗/poet.song.144000.json','["先生湖海士，餘子詎能班。", "正始清談近，黄初美句還。", "相望半舍外，契闊數年間。", "何日衡茅底，匏樽一破顔。"]'),
('53c92ee0-6641-43cc-b9ff-1485f75e6c9f','寄陳孟容二首  其二','喻良能','宋','宋诗','song-poetry','','[]','細草還堪藉，柔荆亦可班。',48,'全唐诗/poet.song.144000.json','["細草還堪藉，柔荆亦可班。", "馭風如肯過，踏月不妨還。", "種藥臨花畔，分流遶竹間。", "眼邊無俗物，頗似一瓢顔。"]'),
('1b019203-0a08-4cb3-a49c-80414593913b','廣信道中','喻良能','宋','宋诗','song-poetry','','[]','昔日題詩處，重來續勝遊。',48,'全唐诗/poet.song.144000.json','["昔日題詩處，重來續勝遊。", "綠陰初入夏，蒼鬢幾經秋。", "細雨渡頭市，孤煙汀際舟。", "溪山雖信美，翻恨不淹留。"]'),
('75115331-cf45-4640-97cc-ac9baf6cdec7','次韻侍御晚宿三叉口','喻良能','宋','宋诗','song-poetry','','[]','故里頻懷梓，新堤未築沙。',48,'全唐诗/poet.song.144000.json','["故里頻懷梓，新堤未築沙。", "文章真吏部，吟詠許劉叉。", "酒醆孤風物，詩筒隔歲華。", "相思江路遠，煙雨茁芳葭。"]'),
('073a1a54-a56b-466b-89d3-67d28c8d703f','書大洞僧壁','喻良能','宋','宋诗','song-poetry','','[]','招提閟林麓，魚鼓白雲邊。',48,'全唐诗/poet.song.144000.json','["招提閟林麓，魚鼓白雲邊。", "地僻疑無路，山深別有天。", "幽花充佛供，好鳥伴僧禪。", "何日征鞭暇，重來借榻眠。"]'),
('6599a0b8-9c0c-48a0-89b1-c46dba90b5a3','寒食遊香山','喻良能','宋','宋诗','song-poetry','','[]','杖藜隨所適，花柳自村村。',48,'全唐诗/poet.song.144000.json','["杖藜隨所適，花柳自村村。", "野岸桃臨水，人家竹映門。", "香泥飛燕子，芳草思王孫。", "著處堪沈醉，春醪正滿樽。"]'),
('2eb01259-eb03-411d-93c8-924eeacb7325','被郡檄禱雨丹井山徐真君祠登山拜畢即獲𩃎霈追用韓文公郴州祈雨韻','喻良能','宋','宋诗','song-poetry','','[]','欲解驕陽厄，寧辭祀禮繁。',48,'全唐诗/poet.song.144000.json','["欲解驕陽厄，寧辭祀禮繁。", "純誠殫毣毣，英烈仰言言。", "雲陣千屯合，雷聲萬馬奔。", "晚來歸路好，飄灑勢騰軒。"]'),
('d4c7de46-9259-4b4f-991d-919a92d08b74','紫霄宮','喻良能','宋','宋诗','song-poetry','','[]','間關穿木杪，詰屈轉山腰。',48,'全唐诗/poet.song.144000.json','["間關穿木杪，詰屈轉山腰。", "自昔形清夢，于今到紫霄。", "容儀粲冰雪，環珮響瓊瑶。", "安得顧吳手，憑渠圖素綃。"]'),
('6b10fe83-ccf6-4618-bfb4-7480e6c75966','攝邑獄空','喻良能','宋','宋诗','song-poetry','','[]','番邑於今劇，民風自古雄。',48,'全唐诗/poet.song.144000.json','["番邑於今劇，民風自古雄。", "琴堂慚久攝，劍獄喜新空。", "纆索塵埃裏，桁楊片段中。", "使君端不擾，顧我百無功。"]'),
('bec37866-1638-4b81-a28a-9c55487f0a4d','石井','喻良能','宋','宋诗','song-poetry','','[]','山右最佳處，有泉生石傍。',48,'全唐诗/poet.song.144000.json','["山右最佳處，有泉生石傍。", "虛明秋後月，清冷雪前霜。", "鰻井真牛後，龍湫可鴈行。", "濯纓仍潄齒，政爾不能忘。"]'),
('52c83b8b-725e-4461-b896-0f100178f782','游西源','喻良能','宋','宋诗','song-poetry','','[]','萬里西源路，秋風屐齒鳴。',48,'全唐诗/poet.song.144000.json','["萬里西源路，秋風屐齒鳴。", "嶙峋千障碧，窈窕一川清。", "天柱雲霄迥，香爐霧靄輕。", "何當携翠袖，重遣酒壺傾。"]'),
('ea3a45b5-072e-4266-9fab-fe6d42b50882','奉和趙大本教授何處春深好二首  其一','喻良能','宋','宋诗','song-poetry','','[]','何處春深好，春深泮水家。',48,'全唐诗/poet.song.144000.json','["何處春深好，春深泮水家。", "不妨頻折角，寧復誤隨車。", "已見傾三峽，行看判五花。", "日邊催覲速，芝檢紫泥斜。"]'),
('7fc95dfb-3ecf-49da-85af-2cf6a347e95b','奉和趙大本教授何處春深好二首  其二','喻良能','宋','宋诗','song-poetry','','[]','何處春深好，春深倅貳家。',48,'全唐诗/poet.song.144000.json','["何處春深好，春深倅貳家。", "雨低簷外柳，風度牖間花。", "有意揮吟筆，無心顧麴車。", "慈顔一笑粲，戲舞綵衣斜。"]'),
('1a125b75-86d2-4d00-a1b5-6100606bb659','景德道中口占','喻良能','宋','宋诗','song-poetry','','[]','捧檄東方日，芳春未及歸。',48,'全唐诗/poet.song.144000.json','["捧檄東方日，芳春未及歸。", "路花紅掩映，溪樹綠因依。", "鳥語催寒食，人煙接翠微。", "尋詩忘遠近，細雨濕征衣。"]'),
('08c6aa79-a34f-4c5d-b0b5-e02cc7e4dbe4','由安仁回宿大木寺','喻良能','宋','宋诗','song-poetry','','[]','御史題詩處，山深草木雄。',48,'全唐诗/poet.song.144000.json','["御史題詩處，山深草木雄。", "一番青燒雨，十里錦帆風。", "婆餠林間語，山茶葉上紅。", "明朝入于越，吟詠與誰同。"]'),
('9a9d0ed4-88f2-46b5-bbac-ae23dbc20c96','奉酬王宗丞用宿大木寺韻見贈','喻良能','宋','宋诗','song-poetry','','[]','譽處千鈞重，文章一世雄。',48,'全唐诗/poet.song.144000.json','["譽處千鈞重，文章一世雄。", "詩工穿月脅，檄好愈頭風。", "北嶽關山碧，南州荔子紅。", "使君今北海，還許一樽同。"]'),
('c7f45ae9-807b-4ed4-add6-043b30dd8792','送侍御帥夔府  其一','喻良能','宋','宋诗','song-poetry','','[]','湖海番君國，江山白帝城。',48,'全唐诗/poet.song.144000.json','["湖海番君國，江山白帝城。", "凝香餘坐嘯，飛詔趣遄征。", "譽處千鈞重，輜車一羽輕。", "攀轅雪眉老，送目逐雙旌。"]'),
('ecde6507-d927-4f7a-acdb-3509e64bb901','送侍御帥夔府  其二','喻良能','宋','宋诗','song-poetry','','[]','千古楚東郡，風流今在茲。',48,'全唐诗/poet.song.144000.json','["千古楚東郡，風流今在茲。", "魯公元直道，文正不妨詩。", "鉗吏似束濕，麾龍如使兒。", "甘棠足遺愛，會有去思碑。"]'),
('192fc4de-9383-4dc2-866b-7eb400a6e744','送侍御帥夔府  其三','喻良能','宋','宋诗','song-poetry','','[]','西風動行色，詩景繞征鞍。',48,'全唐诗/poet.song.144000.json','["西風動行色，詩景繞征鞍。", "赤甲懸危壁，黄牛瀉急湍。", "猿聲雲背落，山勢馬頭盤。", "天險須人守，毋辭蜀道難。"]'),
('7c24bd74-71b9-4118-8483-7c0220767a04','送侍御帥夔府  其四','喻良能','宋','宋诗','song-poetry','','[]','諸葛仍祠廟，公孫只故基。',48,'全唐诗/poet.song.144000.json','["諸葛仍祠廟，公孫只故基。", "棟梁酣夕照，雉堞蔓秋葵。", "耿耿登臨意，悠悠今古思。", "烹鮮不勞力，餘事杜陵詩。"]'),
('95b5f32c-3a28-49af-b471-17bbdbf7e41c','送侍御帥夔府  其五','喻良能','宋','宋诗','song-poetry','','[]','四海猶多事，中原未版圖。',48,'全唐诗/poet.song.144000.json','["四海猶多事，中原未版圖。", "皇心思啟沃，赤子望霑濡。", "八陣難留滯，三階拱進趨。", "茂弘寧有意，江左待夷吾。"]'),
('b10e0a25-9d58-4429-b8d3-4bd8aafba1c6','被檄之上饒言還未幾又復往焉至小渡遇雨遣興一首','喻良能','宋','宋诗','song-poetry','','[]','檄至方云急，吾行敢滯留。',48,'全唐诗/poet.song.144000.json','["檄至方云急，吾行敢滯留。", "朔風經小渡，細雨過中洲。", "冉冉新斑鬢，飄飄敝黑裘。", "欲知來往久，三見月如鈎。"]'),
('82424b5c-1479-4d40-99ce-9f722cb14c3c','九月五日周少府衛秀才會飲吳波亭周有詩因次韻','喻良能','宋','宋诗','song-poetry','','[]','碧水初微落，黄花亦未簪。',48,'全唐诗/poet.song.144000.json','["碧水初微落，黄花亦未簪。", "三人千里客，尊酒五年心。", "我獨年齊白，君皆句似陰。", "不妨鐺脚坐，聊作夜深吟。"]'),
('7764602b-2f9b-4c35-973e-d2cda8e40c04','次韻王侍御夜宿高牙','喻良能','宋','宋诗','song-poetry','','[]','相別三時久，相望萬里賒。',48,'全唐诗/poet.song.144000.json','["相別三時久，相望萬里賒。", "携書期過雁，徙倚至昏鴉。", "風雨番君國，雲煙夔子家。", "何時趣歸覲，重許拜高牙。"]'),
('05199da7-abea-4666-ab5c-b237bcbe62b8','至日見梅','喻良能','宋','宋诗','song-poetry','','[]','漸老身仍健，多愁鬢易華。',48,'全唐诗/poet.song.144000.json','["漸老身仍健，多愁鬢易華。", "異鄉逢至節，細雨見梅花。", "酒薄那能醉，詩成敢自誇。", "何時故園裏，徙倚看橫斜。"]'),
('6c51cdfc-f49b-489e-aaec-f9feb9516f30','次韻俞尉春日遣興','喻良能','宋','宋诗','song-poetry','','[]','漸欣長晝煖，欲解短爐圍。',48,'全唐诗/poet.song.144000.json','["漸欣長晝煖，欲解短爐圍。", "春色已如此，故園猶未歸。", "韋編今日事，回首去年非。", "鏡裏衰遲色，多慚壯志違。"]'),
('8dd6c41e-b22c-4691-9658-70d5ba0e7389','留別趙明府','喻良能','宋','宋诗','song-poetry','','[]','綵棒漫分部，牛刀新發硎。',48,'全唐诗/poet.song.144000.json','["綵棒漫分部，牛刀新發硎。", "花城方竊蔭，瓜戍已餘蓂。", "生計雙蓬鬢，歸心幾驛亭。", "他時重會面，應是眼俱青。"]'),
('939e4dce-4981-445c-9f31-9b2918b5d754','初離鄱陽','喻良能','宋','宋诗','song-poetry','','[]','三年勞簿領，今日進歸程。',48,'全唐诗/poet.song.144000.json','["三年勞簿領，今日進歸程。", "意與長途遠，身兼薄縠輕。", "板輿頻送喜，山驛屢逢晴。", "道上人爭指，霜髭綵戲榮。"]'),
('97334c05-f93d-4cee-a4f6-4de41b849552','衢右道中  其一','喻良能','宋','宋诗','song-poetry','','[]','投曉行衢右，經旬別楚東。',48,'全唐诗/poet.song.144000.json','["投曉行衢右，經旬別楚東。", "侵衣梅溽雨，吹面麥秋風。", "壠畝凝煙外，峰巒滴翠中。", "懸知鄉井近，漸喜語音同。"]'),
('7da827ed-51f0-4c24-a965-1e914e011bf6','衢右道中  其二','喻良能','宋','宋诗','song-poetry','','[]','漸喜家居近，相望六驛間。',48,'全唐诗/poet.song.144000.json','["漸喜家居近，相望六驛間。", "脫身江左役，洗眼浙東山。", "鄉味初充饌，慈闈亦破顔。", "經過縠溪水，應笑鬢毛斑。"]'),
('f6e83053-05ff-4049-92a6-31cae0143f2e','村居夜坐讀王右丞山中與裴迪書愛其清婉有魏晉風味因集其語作詩一首亦老坡哨遍之義也','喻良能','宋','宋诗','song-poetry','','[]','景氣既和暢，故園殊可依。',48,'全唐诗/poet.song.144000.json','["景氣既和暢，故園殊可依。", "遠山映清月，曲水涵淪漪。", "寒犬吠如豹，村舂聞自機。", "因思曩昔友，携手同賦詩。"]'),
('5f975cd8-517f-4a53-b247-e8c428f185b9','獨善堂','喻良能','宋','宋诗','song-poetry','','[]','賞心并四者，文史足三餘。',48,'全唐诗/poet.song.144000.json','["賞心并四者，文史足三餘。", "不作簪紳念，唯便水竹居。", "佳名元籍籍，真樂每如如。", "月旦遺評在，今經幾建除。"]'),
('0515c5ac-f85a-4d93-91dc-342be94c5c85','靈山寺','喻良能','宋','宋诗','song-poetry','','[]','松竹聲中寺，山深人迹稀。',48,'全唐诗/poet.song.144000.json','["松竹聲中寺，山深人迹稀。", "石從林背出，雲向屋頭飛。", "野鹿寒仍聚，棲禽暮自歸。", "怪來襟袖冷，濃翠濕征衣。"]'),
('bc655215-f1aa-4c30-b35c-265d1a2b6553','買舟至九里松遊三天竺','喻良能','宋','宋诗','song-poetry','','[]','解維凌皺玉，輟棹理孤筇。',48,'全唐诗/poet.song.144000.json','["解維凌皺玉，輟棹理孤筇。", "遊遍三天竺，行窮九里松。", "泉聲依石細，山色共秋濃。", "佳處吾能識，幽巖倚秀峰。"]'),
('caa39ca9-9304-4ebf-b3fd-75aebeb2845a','次韻外舅黄虞卿爲愛山園好八首  其一','喻良能','宋','宋诗','song-poetry','','[]','爲愛山園好，芒鞵步步高。',48,'全唐诗/poet.song.144000.json','["爲愛山園好，芒鞵步步高。", "綠針撏露韭，碧箸翦春蒿。", "但得林泉趣，誰能州縣勞。", "何慚王孝伯，痛飲讀離騷。"]'),
('31697781-ac39-4e76-8a12-a9194ea828ea','次韻外舅黄虞卿爲愛山園好八首  其二','喻良能','宋','宋诗','song-poetry','','[]','爲愛山園好，芳籬占一涯。',48,'全唐诗/poet.song.144000.json','["爲愛山園好，芳籬占一涯。", "自耘三徑草，不斷四時花。", "柳絮風中雪，芙蓉水上霞。", "銀潢何處是，不擬問仙槎。"]'),
('0cda4bdf-8eca-4a2f-bed9-ff0e4385e712','次韻外舅黄虞卿爲愛山園好八首  其三','喻良能','宋','宋诗','song-poetry','','[]','爲愛山園好，年年草色新。',48,'全唐诗/poet.song.144000.json','["爲愛山園好，年年草色新。", "醉眠欹柳幄，吟坐俯苔茵。", "栗里風煙古，樊川花木春。", "誰云無伴侶，對影共三人。"]'),
('134fd03c-3926-4bbc-8f55-d76a8b9ce4b7','次韻外舅黄虞卿爲愛山園好八首  其四','喻良能','宋','宋诗','song-poetry','','[]','爲愛山園好，都無塵世喧。',48,'全唐诗/poet.song.144000.json','["爲愛山園好，都無塵世喧。", "穗禾臨芰沼，繩草對苔垣。", "去就隨佳醖，窮通付寓言。", "還同李長吉，來過有高軒。"]'),
('271cae7e-fcde-49a7-b071-37a8c116d8d8','次韻外舅黄虞卿爲愛山園好八首  其五','喻良能','宋','宋诗','song-poetry','','[]','爲愛山園好，蕭齋竹逕通。',48,'全唐诗/poet.song.144000.json','["爲愛山園好，蕭齋竹逕通。", "踈簾捲雌霓，曲檻倚雄風。", "愛酒杜陵老，煎茶桑苧翁。", "菟裘真得計，蹤跡免飄蓬。"]'),
('3574769f-7c93-40e3-adb2-aefcd4284c76','次韻外舅黄虞卿爲愛山園好八首  其六','喻良能','宋','宋诗','song-poetry','','[]','爲愛山園好，投閒日日來。',48,'全唐诗/poet.song.144000.json','["爲愛山園好，投閒日日來。", "花時長夜飲，雪後煖寒杯。", "一逕松篁影，滿畦桑柘栽。", "未能湖海去，幽興亦悠哉。"]'),
('a2f450d9-8d46-4c2b-a329-f25a5a40ccfb','次韻外舅黄虞卿爲愛山園好八首  其七','喻良能','宋','宋诗','song-poetry','','[]','爲愛山園好，林塘十畝寬。',48,'全唐诗/poet.song.144000.json','["爲愛山園好，林塘十畝寬。", "露深花臉濕，春淺柳眉攢。", "只擬希高隠，那能縛小官。", "壽山誰問訊，太白正虯蟠。"]'),
('02b27e2a-f47b-43bf-9f60-a639d2df6ab7','次韻外舅黄虞卿爲愛山園好八首  其八','喻良能','宋','宋诗','song-poetry','','[]','爲愛山園好，紅塵半點無。',48,'全唐诗/poet.song.144000.json','["爲愛山園好，紅塵半點無。", "自應成小隠，誰復嘆將蕪。", "香秫五十畝，黄柑二百株。", "何必隨俯仰，歸去亦良圖。"]'),
('56fe880e-3c35-487b-a0e1-a48f8adeb97d','次韻劉淳叟見寄二首  其一','喻良能','宋','宋诗','song-poetry','','[]','九萬垂雲翼，胡爲乃倦飛。',48,'全唐诗/poet.song.144000.json','["九萬垂雲翼，胡爲乃倦飛。", "丘園聊偃息，巖阜故因依。", "蝶栩新酣睡，鷗馴久息機。", "祇應與風景，相賞莫相違。"]'),
('56ed4f1a-bd3f-4cc0-8426-e6c53aa833ec','次韻劉淳叟見寄二首  其二','喻良能','宋','宋诗','song-poetry','','[]','出處雙青鬢，生涯一釣舟。',48,'全唐诗/poet.song.144000.json','["出處雙青鬢，生涯一釣舟。", "淺深山遠近，濃淡樹稀稠。", "隠几晝逾靜，捲簾春更幽。", "何當乘興去，艤棹向汀洲。"]'),
('07fc63b9-8b0e-4260-8262-d0982c8c2799','次韻季直小疾初愈見寄','喻良能','宋','宋诗','song-poetry','','[]','暌違纔一日，懷想似三秋。',48,'全唐诗/poet.song.144000.json','["暌違纔一日，懷想似三秋。", "忽得五字句，真成百不憂。", "荷花要同賦，竹徑擬清游。", "明夜月華滿，杖藜能過不。"]'),
('c2259cb8-514c-414e-b16d-dfad5465a9b9','二月二日大雪','喻良能','宋','宋诗','song-poetry','','[]','磬湖二月雪，寒氣故裴回。',48,'全唐诗/poet.song.144000.json','["磬湖二月雪，寒氣故裴回。", "麵市連天合，銀花照眼開。", "送窮窮不去，招隠隠難來。", "幸有麴生在，何妨略耻罍。"]'),
('316c32f5-94a1-40e8-9f37-a1ad67806261','遣興  其一','喻良能','宋','宋诗','song-poetry','','[]','山園近寒食，春事總芳菲。',48,'全唐诗/poet.song.144000.json','["山園近寒食，春事總芳菲。", "風暖鵓鴣語，日長蝴蝶飛。", "花光明醉眼，草色浄塵衣。", "自足家居樂，爲生未覺非。"]'),
('c2555b9c-a871-4416-a34d-58e80542383e','遣興  其二','喻良能','宋','宋诗','song-poetry','','[]','昔忝郡文學，今爲宗子師。',48,'全唐诗/poet.song.144000.json','["昔忝郡文學，今爲宗子師。", "政懷三釜樂，那復四愁詩。", "時服光摇目，香秔滑溜匙。", "唯應講風雅，儻可解人頤。"]'),
('7e66c4f1-4fdc-45bc-be24-dede400edea5','伯兄由臨海歸省出示近詩次韻奉別','喻良能','宋','宋诗','song-poetry','','[]','相別既四載，相看如友生。',48,'全唐诗/poet.song.144000.json','["相別既四載，相看如友生。", "未成投轄飲，先作倒衣迎。", "夜雨方同聽，秋風又獨行。", "不堪分手處，霜重鴈行輕。"]'),
('036a8294-c1f1-4f41-a201-45c5aec7c09c','重九會飲愛山堂','喻良能','宋','宋诗','song-poetry','','[]','閒居愛重九，賒酒對黄花。',48,'全唐诗/poet.song.144000.json','["閒居愛重九，賒酒對黄花。", "水榭杯盤瑩，家人笑語譁。", "宦情薄秋靄，吟思繞晴霞。", "向晚歸途好，飄飄醉帽斜。"]'),
('36ccb61b-9075-4f97-b67e-4d60cc26714e','乏酒','喻良能','宋','宋诗','song-poetry','','[]','摇落偏悲客，清寒易中人。',48,'全唐诗/poet.song.144000.json','["摇落偏悲客，清寒易中人。", "寂寥那自守，淡泊亦殊真。", "浮俗仍皆醉，虛談浪飲醇。", "高歌傲燕市，忽憶重千鈞。"]'),
('96874b62-e7ce-468c-b775-a3af0413d44f','五舅處士惠訪小園作詩爲謝','喻良能','宋','宋诗','song-poetry','','[]','五舅多道氣，相過茹杞苗。',48,'全唐诗/poet.song.144000.json','["五舅多道氣，相過茹杞苗。", "意行隨綠徑，情話竟清宵。", "送酒飛花急，撩人鳥語嬌。", "不堪分手處，風雨晚瀟瀟。"]'),
('e8416843-4d2a-4903-8abf-6e9527f4a4a3','海上作','喻良能','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','晴浪空仍白，雲峰遠更青。',48,'全唐诗/poet.song.144000.json','["晴浪空仍白，雲峰遠更青。", "乾坤幾萬里，聚落一浮萍。", "自昔聞溟渤，從今小洞庭。", "端如初發覆，坐覺病眸醒。"]'),
('c3b8ac2c-d4b7-4682-b6e5-663791e22cc3','再用彝公長老韻贈嗣宗教授','喻良能','宋','宋诗','song-poetry','','[]','居易青衫舊，安仁素髮新。',48,'全唐诗/poet.song.144000.json','["居易青衫舊，安仁素髮新。", "愁思中酒聖，貧忍論錢神。", "白也詩誰敵，潮乎筆更親。", "生辰宿南斗，同是數奇人。"]'),
('7a47c98d-9c6a-40ca-96f4-d96a0e1ad549','疊嶂寒溪硯屏','喻良能','宋','宋诗','song-poetry','','[]','疊嶂千重秀，寒溪十里清。',48,'全唐诗/poet.song.144000.json','["疊嶂千重秀，寒溪十里清。", "漁舟朝欵乃，樵斧晝敲鏗。", "窈窕疑身到，幽奇訝筆精。", "蕭齋凝睇久，坐覺世情輕。"]'),
('3809cefa-e72f-4b17-b18a-9ee32c361e58','次韻何茂恭永新見寄之什  其一','喻良能','宋','宋诗','song-poetry','','[]','起家從吏役，寧爲食無魚。',48,'全唐诗/poet.song.144000.json','["起家從吏役，寧爲食無魚。", "游樂廢山澤，懷歸畏簡書。", "文章簿領外，風采折腰餘。", "卧轍從茲始，爲謀未覺疎。"]'),
('99a3e033-6c53-471c-ad2f-b0c6fd1a8c1c','次韻何茂恭永新見寄之什  其二','喻良能','宋','宋诗','song-poetry','','[]','尺書將遠意，飄忽渡江湖。',48,'全唐诗/poet.song.144000.json','["尺書將遠意，飄忽渡江湖。", "嘉楮藤溪少，纖毫月窟無。", "封題煩妙札，沾丐到迂儒。", "多謝相思切，迢迢千里途。"]'),
('dc0d05cd-6eb4-4057-95ae-d39cddb72303','立秋日迓宣諭中丞奉懷宋嗣宗','喻良能','宋','宋诗','song-poetry','','[]','繡斧離朝右，羸驂走道周。',48,'全唐诗/poet.song.144000.json','["繡斧離朝右，羸驂走道周。", "侵星宵不寐，曝日夕初休。", "天地方炎暑，山林漫早秋。", "廣文官舍靜，應念汗交流。"]'),
('818cbb46-3530-450c-a1a5-3d3a2b11dd12','試院九日次王茂材丞公韻兼呈翁沂伯廣文','喻良能','宋','宋诗','song-poetry','','[]','秋杪仍新霽，天涯憶故鄉。',48,'全唐诗/poet.song.144000.json','["秋杪仍新霽，天涯憶故鄉。", "少陵三坐客，太白兩重陽。", "深院日復日，寒花黄未黄。", "昔年吹帽飲，今日讀書牀。"]'),
('f184102c-adf6-48ff-8158-a6c7fc8df8d4','筠溪','喻良能','宋','宋诗','song-poetry','','[]','精舍仍幽處，深溪冒淺篁。',48,'全唐诗/poet.song.144000.json','["精舍仍幽處，深溪冒淺篁。", "寒聲隨浪起，翠影共流長。", "斷岸通秋月，虛簷受夏凉。", "雖無杜陵韻，絕勝贊公房。"]'),
('5781e83f-bc97-4bdd-bc12-cece2ee3879e','二月五日夜夢何茂恭論詩','喻良能','宋','宋诗','song-poetry','','[]','不見水曹久，相思亦已勤。',48,'全唐诗/poet.song.144000.json','["不見水曹久，相思亦已勤。", "夢中不識路，樽酒細論文。", "家食甘春薺，官居采泮芹。", "何時真會面，風月與平分。"]'),
('30c86654-3a05-45d4-a101-ac72adbb365e','挽鹽官縣丞何公','喻良能','宋','宋诗','song-poetry','','[]','先子生辛未，齊年見此翁。',48,'全唐诗/poet.song.144000.json','["先子生辛未，齊年見此翁。", "從容六紀內，隠約古人風。", "教子從書積，延賓畏酒空。", "階前桃杏色，依舊入簾紅。"]'),
('7f76e563-aa8e-46cc-ba17-a651df5c1cd0','夜夢亦好園','喻良能','宋','宋诗','song-poetry','','[]','薄宦思歸切，天涯秋氣深。',48,'全唐诗/poet.song.144000.json','["薄宦思歸切，天涯秋氣深。", "一番南國夢，千里故園心。", "歷歷湖邊路，悠悠沙上禽。", "橫枝清絕處，何日復追尋。"]'),
('e27a88a1-0674-40b5-8d06-1353af9b1112','聞東嘉王公得雜學士喜而成篇','喻良能','宋','宋诗','song-poetry','','[]','四海王夫子，精忠簡冕旒。',48,'全唐诗/poet.song.144000.json','["四海王夫子，精忠簡冕旒。", "詔綸飛渙渥，禁閣要名流。", "江左思安石，朝端欠武侯。", "命珪兼召節，蚤晚到南州。"]'),
('91c709ef-5725-4f58-be38-9694de43ad4a','由真隠至枕峰寺  其一','喻良能','宋','宋诗','song-poetry','','[]','南國清秋杪，長林翠靄重。',48,'全唐诗/poet.song.144000.json','["南國清秋杪，長林翠靄重。", "嬾黄千頃稻，深碧萬株榕。", "峽水風前急，方山雨後濃。", "征鞍何所憩，蕭寺枕孤峰。"]'),
('35eece88-2fd6-4bce-8f43-43acca8e6125','由真隠至枕峰寺  其二','喻良能','宋','宋诗','song-poetry','','[]','野外初凉冷，征衫亦未重。',48,'全唐诗/poet.song.144000.json','["野外初凉冷，征衫亦未重。", "檀欒溪上竹，勃窣道邊榕。", "秋意撩人切，嵐光潑眼濃。", "更尋天竺寺，却憶此高峰。"]'),
('fda614b2-9031-41cf-9c40-a8d84b6e8b78','題雪峰寺','喻良能','宋','宋诗','song-poetry','','[]','蘭若接閩天，登臨意豁然。',48,'全唐诗/poet.song.144000.json','["蘭若接閩天，登臨意豁然。", "樓臺秋色裏，鐘梵暮雲邊。", "未遂遊山興，聊爲借榻眠。", "白頭仍捧檄，奔走只堪憐。"]'),
('1cc19a3b-b74e-4ef4-9819-0f247ca687ae','八月十六夜月','喻良能','宋','宋诗','song-poetry','','[]','一更山吐月，萬里湛虛明。',48,'全唐诗/poet.song.144000.json','["一更山吐月，萬里湛虛明。", "聊當中秋色，堪欣此夜情。", "西風金盞側，香霧玉簪橫。", "却憶青蓮語，寒鴉棲復驚。"]'),
('465b19f3-cf74-42ca-8ce6-e287df3ed973','送廣漕曾郎中赴闕奏事','喻良能','宋','宋诗','song-poetry','','[]','綠鬢懷中詔，清秋向上都。',48,'全唐诗/poet.song.144000.json','["綠鬢懷中詔，清秋向上都。", "聖圖方廣大，賢路不崎嶇。", "會見除清切，寧須復轉輸。", "公如任風憲，抨劾莫踟躕。"]'),
('7542173d-8c89-4faa-92ef-869c6f16348c','侍太孺人由安國過賢沙至鳳池','喻良能','宋','宋诗','song-poetry','','[]','板輿多樂事，沙路及晴時。',48,'全唐诗/poet.song.144000.json','["板輿多樂事，沙路及晴時。", "約略瞻龍卧，逶迤到鳳池。", "匏樽細斟酌，華髮足遨嬉。", "此意安仁解，曛酣更賦詩。"]'),
('7d768270-2b55-4140-bfce-81cfac1b6db7','山陰','喻良能','宋','宋诗','song-poetry','','[]','綠髮經行處，重來兩鬢絲。',48,'全唐诗/poet.song.144000.json','["綠髮經行處，重來兩鬢絲。", "共誰論舊事，何處有新詩。", "鑑水春妍蚤，蘭亭雪意遲。", "邦人爭指似，壽母近期頤。"]'),
('0d8fa6bc-205e-47d9-aec0-aa90d9414be4','禹帝祠','喻良能','宋','宋诗','song-poetry','','[]','幾歲欽文命，今朝拜禹陵。',48,'全唐诗/poet.song.144000.json','["幾歲欽文命，今朝拜禹陵。", "稽山新雨霽，鑑水暮雲凝。", "更覩玄圭錫，懸知四載乘。", "川靈洎河伯，千古獲依憑。"]'),
('f3dd916c-d73a-42f7-90f1-393bafbfe8f2','有感二首  其一','喻良能','宋','宋诗','song-poetry','','[]','冉冉新華髮，颼颼敝黑裘。',48,'全唐诗/poet.song.144000.json','["冉冉新華髮，颼颼敝黑裘。", "一官方半剌，六十已平頭。", "稠疊耶溪泛，崎嶇禹穴游。", "未能江海去，聊作稻粱謀。"]'),
('ecbed4bb-51df-4724-9c97-2cd19c924355','有感二首  其二','喻良能','宋','宋诗','song-poetry','','[]','再有淮南亂，紛紛幾戰場。',48,'全唐诗/poet.song.144000.json','["再有淮南亂，紛紛幾戰場。", "血腥官道雨，骨映野田霜。", "行陣青黄氣，朝廷赤白囊。", "何時洗兵甲，四海重耕桑。"]'),
('361e0eea-6e23-47b6-b110-16a0b2dce3b5','次韻伯壽兄秋日偶題','喻良能','宋','宋诗','song-poetry','','[]','漸老良多感，悲秋强自寬。',48,'全唐诗/poet.song.144000.json','["漸老良多感，悲秋强自寬。", "鬢驚潘掾白，衣怯范生寒。", "逕合荒苔碧，窗明落葉丹。", "澆愁須暫醉，忍放酒杯乾。"]'),
('dacbd13b-cea4-4849-a1e5-f5571502ed0c','夜發曹娥堰','喻良能','宋','宋诗','song-poetry','','[]','孤燈乍明滅，隠約小橋邊。',48,'全唐诗/poet.song.144000.json','["孤燈乍明滅，隠約小橋邊。", "野市人家閉，晴天斗柄懸。", "秋深風落木，夜靜浪鳴船。", "却憶前年事，扁舟過霅川。"]'),
('a9c4011f-e888-4e9a-9e4e-4ca25a712068','書堂','喻良能','宋','宋诗','song-poetry','','[]','每憶書堂好，重來又十年。',48,'全唐诗/poet.song.144000.json','["每憶書堂好，重來又十年。", "征途聊復爾，風物故依然。", "松竹千巖暮，雲煙九月天。", "凭欄佳興發，欲進剡谿船。"]'),
('75bbed42-c733-497f-8691-571a995b695a','九日諸暨道中示興之','喻良能','宋','宋诗','song-poetry','','[]','客裏逢重九，蕭蕭落葉風。',48,'全唐诗/poet.song.144000.json','["客裏逢重九，蕭蕭落葉風。", "略無花對菊，但有鬢如蓬。", "蕉卷新收綠，楓旗半展紅。", "登臨語宗武，剩喜一樽同。"]'),
('605daf09-6abc-4418-abea-ea22f07033cb','道中口占  其一','喻良能','宋','宋诗','song-poetry','','[]','出郭及初旭，郊原豁寒晴。',48,'全唐诗/poet.song.144000.json','["出郭及初旭，郊原豁寒晴。", "雲凈空既碧，霜明湖更清。", "蕭蕭衆木下，杳杳孤鴻鳴。", "安得陶謝手，作詩替丹青。"]'),
('9dda4ada-cfca-44d0-8c19-01a2c85bdca0','道中口占  其二','喻良能','宋','宋诗','song-poetry','','[]','空山古寺裏，齋宿值冬晴。',48,'全唐诗/poet.song.144000.json','["空山古寺裏，齋宿值冬晴。", "塵囂一何寂，心境兩俱清。", "砌月曉霜色，松風夜籟鳴。", "語闌人未寢，孤館伴燈青。"]'),
('8d5ccb9d-c45b-45ac-9e94-4f27006b99f3','題隠靜寺','喻良能','宋','宋诗','song-poetry','','[]','杯渡已仙去，茲山餘勝蹤。',48,'全唐诗/poet.song.144000.json','["杯渡已仙去，茲山餘勝蹤。", "傍雲開廣殿，夾道蔭長松。", "幽洞秋含霧，清溪冷浸峰。", "老僧如宿昔，一笑喜相逢。"]'),
('0218c659-d6b2-49e8-b9c1-e2c1aa4a61c9','訪何茂恭於南湖何有詩因次韻','喻良能','宋','宋诗','song-poetry','','[]','相別三年久，相逢一笑時。',48,'全唐诗/poet.song.144000.json','["相別三年久，相逢一笑時。", "眼邊無俗物，袖裏有清詩。", "山路梅花早，湖天雪意遲。", "不眠成夜話，寒月在疎枝。"]'),
('e2bf7fc5-da76-4ddc-835b-c0d62247096c','即事','喻良能','宋','宋诗','song-poetry','','[]','亦好經年別，歸來意轉親。',48,'全唐诗/poet.song.144000.json','["亦好經年別，歸來意轉親。", "橫斜花練練，清淺水鱗鱗。", "又逼瓜時戍，聊娛戲綵身。", "新添蘭桂圃，近在岸西滣。"]'),
('41fcd65d-cf5e-47ef-8360-1710f55ec053','紫笑','喻良能','宋','宋诗','song-poetry','','[]','表裏俱穠紫，冬春獨擅青。',48,'全唐诗/poet.song.144000.json','["表裏俱穠紫，冬春獨擅青。", "每蒙天一笑，不與素同馨。", "風味撩吟筆，芳非入畫屏。", "幾番饒睡思，聞此灑然醒。"]'),
('0460611b-a33b-45f9-bd99-9925a5e671af','雨餘','喻良能','宋','宋诗','song-poetry','','[]','雨餘平野綠，耕種滿東臯。',48,'全唐诗/poet.song.144000.json','["雨餘平野綠，耕種滿東臯。", "處處鞭黄犢，家家賣孟勞。", "筠盤餽糠籺，瓦盌薦溪毛。", "所願甘霖足，梁間掛桔槔。"]'),
('2d6c71cc-c67a-4104-9ffc-5319a045ebdd','謝趙昌父投贈詩卷','喻良能','宋','宋诗','song-poetry','','[]','趙子有新作，鼎珍初出庖。',48,'全唐诗/poet.song.144000.json','["趙子有新作，鼎珍初出庖。", "端能工競病，寧復費推敲。", "白戰應難敵，清臞亦任嘲。", "風流前輩盡，試合續絃膠。"]'),
('1bb0f06f-1a60-4c7e-928c-7f637f59e582','三月六日湖上分韻得山字','喻良能','宋','宋诗','song-poetry','','[]','剩漲三篙水，寬圍十里山。',48,'全唐诗/poet.song.144000.json','["剩漲三篙水，寬圍十里山。", "垂楊飛舞裏，細雨有無間。", "把酒從杯溢，題詩任鬢斑。", "青春仍暇日，莫惜晚西還。"]'),
('c1a594c5-2edd-4c2a-ac5c-9b6a9ee64e13','三月二十六日工部宿直','喻良能','宋','宋诗','song-poetry','','[]','邃宇近霄漢，微風摇竹梢。',48,'全唐诗/poet.song.144000.json','["邃宇近霄漢，微風摇竹梢。", "漏聲通五夜，鐘韻自三茅。", "衣裌偏宜睡，杯單詎用庖。", "夙興那敢後，雞唱已嘐嘐。"]'),
('07e5c1d6-cda4-4e91-8701-6cd518480d5c','題秀野堂','喻良能','宋','宋诗','song-poetry','','[]','秀野臨空闊，三堂若是班。',48,'全唐诗/poet.song.144000.json','["秀野臨空闊，三堂若是班。", "荷香平入座，湖影倒涵山。", "魚鳥丹青裏，雲煙水墨間。", "他年儻同社，應共狎鷗閒。"]'),
('eb14b26b-b21e-4577-a594-c7f95e1bbcc5','奉酬鮑仲山機宜見贈','喻良能','宋','宋诗','song-poetry','','[]','四海今詩伯，才名許孰儔。',48,'全唐诗/poet.song.144000.json','["四海今詩伯，才名許孰儔。", "波瀾掩顔謝，步驟到曹劉。", "婉畫參機幕，精忠動冕旒。", "時危須戮力，談笑復神州。"]'),
('79c35a50-7a48-460b-a202-e5dcce4b8902','次韻陳魯望郎中','喻良能','宋','宋诗','song-poetry','','[]','筆底詞華盛，寧論大小山。',48,'全唐诗/poet.song.144000.json','["筆底詞華盛，寧論大小山。", "敷腴建安際，古澹貞元間。", "未許窺三昧，時容見一斑。", "草堂詩律在，風味喚仍還。"]'),
('c8a73551-c9bf-4ef6-bc57-80dfc75c1bf0','溫泉','喻良能','宋','宋诗','song-poetry','','[]','招提閟林麓，棟宇壓江郊。',48,'全唐诗/poet.song.144000.json','["招提閟林麓，棟宇壓江郊。", "來作溫泉浴，如逢癢處搔。", "綵衣臨砌檻，華髮對尊匏。", "一笑涼風起，紅欹荔子梢。"]'),
('6be21ab8-f43a-4978-9a95-bcbb53a7c424','曹務拘綴不及赴張持荷賞梅之約因得小詩寄似','喻良能','宋','宋诗','song-poetry','','[]','渺渺煙波闊，南湖在帝城。',48,'全唐诗/poet.song.144000.json','["渺渺煙波闊，南湖在帝城。", "梅將春共早，人與境俱清。", "筆墨探三昧，樽罍有四并。", "未能乘興去，遥望目增明。"]'),
('9402b9b3-b5a9-4655-9766-5d036e394028','題郭邵州同塵庵','喻良能','宋','宋诗','song-poetry','','[]','榮辱酣歌裏，賢愚睡眼中。',48,'全唐诗/poet.song.144000.json','["榮辱酣歌裏，賢愚睡眼中。", "未應分野馬，那復障西風。", "晏坐從凝席，揚鞭任軟紅。", "巖棲兼鼎食，處處不妨同。"]'),
('cca1310e-7d9e-433a-abdf-c8766d277c1e','臘八日雪參議林郎中有詩因次韻','喻良能','宋','宋诗','song-poetry','','[]','玉樹參差見，銀花子細看。',48,'全唐诗/poet.song.144000.json','["玉樹參差見，銀花子細看。", "淖糜分臘序，圓炭度朝寒。", "冉冉頭新白，匆匆歲又殘。", "聊憑一杯醉，忍把兩眉攢。"]'),
('d3e01af8-639c-4bc1-ba30-353617cfa634','次韻李大著春日雜詩十首  其一','喻良能','宋','宋诗','song-poetry','','[]','春晚饒芳景，官閒得細看。',48,'全唐诗/poet.song.144000.json','["春晚饒芳景，官閒得細看。", "隔窗黄鳥並，開卷壁魚乾。", "過雨蒼苔濕，迎風翠竹寒。", "髮華搔更短，斗酒自相寬。"]'),
('cbbb2d17-b3f1-4eec-b802-045f01228a20','次韻李大著春日雜詩十首  其二','喻良能','宋','宋诗','song-poetry','','[]','漫仕歎遲暮，卜居城北偏。',48,'全唐诗/poet.song.144000.json','["漫仕歎遲暮，卜居城北偏。", "已教山白石，祇欠沼清泉。", "簾透一簷月，窗橫數尺天。", "雜花還映竹，故故自芳妍。"]'),
('75208f33-c0ee-4323-b6f7-abf93cdfbb1a','次韻李大著春日雜詩十首  其三','喻良能','宋','宋诗','song-poetry','','[]','賤子知何幸，萊衣老更斑。',48,'全唐诗/poet.song.144000.json','["賤子知何幸，萊衣老更斑。", "白頭居杜曲，清夢到香山。", "琢句愁雕腎，銜盃喜渥顔。", "此身慚暮翼，飛倦未知還。"]'),
('373ee896-d835-490d-93c6-a53271bd87e1','次韻李大著春日雜詩十首  其四','喻良能','宋','宋诗','song-poetry','','[]','偏親須寸祿，匠院敢辭留。',48,'全唐诗/poet.song.144000.json','["偏親須寸祿，匠院敢辭留。", "頗媿花經眼，還應草喚愁。", "身唯親布被，交已絕牙籌。", "詩興抽毫足，無勞入海求。"]'),
('8eeb36fc-2664-4028-9077-25c09c81a961','次韻李大著春日雜詩十首  其五','喻良能','宋','宋诗','song-poetry','','[]','花日淺明牖，竹風低度牆。',48,'全唐诗/poet.song.144000.json','["花日淺明牖，竹風低度牆。", "舉頭空弱絮，轉盼墮危芳。", "興遣憑毛穎，愁消頼羽觴。", "陰陰繁夏木，故里耿難忘。"]'),
('ed27bf7d-051c-414d-be0d-685476378370','次韻李大著春日雜詩十首  其六','喻良能','宋','宋诗','song-poetry','','[]','借居仍種菊，往往似天隨。',48,'全唐诗/poet.song.144000.json','["借居仍種菊，往往似天隨。", "日味三春酒，燈明午夜棋。", "閒臨永和帖，細誦建安詩。", "潦倒同中散，歡欣似啟期。"]'),
('f090c395-04b5-46b1-a58a-0c3bd886b4c3','次韻李大著春日雜詩十首  其七','喻良能','宋','宋诗','song-poetry','','[]','帝里春仍好，風和晝漏遲。',48,'全唐诗/poet.song.144000.json','["帝里春仍好，風和晝漏遲。", "但懷三釜樂，遑恤北山移。", "老大諳斑戲，空疎媿色絲。", "平生杜陵老，耿耿寸心知。"]'),
('b5e73867-68e9-4afb-a2c1-2782c644ad81','次韻李大著春日雜詩十首  其八','喻良能','宋','宋诗','song-poetry','','[]','屯雲初解駁，曉日有晶輝。',48,'全唐诗/poet.song.144000.json','["屯雲初解駁，曉日有晶輝。", "城郭紅塵軟，江湖春水肥。", "小舟浮綠凈，芳徑步熹微。", "起我故山思，多慚未拂衣。"]'),
('009ac710-1bfd-4f62-b87e-fad67bb432f9','次韻李大著春日雜詩十首  其九','喻良能','宋','宋诗','song-poetry','','[]','素髮已垂領，故園猶未歸。',48,'全唐诗/poet.song.144000.json','["素髮已垂領，故園猶未歸。", "鳥聲思磴道，柳色憶荆扉。", "嫩綠枝邊暗，殘紅葉底稀。", "幾多新乳燕，一一出巢飛。"]'),
('0c9cf018-de5d-4c9b-a41f-2b15b7afe762','次韻李大著春日雜詩十首  其一○','喻良能','宋','宋诗','song-poetry','','[]','二載違枌社，全家客帝都。',48,'全唐诗/poet.song.144000.json','["二載違枌社，全家客帝都。", "濁醪充上頓，清俸付中厨。", "親老唯須養，皇恩詎敢孤。", "逍遥處山澤，未忍學仙臞。"]'),
('788f519c-a18a-4da6-800e-5bf76845edf1','次韻王龜齡春日湖上','喻良能','宋','宋诗','song-poetry','','[]','春老花茵積，雲開天鏡磨。',48,'全唐诗/poet.song.144000.json','["春老花茵積，雲開天鏡磨。", "暖風今日好，細雨向來多。", "柳蔭青絲障，湖明金叵羅。", "何時成醉倒，煙草藉晴坡。"]'),
('1b990440-11ac-4086-95c0-98515aea1ab0','羅春伯以呂居仁集寄似作詩爲謝','喻良能','宋','宋诗','song-poetry','','[]','平生子呂子，妙語總關心。',48,'全唐诗/poet.song.144000.json','["平生子呂子，妙語總關心。", "忽得詩三百，端勝書萬金。", "愔愔醒睡眼，炯炯凈煩襟。", "何以報嘉惠，空慚綠綺琴。"]'),
('3716be6f-01d4-429f-8a90-f5e6a0ead0cd','六月二十二日夜省宿一首','喻良能','宋','宋诗','song-poetry','','[]','省廬頻宿直，何異在承明。',48,'全唐诗/poet.song.144000.json','["省廬頻宿直，何異在承明。", "地峻江聲近，風輕荷氣清。", "鬢毛真騎省，詩思小陰鏗。", "記得山村日，馳情向玉京。"]'),
('825ad7e2-d16d-40b5-99fd-13d8691ce96e','印印詩','喻良能','宋','宋诗','song-poetry','','[]','印印秀而好，明眸冰雪膚。',48,'全唐诗/poet.song.144000.json','["印印秀而好，明眸冰雪膚。", "逢人賞岐嶷，問字識之無。", "若有萬金藥，真成千里駒。", "空花今已矣，晬日一長吁。"]'),
('1f97b02e-b574-4e35-a305-30060d913fbb','十一月二日與陸明府陳廣文黄使君吳都曹江廣文同飲於閎中堂修年契也酒後耳熱因得小詩呈似','喻良能','宋','宋诗','song-poetry','','[]','菊色猶黄處，梅花未發天。',48,'全唐诗/poet.song.144000.json','["菊色猶黄處，梅花未發天。", "三山千里客，一笑六同年。", "公等多朱紱，予方乏坐氊。", "清談仍痛飲，應作畫圖傳。"]'),
('9d80d61a-7a05-49cd-93f0-6478c90d0a02','同德坊寓居','喻良能','宋','宋诗','song-poetry','','[]','天地方摇落，江湖入夢思。',48,'全唐诗/poet.song.144000.json','["天地方摇落，江湖入夢思。", "三爲京輦客，十見歲華移。", "亹亹金閨直，蕭蕭素髮垂。", "殘年飽喫飯，細誦少陵詩。"]'),
('b96d9fd0-4c9d-4da0-ba5a-54f711f9d39c','檢書偶見故王侍郎嘉叟舊與余倡和之什良用慨然因題四韻','喻良能','宋','宋诗','song-poetry','','[]','文字名三世，精神運五兵。',48,'全唐诗/poet.song.144000.json','["文字名三世，精神運五兵。", "徒看遺墨在，却嘆曲池平。", "浙右頻犀麈，江東幾兕觥。", "倡酬今已矣，撫卷泪縱橫。"]'),
('739779f0-ade6-4320-b56c-2dd481d11c1d','挽高宗皇帝詞  其一','喻良能','宋','宋诗','song-poetry','','[]','扈從浮江日，憂勤立極初。',48,'全唐诗/poet.song.144000.json','["扈從浮江日，憂勤立極初。", "八年躬甲胄，萬國混車書。", "治定端無競，功成自不居。", "休明媲虞舜，逸樂夢華胥。"]'),
('f60c3eb0-7960-46fa-b722-aa05a08e21dc','挽高宗皇帝詞  其二','喻良能','宋','宋诗','song-poetry','','[]','天地重開闢，民人拱德馨。',48,'全唐诗/poet.song.144000.json','["天地重開闢，民人拱德馨。", "奎文贊元聖，宸翰列羣經。", "禮樂盈三紀，光華亞九齡。", "龍髯攀莫及，臣子涕交零。"]'),
('182f469b-b17d-42f4-a33d-1492750fa400','入局言懷','喻良能','宋','宋诗','song-poetry','','[]','學省清秋好，無塵意趣長。',48,'全唐诗/poet.song.144000.json','["學省清秋好，無塵意趣長。", "講餘簾影靜，坐久綵衣涼。", "未有裨王族，真成耗太倉。", "顧慚麋鹿質，亦許玷朝行。"]'),
('ee2c2bf6-1249-4338-a7ba-f2acd784bd77','寄宋子淵運使','喻良能','宋','宋诗','song-poetry','','[]','對閣思槐市，成規媿奉常。',48,'全唐诗/poet.song.144000.json','["對閣思槐市，成規媿奉常。", "六年談笑阻，千里夢魂長。", "將漕衣仍繡，空餐鬢已蒼。", "何當奉犀麈，風月要平章。"]'),
('aac7e0ba-f4c0-4b9d-9c31-aa86a65583bd','判院蔡丈和予五詩次韻一篇奉酬','喻良能','宋','宋诗','song-poetry','','[]','病起驚華髮，官閒覺素餐。',48,'全唐诗/poet.song.144000.json','["病起驚華髮，官閒覺素餐。", "文章慚李益，名譽羨蘇端。", "老去觀書嬾，愁來避酒難。", "非關作詩苦，自爾带圍寬。"]'),
('2f635090-d3ba-4c3d-b126-a6fb881bbf26','黄講書太器見和五詩次韻一篇奉酬','喻良能','宋','宋诗','song-poetry','','[]','客氊寒莫致，官舍總蕭然。',48,'全唐诗/poet.song.144000.json','["客氊寒莫致，官舍總蕭然。", "睡思茶甘外，窮愁酒力邊。", "未成投轄飲，時作撥書眠。", "野鶴如雙鬢，衰遲祇自憐。"]'),
('8d6e7339-1e38-44c8-bbd1-5c4fc63fdd50','獻之大著得予喜賦以詩來謝次韻奉酬','喻良能','宋','宋诗','song-poetry','','[]','奪袍吟處筆，墊角雨餘巾。',48,'全唐诗/poet.song.144000.json','["奪袍吟處筆，墊角雨餘巾。", "黄絹才無敵，青藜杖有神。", "將乘桓典馬，肯受庾公塵。", "老我知何幸，窮塗獲卜鄰。"]'),
('efc6c587-e5ae-4740-ba58-46300c19a1a7','茂林見訪有詩次韻奉酬','喻良能','宋','宋诗','song-poetry','','[]','解鞍揮玉麈，亹亹笑談清。',48,'全唐诗/poet.song.144000.json','["解鞍揮玉麈，亹亹笑談清。", "昨夜燈花喜，今朝乾鵲聲。", "興同狂祕監，詩似老彌明。", "憶昔南臺北，相逢盖始傾。"]'),
('0bf149e4-ef60-4792-9a22-c042c75b7dca','陳彥山寄示新詩次韻奉酬','喻良能','宋','宋诗','song-poetry','','[]','山園寧厭小，閒地只如馨。',48,'全唐诗/poet.song.144000.json','["山園寧厭小，閒地只如馨。", "木落長天碧，雲飛遠岫青。", "故人應見憶，新詠許時聽。", "句好何勞琢，雖搜不用冥。"]'),
('b4441b70-daac-4664-91ee-b9c35581cb85','題周希稷清閟軒','喻良能','宋','宋诗','song-poetry','','[]','之子藴琅玕，幽軒足考槃。',48,'全唐诗/poet.song.144000.json','["之子藴琅玕，幽軒足考槃。", "蘢葱煙翠濕，瑣碎日光寒。", "似向蘭亭見，全勝墨本看。", "是中雖信美，未可懶彈冠。"]'),
('ee5c0c29-fe72-4b79-afe7-16e5dafb9bae','喜雪','喻良能','宋','宋诗','song-poetry','','[]','同雲生舊臘，積雪入新春。',48,'全唐诗/poet.song.144000.json','["同雲生舊臘，積雪入新春。", "野色連滄海，驩聲動紫宸。", "峰巒朝掩映，樓閣夜精神。", "莫展山陰畫，雖工不是真。"]'),
('d0dfa7d4-194c-4507-ac1e-6d4b0fbb11d8','贈陳宣幹','喻良能','宋','宋诗','song-poetry','','[]','嗜古心仍切，尋詩句益工。',48,'全唐诗/poet.song.144000.json','["嗜古心仍切，尋詩句益工。", "十年江左別，一笑日邊同。", "補外吾天幸，懷歸子道東。", "好爲旬朔款，解榻待春風。"]'),
('c2793bc8-ce7c-47db-9a5b-270a4db1e475','侍親由三山還東陽','喻良能','宋','宋诗','song-poetry','','[]','南雪不到地，玄冬偏滿山。',48,'全唐诗/poet.song.144000.json','["南雪不到地，玄冬偏滿山。", "春風仍料峭，綵袂正斕斑。", "廣厦千間靜，虛空一宿閒。", "此身如羽翼，飛倦始知還。"]'),
('ba8ba7e7-8cce-426c-9f52-0f9effaaf329','文舉仙尉以詩寄似兼惠新安紙乳洞茶次韻奉酬','喻良能','宋','宋诗','song-poetry','','[]','閉戶鶑聲老，開緘鯉素新。',48,'全唐诗/poet.song.144000.json','["閉戶鶑聲老，開緘鯉素新。", "多慚青眼舊，遠寄白頭人。", "佳楮冰天繭，芳荿雪洞春。", "著書兼破睡，勒謝敢辭頻。"]'),
('6d373f03-c611-4fb3-a259-f91f47284447','題雲黄山寶林寺','喻良能','宋','宋诗','song-poetry','','[]','彌勒下生地，溪山秀且長。',48,'全唐诗/poet.song.144000.json','["彌勒下生地，溪山秀且長。", "蕭蕭雙樹碧，冉冉片雲黄。", "曉日觚棱凈，西風松桂香。", "十年疎杖屨，玉石耿難忘。"]'),
('023bf374-36a9-4251-9aa6-e11c99d2dff6','錦園  其一','喻良能','宋','宋诗','song-poetry','','[]','孟夏錦園好，山花高下開。',48,'全唐诗/poet.song.144000.json','["孟夏錦園好，山花高下開。", "風欹紅芍藥，雨重紫徘徊。", "衣染香邊蘂，鞵粘綠處苔。", "鶑歌兼蝶拍，時送掌中杯。"]'),
('8e1fc9b4-9b1f-46b2-838e-c7ee3355f1bd','錦園  其二','喻良能','宋','宋诗','song-poetry','','[]','山園多勝踐，繚繞磬湖濱。',48,'全唐诗/poet.song.144000.json','["山園多勝踐，繚繞磬湖濱。", "畦藥青生甲，湖波綠動鱗。", "鵓鴣知欲雨，鴉舅報將晨。", "却憶京華日，長懷浩蕩春。"]'),
('ed499a8c-c0b8-432b-a4ac-0dca7c373ce1','題何茂宏茂恭林堂','喻良能','宋','宋诗','song-poetry','','[]','華堂閟林樾，林秀水泉甘。',48,'全唐诗/poet.song.144000.json','["華堂閟林樾，林秀水泉甘。", "野色袁家渴，秋聲鈷鉧潭。", "二難今有此，四者許誰參。", "他日承明直，懸知憶翠嵐。"]'),
('e273c4ef-efda-44fa-834e-d0c1a453f745','月桂堂','喻良能','宋','宋诗','song-poetry','','[]','月桂堂何有，池清桂影橫。',48,'全唐诗/poet.song.144000.json','["月桂堂何有，池清桂影橫。", "畫圖寧辦此，玉斧巧修成。", "入夜境逾妙，纔秋風又生。", "饒陽巖石下，隠約欠分明。"]'),
('4b9b2853-13b1-4e82-bd3d-d6578f0b4687','廿五兄宣義見招偕諸弟赴新亭宴集即席有作','喻良能','宋','宋诗','song-poetry','','[]','瀟灑新亭好，松長桂亦稠。',48,'全唐诗/poet.song.144000.json','["瀟灑新亭好，松長桂亦稠。", "清秋集鴻鴈，暇日勸觥籌。", "既遠含香直，何辭秉燭遊。", "主人情義重，終宴不知休。"]'),
('65331ad9-afeb-4b8c-ac07-6cce692246e3','錦園雙桂植之二十八年未嘗著花今忽盛開紫趺黄蘂所未曾見喜而賦詩','喻良能','宋','宋诗','song-poetry','','[]','疇昔栽雙桂，于今四七秋。',48,'全唐诗/poet.song.144000.json','["疇昔栽雙桂，于今四七秋。", "紫趺香冉冉，金蘂色浮浮。", "標致殊他桂，風流最蓐收。", "無才强摹寫，著語故難遒。"]'),
('3e548879-4066-438a-97e2-bc07a93d54c4','八月十三夜仲季二弟弄月亭對飲','喻良能','宋','宋诗','song-poetry','','[]','今宵端正月，故故向湖山。',48,'全唐诗/poet.song.144000.json','["今宵端正月，故故向湖山。", "玉兔窺杯凸，冰娥怪鬢斑。", "詩情甪里逸，酒膽夏黄慳。", "興罷度橋處，天風松桂間。"]'),
('96da2f8c-752b-4d0b-826d-7ebe7b9dc328','次韻程觀過夜飲靈濟祠下','喻良能','宋','宋诗','song-poetry','','[]','松月瀉清影，爐煙凝宿雲。',48,'全唐诗/poet.song.144000.json','["松月瀉清影，爐煙凝宿雲。", "檠燈寒照席，樽酒細論文。", "清漏轉三鼓，芳杯釂十分。", "紛勝銀燭裏，妙舞看榴裙。"]'),
('086ddeac-6890-4bf8-abb6-5ffc906f6fb9','送朱師古少卿歸蜀','喻良能','宋','宋诗','song-poetry','','[]','西蜀多賢士，于今見奉常。',48,'全唐诗/poet.song.144000.json','["西蜀多賢士，于今見奉常。", "十年方出守，萬里好還鄉。", "峽水冬無險，河圖晚有光。", "臨歧分手處，政爾不能忘。"]'),
('d521782f-e01f-4e86-b632-b383919f3c0e','丞相王公挽詞  其一','喻良能','宋','宋诗','song-poetry','','[]','炎統中興日，淳熙翊贊功。',48,'全唐诗/poet.song.144000.json','["炎統中興日，淳熙翊贊功。", "憲邦同吉甫，待旦類周公。", "一品恩榮重，三朝禮貌隆。", "欲知勳業盛，請眎鼎彝中。"]'),
('4d299e9c-71b1-4137-b8d1-da7700b67d77','丞相王公挽詞  其二','喻良能','宋','宋诗','song-poetry','','[]','維嶽鍾英粹，興王有俊良。',48,'全唐诗/poet.song.144000.json','["維嶽鍾英粹，興王有俊良。", "文章周衛武，書考郭汾陽。", "調燮民庸茂，彌縫主道昌。", "中台一宵坼，四海淚滂滂。"]'),
('184ba523-bdf9-4be8-a5ff-25e1426a2f11','丞相王公挽詞  其三','喻良能','宋','宋诗','song-poetry','','[]','疇昔翹材館，疎庸獲屢游。',48,'全唐诗/poet.song.144000.json','["疇昔翹材館，疎庸獲屢游。", "衮衣無傲色，吐握有勤求。", "輔弼十年久，雍容片善收。", "至今天下士，語及淚交流。"]'),
('9ef97899-f33b-43d2-a0e2-163498b97a1b','丞相大資葉公挽詞  其一','喻良能','宋','宋诗','song-poetry','','[]','雙谿鍾地讖，一相破天荒。',48,'全唐诗/poet.song.144000.json','["雙谿鍾地讖，一相破天荒。", "道至黄扉重，勳由紫府昌。", "堤成歡百辟，台坼泣羣方。", "盛烈銘鐘鼎，千秋耿不忘。"]'),
('c18a8fd1-6004-4417-a1d7-7750a5790d34','丞相大資葉公挽詞  其二','喻良能','宋','宋诗','song-poetry','','[]','德望堂堂重，威名凜凜寒。',48,'全唐诗/poet.song.144000.json','["德望堂堂重，威名凜凜寒。", "三年衮衣粲，四海寸心丹。", "綠野悲裴度，蒼生憶謝安。", "白頭賓客在，慚痛淚闌干。"]'),
('644b1eb4-cd48-41e6-af74-402505013719','挽商元鼎','喻良能','宋','宋诗','song-poetry','','[]','舉世方貪祿，斯人祇自怡。',48,'全唐诗/poet.song.144000.json','["舉世方貪祿，斯人祇自怡。", "一官如涕唾，半世足遨嬉。", "心地陂千頃，生涯酒一巵。", "唯應郭有道，吾不媿爲碑。"]'),
('b0895154-1fd8-44af-b16c-175d2bbfd4c5','挽黄泰之','喻良能','宋','宋诗','song-poetry','','[]','漢世無雙價，皇朝第一流。',48,'全唐诗/poet.song.144000.json','["漢世無雙價，皇朝第一流。", "文章驚北闕，名譽滿中州。", "槐市師模邃，蘭臺史筆遒。", "所嗟時未合，不作濟川舟。"]'),
('8bd04f23-3c15-4097-865c-9fc1c65d8c62','挽樓士特','喻良能','宋','宋诗','song-poetry','','[]','平生易諸子，向我獨拳拳。',48,'全唐诗/poet.song.144000.json','["平生易諸子，向我獨拳拳。", "雪屋傾銀斝，春風並錦韉。", "笑談多竟夕，契闊未經年。", "來作生芻奠，凄凉涕泫然。"]'),
('313ee550-08e2-4284-b3e8-db3cebf47423','挽唐立夫舍人','喻良能','宋','宋诗','song-poetry','','[]','才名振西蜀，老氣益中州。',48,'全唐诗/poet.song.144000.json','["才名振西蜀，老氣益中州。", "草制追盤誥，籌邊動冕旒。", "已令榮壓角，復遣飲遨頭。", "千古九江恨，長隨逝水流。"]'),
('e67cdd2b-b948-48b5-beb2-816457b3234c','挽石似之郎中','喻良能','宋','宋诗','song-poetry','','[]','幾作儒林冠，親承帝渥隆。',48,'全唐诗/poet.song.144000.json','["幾作儒林冠，親承帝渥隆。", "雙旌大江左，一節古吳中。", "列宿英聲在，浮雲舊事空。", "無從挂吾劍，老淚濕西風。"]'),
('b4e8b7f8-6d51-45b3-82c7-0aa27f106fd8','挽國史侍讀李公仁父','喻良能','宋','宋诗','song-poetry','','[]','大名垂宇宙，秀氣發岷峨。',48,'全唐诗/poet.song.144000.json','["大名垂宇宙，秀氣發岷峨。", "學比淵雲贍，才方賈馬過。", "九朝資直筆，二子振賢科。", "已矣流芳在，千秋保不磨。"]'),
('a3091d1c-6276-44ff-8559-b94bcabd9380','挽處士陳容  其一','喻良能','宋','宋诗','song-poetry','','[]','乾坤身老大，邱壑跡委蛇。',48,'全唐诗/poet.song.144000.json','["乾坤身老大，邱壑跡委蛇。", "不枉安車召，誰爲薦鶚詞。", "平生五千卷，身後寧馨兒。", "他日編遺藁，應多感遇詩。"]'),
('9d8c10e5-0980-42f1-9ddc-e941f5dea55e','挽處士陳容  其二','喻良能','宋','宋诗','song-poetry','','[]','歷數鄉閭老，誰知德齒尊。',48,'全唐诗/poet.song.144000.json','["歷數鄉閭老，誰知德齒尊。", "無心游魏闕，有意樂丘園。", "漫不霑三釜，真堪映九原。", "涕洟歌楚些，已矣莫招魂。"]'),
('cb4ebb41-1a04-4330-baa8-7d2407fbeeeb','挽李靖少傅夫人  其一','喻良能','宋','宋诗','song-poetry','','[]','九月秋光急，山川苦霧迷。',48,'全唐诗/poet.song.144000.json','["九月秋光急，山川苦霧迷。", "卜邙新隧啟，度鞏短簫齊。", "寶劍知終合，靈蟾已隕西。", "松門來會葬，車馬幾千蹄。"]'),
('851e5041-53f5-4326-ab9e-9e79592ea066','挽李靖少傅夫人  其二','喻良能','宋','宋诗','song-poetry','','[]','板輿曾至鄭，靈輤此歸周。',48,'全唐诗/poet.song.144000.json','["板輿曾至鄭，靈輤此歸周。", "靄靄雲將夕，亭亭月正秋。", "九原開祔穴，故土覆新丘。", "歲晏寒松下，茅苫孝子留。"]'),
('21503e41-e963-4875-8d4a-920918b37b71','挽湯丞相漢國夫人','喻良能','宋','宋诗','song-poetry','','[]','七秩芳名盛，于今等逝波。',48,'全唐诗/poet.song.144000.json','["七秩芳名盛，于今等逝波。", "承天登宰輔，看子掌編摩。", "鳳去青春獨，鸞回紫誥多。", "他年彤管史，兼述采蘩歌。"]'),
('0caa690d-8cad-4a17-8a8f-60ecd845118b','春水','喻良能','宋','宋诗','song-poetry','','[]','磬湖春水夜來生，曉起雷聲逗雨聲。',64,'全唐诗/poet.song.144000.json','["磬湖春水夜來生，曉起雷聲逗雨聲。", "去馬來牛心莫辨，鸕鷀鸂鶒眼俱明。", "飄零花片有底急，摇曳柳絲如許輕。", "旬月烟村半風雨，榆錢好爲買春晴。"]'),
('89e41502-65f3-4a23-9b9f-c3b01cc2c31f','次韻送季直弟入越','喻良能','宋','宋诗','song-poetry','','[]','積雨新晴耳目醒，長堦柳色靜閒庭。',64,'全唐诗/poet.song.144000.json','["積雨新晴耳目醒，長堦柳色靜閒庭。", "已看桃萼臙脂濕，未有楊花雪片零。", "客路汝應懷稚子，家居吾亦念樵青。", "須知兩地無百里，不用陽關腸斷聽。"]'),
('1bce6654-cc1d-4636-8d0f-5fd7bf6632fa','一室','喻良能','宋','宋诗','song-poetry','','[]','陰陽一室冷兢兢，燕坐何曾病鬰蒸。',64,'全唐诗/poet.song.144000.json','["陰陽一室冷兢兢，燕坐何曾病鬰蒸。", "只擬綸巾持羽扇，未須赤脚踏層冰。", "滿盤碧玉初投箸，一榻清風更曲肱。", "掃地焚香凉到骨，疎簾何處欲揮蠅。"]'),
('9eca8640-d11a-4985-bbac-c1df5b99ac91','記夢','喻良能','宋','宋诗','song-poetry','','[]','小窗幽閣睡初勻，夢到鈞天侍紫宸。',64,'全唐诗/poet.song.144000.json','["小窗幽閣睡初勻，夢到鈞天侍紫宸。", "盤號搯桃真異器，果名黄棗豈常珍。", "殊恩併浹鴒原弟，美味初嘗鶴髮親。", "願竭精忠圖報稱，覺來肝膽已輪囷。"]'),
('885168e9-68e4-40e6-8fb3-2261f94b2efd','次韻伯壽兄宿華藏有感','喻良能','宋','宋诗','song-poetry','','[]','水凈溪空峰更青，目雖未到已先明。',64,'全唐诗/poet.song.144000.json','["水凈溪空峰更青，目雖未到已先明。", "棟浮萬縷晴雲細，軒擁千重夏木清。", "幽興入門應自適，殘樽下馬與誰傾。", "老僧齋罷唯須睡，不信人間有月評。"]'),
('216aa775-551b-4d88-bfc7-339117aa6635','曉霽','喻良能','宋','宋诗','song-poetry','','[]','夜來細雨暗冥冥，曉起秋容入畫屏。',64,'全唐诗/poet.song.144000.json','["夜來細雨暗冥冥，曉起秋容入畫屏。", "水色凈涵天影碧，林梢微露遠峰青。", "嫩黄稼卧衡從畝，老翠柳拖長短亭。", "一晌西風醒睡眼，端如痛飲讀騷經。"]'),
('63ebef1a-aeca-4173-9657-5fde6f00d871','題繡川驛揖秀亭次張明府韻','喻良能','宋','宋诗','song-poetry','','[]','一色蒼波百頃煙，直楣橫檻覆華椽。',64,'全唐诗/poet.song.144000.json','["一色蒼波百頃煙，直楣橫檻覆華椽。", "從來好景無今日，何限清詩似昔賢。", "把醆有山來酒面，凭欄無路到愁邊。", "我來政值雨新足，芳草芊芊綠滿川。"]'),
('f422eb73-dfc9-4e9a-97ee-fd503d4f6f7d','次韻趙禹平春日書懷','喻良能','宋','宋诗','song-poetry','','[]','草色青青二月時，物華雖是我廬非。',64,'全唐诗/poet.song.144000.json','["草色青青二月時，物華雖是我廬非。", "日明院宇燕相語，花發園林鶑亂飛。", "無數小桃初掩映，幾多垂柳自因依。", "春風十里歸吟筆，未用羅幃繡幕圍。"]'),
('15f8d112-1339-44bc-8109-f8d1dc206ef7','八月十四日亦好亭遲月不至分韻得秋字','喻良能','宋','宋诗','song-poetry','','[]','亦好登臨似庾樓，是中風月最宜秋。',64,'全唐诗/poet.song.144000.json','["亦好登臨似庾樓，是中風月最宜秋。", "素娥欲赴經年約，行雨潛分一段愁。", "聊復飛觴追勝賞，何妨秉燭事清游。", "明年此夕看明月，千里相思楚水頭。"]'),
('c5188f63-633c-43ae-8466-8ee59ccfa6fa','次韻衛知機秀才梅花','喻良能','宋','宋诗','song-poetry','','[]','東君調護亦多情，瘦比夷齊徹骨清。',64,'全唐诗/poet.song.144000.json','["東君調護亦多情，瘦比夷齊徹骨清。", "有韻綠毛時倒掛，無塵白鷺可同盟。", "未應桃葉能稱姊，若齒山樊定是兄。", "何事故園頻入夢，疎枝新賞玉谿晴。"]'),
('02040100-1498-475d-be39-1eb39c37878c','謝張使君惠簟','喻良能','宋','宋诗','song-poetry','','[]','瘦玉敲風翠幹長，織成漪浪瑩滄浪。',64,'全唐诗/poet.song.144000.json','["瘦玉敲風翠幹長，織成漪浪瑩滄浪。", "封題尚带鄱江潤，卷贈猶餘燕寢香。", "竹笛當年同秀質，桃笙何處避寒光。", "微軀詎足當珍賜，持奉親闈枕扇凉。"]'),
('bc16dab4-d7cf-4db3-a414-d8c465e2f434','送張使君','喻良能','宋','宋诗','song-poetry','','[]','桐川風物最三吳，刺史循良繼兩都。',64,'全唐诗/poet.song.144000.json','["桐川風物最三吳，刺史循良繼兩都。", "但見賣刀還買犢，誰知有袴本無襦。", "來時竹馬迎兒輩，去日棠陰遶舍隅。", "攀斷車轅留不止，他年應作祖張圖。"]'),
('5397ea95-a2d3-4522-bc3f-a785cb429fbf','寄題梅山','喻良能','宋','宋诗','song-poetry','','[]','平生滿耳說梅山，十里荷花繚繞間。',64,'全唐诗/poet.song.144000.json','["平生滿耳說梅山，十里荷花繚繞間。", "宮女三千顔綽約，繡衣十萬綵斕斑。", "瀕江景好圖難盡，飛鷺詩工語莫刪。", "定約後期窮勝賞，不辭和月棹船還。"]'),
('7ab826ac-b16f-4c10-9798-4543720c06f6','寧川','喻良能','宋','宋诗','song-poetry','','[]','平生滿耳說宣城，入境雲煙照眼明。',64,'全唐诗/poet.song.144000.json','["平生滿耳說宣城，入境雲煙照眼明。", "過雨偏濃千嶂碧，未秋先冷數溪清。", "細看菡萏波間色，時聽綿蠻竹裏聲。", "不是多才謝公子，江山猶解發吟情。"]'),
('9839c50c-1d32-4835-a9c2-3993f8a59868','再用前韻','喻良能','宋','宋诗','song-poetry','','[]','晚驅羸馬背重城，曉度層巒淡月明。',64,'全唐诗/poet.song.144000.json','["晚驅羸馬背重城，曉度層巒淡月明。", "醉與別愁相喚醒，秋兼詩思一齊清。", "舞風繁蓼堤邊影，泣露寒蛩草際聲。", "欲駐征鞍聊小憩，敢將王事徇私情。"]'),
('8140f89f-7ae5-48b8-baf5-cc12030521e8','秋浦試院奉和馬駒父見寄','喻良能','宋','宋诗','song-poetry','','[]','也知融帳多餘暇，欲往論文偶未遑。',64,'全唐诗/poet.song.144000.json','["也知融帳多餘暇，欲往論文偶未遑。", "棄置亡何投轄飲，經營俱下讀書行。", "子雲但覺玄猶白，元亮應欣菊已黄。", "辱贈清詩不知報，剩親燈火趁新凉。"]'),
('24f4f775-50b4-42f7-89f1-c17c5ef56335','由當塗回宿齊山用杜牧之韻','喻良能','宋','宋诗','song-poetry','','[]','一望雲煙興欲飛，晴光聊復步熹微。',64,'全唐诗/poet.song.144000.json','["一望雲煙興欲飛，晴光聊復步熹微。", "幾年想像空懷古，今日登臨自送歸。", "寒菊有花宜靖節，澄江如練憶玄暉。", "夜深靜坐清人骨，巖影侵堦月滿衣。"]'),
('27a6c286-cb6e-465f-8610-430674affbec','九日青陽道中呈張主簿','喻良能','宋','宋诗','song-poetry','','[]','重陽時候在青陽，野店山肴對舉觴。',64,'全唐诗/poet.song.144000.json','["重陽時候在青陽，野店山肴對舉觴。", "菊蘂半開簪鬢好，橘包初破噀人香。", "西風有意吹紗帽，細雨無情濕錦障。", "但得一樽相對飲，不須更問是他鄉。"]'),
('6c47bb43-a44d-40f4-8b04-8837cf82b04b','謁太平興國宮','喻良能','宋','宋诗','song-poetry','','[]','平生耳滿太平名，今日身親謁太平。',64,'全唐诗/poet.song.144000.json','["平生耳滿太平名，今日身親謁太平。", "道子畫圖形未泯，廬君山水眼初明。", "雨餘翠滴千峰色，秋半寒生萬壑聲。", "扣石當年開洞府，儻容凡骨到蓬瀛。"]'),
('1d967730-d4e7-490b-8455-c40458f9b586','八月十五日夜試院翫月呈葉判官徐教授蔡主簿','喻良能','宋','宋诗','song-poetry','','[]','西風細逐桂枝生，秋月圓從屋角明。',64,'全唐诗/poet.song.144000.json','["西風細逐桂枝生，秋月圓從屋角明。", "歡伯向人端有意，素娥於客亦多情。", "試吟飛鵲南枝句，更聽春蠶食葉聲。", "從此塗山添勝事，四翁相遇四難并。"]'),
('393e8c54-b604-4fb2-8a8c-dd69c1ceb807','亦好園梅花','喻良能','宋','宋诗','song-poetry','','[]','一別經年見未曾，衝寒相值意凌兢。',64,'全唐诗/poet.song.144000.json','["一別經年見未曾，衝寒相值意凌兢。", "肌膚姑射仙人雪，品格中山孺子冰。", "清淺池塘春未動，黄昏籬落月初棱。", "從來自倚心如鐵，被惱如今似少陵。"]'),
('fd730502-216f-42f6-9279-4217d1632399','次韻茂恭元日大雪','喻良能','宋','宋诗','song-poetry','','[]','逗曉褰幃著綵衣，忽驚庭戶有光輝。',64,'全唐诗/poet.song.144000.json','["逗曉褰幃著綵衣，忽驚庭戶有光輝。", "緩將柏葉隨觴舉，細看梅花伴雪飛。", "阿堵無心來潤屋，詩仙有句到柴扉。", "酒酣笑共兒曹說，去歲如今歸未歸。"]'),
('d4fc5281-33a1-4267-a143-1bc07d659e77','柳季修知丞以詩見貽次韻爲謝','喻良能','宋','宋诗','song-poetry','','[]','古木陰陰繞屋廬，官居端的似田居。',64,'全唐诗/poet.song.144000.json','["古木陰陰繞屋廬，官居端的似田居。", "詩清子厚龍城句，字瘦誠懸殿壁書。", "那復有心追四至，只應無事富三餘。", "一樽閒論金罍事，爲笑紛紛竭澤漁。"]'),
('db9a5829-63ad-41f9-82f1-477eff74a55b','送交代李丞元舉','喻良能','宋','宋诗','song-poetry','','[]','藍田松下日棲遲，不比韓公作記時。',64,'全唐诗/poet.song.144000.json','["藍田松下日棲遲，不比韓公作記時。", "鷁首千行攀別淚，牛腰幾軸送行詩。", "我無楚尾歌來暮，君有齊民頌去思。", "自是中年多作惡，可堪烟雨話分離。"]'),
('4b869056-22e6-4645-afe2-8d4d7815379c','春盡偶書','喻良能','宋','宋诗','song-poetry','','[]','溪流如带碧縈紆，滿地閒花雜野蔬。',64,'全唐诗/poet.song.144000.json','["溪流如带碧縈紆，滿地閒花雜野蔬。", "濃淡柘陰三月暮，淺深山色晚晴初。", "頗驚井落家徒壁，却喜盤飱食有魚。", "蜀魄健啼春又老，揮鞭吾亦憶吾廬。"]'),
('c710b76b-f0cb-4a5f-8811-5d1a5624460e','題顔范祠堂','喻良能','宋','宋诗','song-poetry','','[]','聖宋神唐兩鉅人，高風勁節許誰倫。',64,'全唐诗/poet.song.144000.json','["聖宋神唐兩鉅人，高風勁節許誰倫。", "闉闍自昔宜雙廟，輪奐于今始一新。", "破敵威名優魏國，偃藩功業過張巡。", "後先來作江城守，俱障西風避庾塵。"]'),
('71324036-11cd-41f8-9f84-78a50ac71d78','宴餞逢寺丞口號','喻良能','宋','宋诗','song-poetry','','[]','一扇清風自楚臺，公堂葱鬰玳筵開。',64,'全唐诗/poet.song.144000.json','["一扇清風自楚臺，公堂葱鬰玳筵開。", "旌幢映座千峰日，鼓吹喧天萬壑雷。", "秋水幾行揮玉箸，春葱千指送金杯。", "甘棠不獨留遺愛，會見翻爲調鼎梅。"]'),
('e57f4c63-abe7-49b7-b83f-3fabfc3e3b08','捕盜至栗洪嶺下道人庵滯留數日遣興','喻良能','宋','宋诗','song-poetry','','[]','亂山深處小溪隈，夏木陰陰水半回。',64,'全唐诗/poet.song.144000.json','["亂山深處小溪隈，夏木陰陰水半回。", "風岸欹斜對青竹，雨枝低重弄黄梅。", "濃愁難辦新詩語，吉耗聊傾濁酒杯。", "戲綵老人須强飯，玉鈎纔吐即歸來。"]'),
('0abefc19-61fb-46ce-8b16-534f6ae1e483','題開先寺  其一','喻良能','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','少年魂夢到廬山，今日親遊鬢已斑。',64,'全唐诗/poet.song.144000.json','["少年魂夢到廬山，今日親遊鬢已斑。", "聊復揮毫吟紫翠，未妨拄頰對孱顔。", "遥看飛瀑三千丈，近去青天咫尺間。", "不爲白雲頻屬念，應遊此地不知還。"]'),
('829d8df5-87b0-45eb-b4ec-44c85ba5fc54','題開先寺  其二','喻良能','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','壯觀端宜冠九州，未應萬壑敢爭流。',64,'全唐诗/poet.song.144000.json','["壯觀端宜冠九州，未應萬壑敢爭流。", "盡將銀漢爲懸瀑，一洗紅塵變凜秋。", "白雨廉纖飛迥野，玉龍夭矯下靈湫。", "廬山處處雖奇絕，不到開先未是游。"]'),
('98b404e1-77ba-4612-8ab2-dc7f74ac9aaa','鵝湖寺  其一','喻良能','宋','宋诗','song-poetry','','[]','長松夾道摇蒼煙，十里絕如靈隠前。',64,'全唐诗/poet.song.144000.json','["長松夾道摇蒼煙，十里絕如靈隠前。", "不見素鵝青嶂裏，空餘碧水白雲邊。", "氛埃斗脫三千界，瀟灑疑通十九泉。", "五月人間正炎熱，清凉一覺北窗眠。"]'),
('e107bfe2-d05b-4f0e-aeb4-b1dbbafa9965','鵝湖寺  其二','喻良能','宋','宋诗','song-poetry','','[]','水鳥飛來一問津，璧宮珠塔便紅塵。',64,'全唐诗/poet.song.144000.json','["水鳥飛來一問津，璧宮珠塔便紅塵。", "開基古佛留遺像，直日奇峰列衆賓。", "芋火擁殘知永夜，霜鐘遞起嚮初晨。", "川徒渺渺驅塵駕，回首林前愧野人。"]'),
('9e8955c4-df85-499a-91fb-9e06dabb3a56','游西源于白雲峰下煙霏霧靄間逢一女子縞裙翠袂玉雪可念同遊十有二人遂共酌酒于大石屏季直弟有詩因用其韻','喻良能','宋','宋诗','song-poetry','','[]','相携攝履響層巒，翠蔓蒼蘿著處攀。',64,'全唐诗/poet.song.144000.json','["相携攝履響層巒，翠蔓蒼蘿著處攀。", "身在天台秋色裏，路經巫峽暮雲間。", "欲飛還住一仙子，似淡如濃雙遠山。", "笑盡一樽無處覓，斷腸霧鬢與風鬟。"]'),
('acaec5ab-cd63-4973-9f52-0dca08594f52','西禪寺','喻良能','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','脩廊千柱壓城陰，山並廬山勝二林。',64,'全唐诗/poet.song.144000.json','["脩廊千柱壓城陰，山並廬山勝二林。", "六月簷楹無暑氣，四時山水有清音。", "鳥飛不盡上方遠，鯨吼希聞別院深。", "更欲題詩發佳境，泮林講說總關心。"]'),
('674ecb4f-3c4e-4a15-997e-6ea65a9fe72f','予卧病數日意思殊昏昏中秋强起陪老人把酒對月不敢濡唇吻思去歲在當塗試院與諸公飲酒賦詩又一載矣因成長句','喻良能','宋','宋诗','song-poetry','','[]','楚水塗山各一涯，今年還是去年時。',64,'全唐诗/poet.song.144000.json','["楚水塗山各一涯，今年還是去年時。", "古來明月皆如此，我試停杯一問之。", "丹桂飄香知有子，飛烏遶樹似無枝。", "直須看到冰輪昃，忍負姮娥隔歲期。"]'),
('b1130114-ff9e-49ec-84d1-20239eb862ce','次韻戲綵老人重陽懷故園作','喻良能','宋','宋诗','song-poetry','','[]','瀟灑秋容雨後天，丹青端似倩龍眠。',64,'全唐诗/poet.song.144000.json','["瀟灑秋容雨後天，丹青端似倩龍眠。", "故園綠竹應今日，異縣黄花又一年。", "微祿祇堪供菽水，菲材安敢擬淵騫。", "日來王事欣多暇，聊向樽前一粲然。"]'),
('e3ea1a90-f132-4bde-aa28-527d820a8c45','送閻紫微歸蜀','喻良能','宋','宋诗','song-poetry','','[]','曲江分袂十年中，一笑相逢楚水東。',64,'全唐诗/poet.song.144000.json','["曲江分袂十年中，一笑相逢楚水東。", "西掖判花知思湧，南牆哦竹坐詩窮。", "秋風但覺艅艎駛，晝繡何妨畫㦸雄。", "道過夔門王內史，爲言雙鬢已如蓬。"]'),
('40b3eb3a-18f8-4dc7-ab93-918578fce032','寄周彥禮知丞樓文舉司理','喻良能','宋','宋诗','song-poetry','','[]','從容里閈待時須，二老風流孰與俱。',64,'全唐诗/poet.song.144000.json','["從容里閈待時須，二老風流孰與俱。", "遷善節香如故否，望雲迎月更佳無。", "醲寒凜凜侵衣袂，薄雪斑斑入畫圖。", "欲把一杯論舊事，五年魂夢隔江湖。"]'),
('edfe8382-c702-4ad8-8b0d-bb9b63f57146','次韻伯壽兄見寄','喻良能','宋','宋诗','song-poetry','','[]','江國疎梅吐玉英，故園想見木欣榮。',64,'全唐诗/poet.song.144000.json','["江國疎梅吐玉英，故園想見木欣榮。", "二年鴻鴈碧雲闊，千里江湖春水生。", "冉冉池塘應入夢，瀟瀟風雨若爲情。", "行看戲綵青萱發，準擬芳樽相對傾。"]'),
('a07b3724-08ec-4bc4-9a3e-9508749489af','二月十五日陪府公出郊勸農','喻良能','宋','宋诗','song-poetry','','[]','雨過郊原草色勻，元戎小隊出城闉。',64,'全唐诗/poet.song.144000.json','["雨過郊原草色勻，元戎小隊出城闉。", "聊穿阡陌溝塍路，徧勸耡耰襏襫人。", "紅杏梢頭春意好，綠楊深處鳥聲新。", "此行端爲劭農設，肯學醺酣吐錦茵。"]'),
('ab2342d3-9f73-4170-9392-908f2da44129','陪曹使君牧馬寺勸農','喻良能','宋','宋诗','song-poetry','','[]','朱轓小隊出郊坰，風捲濃陰作快晴。',64,'全唐诗/poet.song.144000.json','["朱轓小隊出郊坰，風捲濃陰作快晴。", "夾道老人迎五馬，囀枝黄鳥避雙旌。", "參差麥壠雲屯重，零亂梅花雪片輕。", "勸課定知非小補，扶犁携餉趁春耕。"]'),
('78618f6a-ef0a-45a7-9173-ff8cb47b5839','次韻木藴之狀元見寄之作','喻良能','宋','宋诗','song-poetry','','[]','水遶星山木遶廬，江城孤絕政愁予。',64,'全唐诗/poet.song.144000.json','["水遶星山木遶廬，江城孤絕政愁予。", "鳥言爲吏居篁竹，烏鬼得魚歡里閭。", "照眼梅花寒皎皎，關心煙雨晚疎疎。", "真山多謝遥相憶，長句新詩細字書。"]'),
('e03af338-d9a4-45d6-aa5c-631e2d683fbb','登五峰亭望廬山','喻良能','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','平生廬阜去無因，咫尺于今不得親。',64,'全唐诗/poet.song.144000.json','["平生廬阜去無因，咫尺于今不得親。", "顧我塵勞四十九，羨他蕭散二仙人。", "會當拄頰看山色，更欲題詩滿澗濱。", "爲報草堂蓮社友，掃雲開戶待游輪。"]'),
('90542453-05c6-4146-8302-de82f77cab02','詠月','喻良能','宋','宋诗','song-poetry','','[]','何年玉斧巧修成，半似明生半魄生。',64,'全唐诗/poet.song.144000.json','["何年玉斧巧修成，半似明生半魄生。", "易使飛烏來匝繞，難將老蚌較虧盈。", "桂枝不逐秋風老，水影長隨夜氣清。", "曾是廣寒宮裏客，舊遊重訪更含情。"]'),
('38ec096a-bd67-479a-96a4-e42d9edf786e','陪通守李丈出郊','喻良能','宋','宋诗','song-poetry','','[]','出郭旌旗及曉晴，朔風凜凜水泠泠。',64,'全唐诗/poet.song.144000.json','["出郭旌旗及曉晴，朔風凜凜水泠泠。", "堵牆野老瞻泥軾，冠劍長松拂屏星。", "破臘梅花强半白，先春草色未多青。", "經行肯爲遊觀美，王事馳驅不敢寧。"]'),
('d2301738-1c0c-46dd-922f-a8230982cbb2','曉行霜重如雪','喻良能','宋','宋诗','song-poetry','','[]','霜重寒威一夜加，曉來人迹板橋斜。',64,'全唐诗/poet.song.144000.json','["霜重寒威一夜加，曉來人迹板橋斜。", "已看白鴈來千里，想見青州滿百花。", "何處菊枝猶復耐，故園菊味定堪嘉。", "慈顔正念征裘薄，歸去萱堂笑語譁。"]'),
('4fef44a4-f269-47ad-b825-2a20e30a8479','挽施州使君鍾公','喻良能','宋','宋诗','song-poetry','','[]','弱冠爲儒世所推，中年事業更瓌奇。',64,'全唐诗/poet.song.144000.json','["弱冠爲儒世所推，中年事業更瓌奇。", "才名屢致諸公薦，讜論深蒙睿主知。", "郡政堅强同薤水，行囊蕭瑟似琴龜。", "只今惟有清江路，父老相逢說去思。"]'),
('ee03e9b1-f1eb-46fb-9909-22f0cb13d067','東歸','喻良能','宋','宋诗','song-poetry','','[]','無邊春意正沖融，十幅歸帆到淛東。',64,'全唐诗/poet.song.144000.json','["無邊春意正沖融，十幅歸帆到淛東。", "照水杏花紅翦翦，弄晴楊柳綠茸茸。", "風光併入吟毫裏，山色都歸醉眼中。", "說與林間子規道，丁寧不必向東風。"]'),
('b4527154-6458-4f46-91b2-8dcecbdfde3e','東歸見梅','喻良能','宋','宋诗','song-poetry','','[]','老大無堪鬢似銀，虛名猶復玷簪紳。',64,'全唐诗/poet.song.144000.json','["老大無堪鬢似銀，虛名猶復玷簪紳。", "久爲碌碌趨朝士，暫作棲棲去國人。", "行李衝寒歸故里，江梅偷煖報新春。", "萬鍾於我何加益，三釜新來喜及親。"]'),
('d5be37e0-fb54-4290-9949-be22a1377f35','草堂成即事二首  其一','喻良能','宋','宋诗','song-poetry','','[]','三年留滯江之南，歸來故園寢亦甘。',64,'全唐诗/poet.song.144000.json','["三年留滯江之南，歸來故園寢亦甘。", "經理草堂唐寶應，耘耡荒徑晉陶潛。", "寸心自昔似南八，雙鬢只今如謝三。", "手栽楊柳既合抱，木尚如此人何堪。"]'),
('5a9ca8bf-f681-4e8e-bc25-7966f686d6ce','草堂成即事二首  其二','喻良能','宋','宋诗','song-poetry','','[]','燕雀桑麻五畝勻，香爐峰下磬湖濱。',64,'全唐诗/poet.song.144000.json','["燕雀桑麻五畝勻，香爐峰下磬湖濱。", "青衫不礙兩居士，白髮真成六老人。", "子美浣花元不惡，淵明栗里總宜貧。", "作詩飲酒真吾事，回首江湖懶問津。"]'),
('d40b75ce-7a99-4911-9d89-2ece5a2b2e9d','亦好園即事','喻良能','宋','宋诗','song-poetry','','[]','誰將春色到山家，湖綠平堤草滿沙。',64,'全唐诗/poet.song.144000.json','["誰將春色到山家，湖綠平堤草滿沙。", "細刻真酥水仙蘂，勻搓絳蠟海紅花。", "芳林得日鶑還囀，香徑無風蝶自斜。", "聊與後生修故事，未妨詩酒作生涯。"]'),
('7375291c-e905-4e37-ae91-07923a85d4ab','亦好園春晚再用前韻','喻良能','宋','宋诗','song-poetry','','[]','境凈山明別一家，幾多垂柳裊平沙。',64,'全唐诗/poet.song.144000.json','["境凈山明別一家，幾多垂柳裊平沙。", "閒中牽夢一池草，空裏愁人萬點花。", "細雨朝朝兼暮暮，淡烟整整復斜斜。", "綠陰青子真堪畫，滿意春風磬水涯。"]'),
('09332838-1093-477f-858e-1b121e6cf92e','經理西山同二客二弟姪輩侍太孺人游觀聯句','喻良能','宋','宋诗','song-poetry','','[]','西山仍復踞西臺，石逕嶔崎此日開。',64,'全唐诗/poet.song.144000.json','["西山仍復踞西臺，石逕嶔崎此日開。", "竹杖相邀七八客，芳樽時釂兩三杯。", "瀑懸巖腹如飛雨，石轉山腰若隠雷。", "敬侍慈顔供一笑，陂陀坐穩興悠哉。"]'),
('79ca632d-dfed-4301-bf23-782658af1620','春興','喻良能','宋','宋诗','song-poetry','','[]','日日春泥妨杖藜，一聲何處子規啼。',64,'全唐诗/poet.song.144000.json','["日日春泥妨杖藜，一聲何處子規啼。", "紅將滿地花空委，綠盡前山草正萋。", "已辦篇章書側理，可無杯斝捧柔荑。", "清明過後芳菲少，桃李清陰欲滿蹊。"]'),
('c636f6ac-3d3a-4903-b95c-6c2dad80ff46','侍太夫人拜掃先塋季直弟有詩因次其韻','喻良能','宋','宋诗','song-poetry','','[]','東郊雲氣曉疎疎，十里相携霽色初。',64,'全唐诗/poet.song.144000.json','["東郊雲氣曉疎疎，十里相携霽色初。", "林幄盡頭聞杜宇，荇絲深處見王餘。", "提壺相勸仍沽酒，扶杖來觀或荷鋤。", "不向如臯閒射雉，真成一笑粲潘輿。"]'),
('ce3477b9-0dbb-4acd-97d9-3347538ab98b','次韻伯壽兄中秋翫月','喻良能','宋','宋诗','song-poetry','','[]','中秋自古月華好，何况浮雲掃碧天。',64,'全唐诗/poet.song.144000.json','["中秋自古月華好，何况浮雲掃碧天。", "不比尋常三五夕，須知瀲灧十分圓。", "畫簷影轉猶宜飲，銀漢輝斜未忍眠。", "却憶年時今夜裏，獨將醒眼對嬋娟。"]'),
('44037653-dc20-4d7b-9fe5-83783790da6a','東軒即事','喻良能','宋','宋诗','song-poetry','','[]','嘯傲東軒得此生，平章物理憶淵明。',64,'全唐诗/poet.song.144000.json','["嘯傲東軒得此生，平章物理憶淵明。", "晴塘灧灧起萍浪，夏木陰陰求友聲。", "聊欲庶幾三不惑，誰能復較四難并。", "旋燒蟹眼烹鷹爪，啜罷呼兒課二京。"]'),
('056ff070-24b2-4d5f-aa1f-edc7454c02c9','寄程教授士廓','喻良能','宋','宋诗','song-poetry','','[]','去年同宴小重陽，香霧霏霏橘半黄。',64,'全唐诗/poet.song.144000.json','["去年同宴小重陽，香霧霏霏橘半黄。", "楚尾吳頭雙妙麗，茱枝菊蘂總芬芳。", "十分滿釂白衣酒，兩袖濃携燕寢香。", "回首只今如夢寐，暮雲烟浪正微茫。"]'),
('46ff2c4d-6a6e-4cc3-b981-06cefefde76e','重陽遣興','喻良能','宋','宋诗','song-poetry','','[]','秋高身老少陵悲，不獨雲飛鴈亦飛。',64,'全唐诗/poet.song.144000.json','["秋高身老少陵悲，不獨雲飛鴈亦飛。", "紅葉色深偏照酒，黄花香重欲沾衣。", "絕知落帽歡娛好，最奈登山伴侶稀。", "强插茱萸修故事，未妨醉眼送斜暉。"]'),
('392ee947-deb6-4dc7-a559-3697b9f59821','亦好園江梅變紅仲文季直二弟有詩因次韻','喻良能','宋','宋诗','song-poetry','','[]','蕭蕭亦好耐寒枝，天與風流一段奇。',64,'全唐诗/poet.song.144000.json','["蕭蕭亦好耐寒枝，天與風流一段奇。", "刻玉不惟工傲雪，施朱端欲妙凝脂。", "佳人赬頰今纔見，公子酡顔頃未知。", "便好作軒名頓有，二難連璧賦清詩。"]'),
('476f5399-6f3d-4d44-9a52-93d178668c92','雪中賞橫枝梅花','喻良能','宋','宋诗','song-poetry','','[]','橫枝梅花最先開，影著清淺無纖埃。',64,'全唐诗/poet.song.144000.json','["橫枝梅花最先開，影著清淺無纖埃。", "壽陽粧額依然在，姑射冰肌何處來。", "無數雪花新點綴，幾番霜鬢獨徘徊。", "想見懷安官道側，十里潔白如瓊瑰。"]'),
('4cf1c170-9bba-4745-b972-dea21ba43e8d','戊子除夕追和陳簡齋除夜一首','喻良能','宋','宋诗','song-poetry','','[]','世事年來已飽更，百年今夕兩分平。',64,'全唐诗/poet.song.144000.json','["世事年來已飽更，百年今夕兩分平。", "窗間蠟炬偎人煖，缾裏梅花照眼明。", "瓦屋三間聊足喜，鬢霜千丈總堪驚。", "明朝同上西山望，應有江湖春水生。"]'),
('c3a1428f-7c52-4921-96cb-a45b5600c4e1','次韻季直弟春日雪','喻良能','宋','宋诗','song-poetry','','[]','休驚雙鬢二毛加，且喜東君發物華。',64,'全唐诗/poet.song.144000.json','["休驚雙鬢二毛加，且喜東君發物華。", "未向林梢開嫩葉，先於簷際舞飛花。", "鼠鬚正好書春帖，蟹眼偏宜試露芽。", "便欲扁舟訪安道，不堪山驛水程賒。"]'),
('4ad9adce-5194-42ca-bd75-643c574025f5','次韻和夷仲節推陪府公游北山','喻良能','宋','宋诗','song-poetry','','[]','紅蓮猶得愛青山，翠木蒼蘿處處攀。',64,'全唐诗/poet.song.144000.json','["紅蓮猶得愛青山，翠木蒼蘿處處攀。", "雲水窟中聊假日，簿書叢裏暫偷閒。", "幨帷車乘春同到，燈火城門夜未關。", "我亦林泉曾俯仰，只今雙屨又塵寰。"]'),
('af2012d0-ed57-448a-97ae-d28e1bcaa18f','題祥符寺靈山閣','喻良能','宋','宋诗','song-poetry','','[]','一倚危欄已快哉，俯看屏障掌中開。',64,'全唐诗/poet.song.144000.json','["一倚危欄已快哉，俯看屏障掌中開。", "江間碧浪循城去，天外青山入座來。", "隔岸幾聲聞鼓角，傍林千簇見樓臺。", "白雲只在孤飛處，西望關心首重迴。"]'),
('356d477a-dfb3-4ea9-820b-4beadcdb2acf','武夷山','喻良能','宋','宋诗','song-poetry','','[]','沖佑觀前水紺色，昇真洞北山笋攢。',64,'全唐诗/poet.song.144000.json','["沖佑觀前水紺色，昇真洞北山笋攢。", "羣峯不斷四時翠，萬壑長留九月寒。", "溪上桃花引漁子，雲間仙犬逐劉安。", "平生飽識佳山水，直作東南第一看。"]'),
('96aee5ee-3a9b-4337-bcf1-e9ddeba111a5','天申節望闕口號','喻良能','宋','宋诗','song-poetry','','[]','日永凉生殿閣風，需雲宴衎慶流虹。',64,'全唐诗/poet.song.144000.json','["日永凉生殿閣風，需雲宴衎慶流虹。", "明良叶德千齡遇，臣妾傾心萬國同。", "葵影緩隨羲馭轉，榴花高映御袍紅。", "西踰葱嶺東遼海，長屬堯封禹貢中。"]'),
('c319ee7e-ff0e-45da-9d50-9084403da073','試院次韻馬駒父見寄','喻良能','宋','宋诗','song-poetry','','[]','華髮蕭蕭知更稀，回頭五十四年非。',64,'全唐诗/poet.song.144000.json','["華髮蕭蕭知更稀，回頭五十四年非。", "花添病眼正臨卷，春滿故園猶未歸。", "止酒獨醒陶靖節，寄詩相憶謝玄暉。", "若爲比得新篇美，西蜀江頭錦一機。"]'),
('7630a321-af31-4d4d-9826-ef2963399515','試院七夕','喻良能','宋','宋诗','song-poetry','','[]','過雨秋風灑客裳，長廊廣厦更清凉。',64,'全唐诗/poet.song.144000.json','["過雨秋風灑客裳，長廊廣厦更清凉。", "不看雲際癡牛女，細讀文中古戰場。", "病骨未輕聊把酒，詩情欲適旋焚香。", "敢辭秉燭分清夜，猶記槐黄昔日忙。"]'),
('462c77a2-e708-43a6-874d-e64bc1fd8b15','陳知府體仁和予七夕試院詩併以龍涎數十餠爲餉次韻奉酬陳每講會甚盛','喻良能','宋','宋诗','song-poetry','','[]','八郡經生滿鱣堂，那能斗酒博西凉。',64,'全唐诗/poet.song.144000.json','["八郡經生滿鱣堂，那能斗酒博西凉。", "晚年刻意玄虛講，蚤歲留心翰墨場。", "憐我無氈寒坐客，分公燕寢舊清香。", "相逢一笑寧多得，歸去匆匆有底忙。"]'),
('40b6c1c4-d9c5-4645-900e-aaad743402b4','司戶李巖詹和予廬山詩二十一篇作詩爲謝','喻良能','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','東野龍鍾誇白首，巖詹矍鑠事清修。',64,'全唐诗/poet.song.144000.json','["東野龍鍾誇白首，巖詹矍鑠事清修。", "胸中似有九雲夢，筆下倒傾三峽流。", "和我七言清有味，能令三伏凜生秋。", "當年廬阜賞心處，恨不携公九日游。"]'),
('15cba25d-0a46-47b5-b3d6-fc771b15e374','題馮家洞','喻良能','宋','宋诗','song-poetry','','[]','空巖寒氣凜兢兢，入戶神清思亦澂。',64,'全唐诗/poet.song.144000.json','["空巖寒氣凜兢兢，入戶神清思亦澂。", "似應如非聲澒洞，已垂未落石崚嶒。", "深於豳俗藏冰室，險過文王避雨陵。", "刮蘚磨崖書淡墨，勝游聊復記吾曾。"]'),
('aa2e08a2-649e-4cc4-97da-f48beaefc81d','校官廳新栽巖桂','喻良能','宋','宋诗','song-poetry','','[]','不將官舍等逆旅，故把霜根栽繞牆。',64,'全唐诗/poet.song.144000.json','["不將官舍等逆旅，故把霜根栽繞牆。", "他日花開映秋色，何人手折惹天香。", "丁寧護取森森碧，想像勻排粟粟黄。", "顧我疎慵百無取，未應人錯比甘棠。"]'),
('97dadf95-5b1b-451e-a7fe-21936c7f60df','參議李郎中見和次韻奉酬','喻良能','宋','宋诗','song-poetry','','[]','頃歲題名曲江院，及肩曾許亞宮牆。',64,'全唐诗/poet.song.144000.json','["頃歲題名曲江院，及肩曾許亞宮牆。", "胸中闊貯雲夢澤，筆下濃薰班馬香。", "省直舊霑衾半白，除書行見紙新黄。", "和篇如出少陵手，誰謂無心賦海棠。"]'),
('49c24464-8c79-415c-b0f8-072532bfe0a4','再用前韻呈參議李郎中','喻良能','宋','宋诗','song-poetry','','[]','獨冷官曹有底忙，經旬不得造門牆。',64,'全唐诗/poet.song.144000.json','["獨冷官曹有底忙，經旬不得造門牆。", "雨添垂柳絲絲碧，風攪飛花片片香。", "顧我摧頹如病顙，羨公騰踏勝飛黄。", "新詩迥出南豐右，不是無香似海棠。"]'),
('9c1d4753-8515-4827-b944-ddc8da576abe','寄張君玉','喻良能','宋','宋诗','song-poetry','','[]','橘亭一別五回冬，寤寐何曾置此翁。',64,'全唐诗/poet.song.144000.json','["橘亭一別五回冬，寤寐何曾置此翁。", "二十五聲秋後點，八千里外月明中。", "夫君不寄平安信，而我方棲簿領叢。", "三峽江高天共遠，側身西望興何窮。"]'),
('531986d3-2c72-4266-a3bd-86659d2b41b7','次韻周希稷詠芭蕉','喻良能','宋','宋诗','song-poetry','','[]','經年不接故人書，開戶逢渠了不殊。',64,'全唐诗/poet.song.144000.json','["經年不接故人書，開戶逢渠了不殊。", "誰運七輪風裏扇，時跳千斛雨中珠。", "退之有意吟山石，摩詰無心作畫圖。", "爲愛青青無俗韻，故教移植傍庭隅。"]'),
('54c24ff3-c617-45d8-89cd-864bc5fcfcc4','次韻葉省幹重九樓上言懷','喻良能','宋','宋诗','song-poetry','','[]','水落魚龍已退藏，小樓蕭爽裌衣凉。',64,'全唐诗/poet.song.144000.json','["水落魚龍已退藏，小樓蕭爽裌衣凉。", "山雲雨過無窮態，巖桂風來不斷香。", "已分文章成白豕，擬將富貴等黄粱。", "嵇康潦倒渾無取，豈復眉開一點黄。"]'),
('d5411db0-60fb-4e79-9c6b-125f8eb744f5','送洪右史赴召三首  其一','喻良能','宋','宋诗','song-poetry','','[]','胸蟠補衮五色絲，筆驅波濤三峽詞。',64,'全唐诗/poet.song.144000.json','["胸蟠補衮五色絲，筆驅波濤三峽詞。", "上追班馬真輩行，下視燕許如兒嬉。", "拙工廢繩那足道，巧匠縮手今當施。", "前途著鞭政須急，玉堂獨步非公誰。"]'),
('abc3b1d1-eecd-4767-a8e4-930a14ca3001','送洪右史赴召三首  其二','喻良能','宋','宋诗','song-poetry','','[]','長公前日辭揆塗，少公今日被鋒車。',64,'全唐诗/poet.song.144000.json','["長公前日辭揆塗，少公今日被鋒車。", "路人共指拜內相，天子久欲登鴻儒。", "黄麻端擬似經訓，金蓮不獨榮傳呼。", "如聞書詔正填委，北轅疾驅公勿徐。"]'),
('bd50cca8-4d93-4b84-a477-84ad171c4e26','送洪右史赴召三首  其三','喻良能','宋','宋诗','song-poetry','','[]','月宿南斗窮何遣，爬沙脚手鈍可咍。',64,'全唐诗/poet.song.144000.json','["月宿南斗窮何遣，爬沙脚手鈍可咍。", "一生冰清但糠粃，兩鬢雪白獨塵埃。", "達人疑劍未免按，夷途薦轂誰當推。", "公乎行矣斷國論，能忘料理忍窮枚。"]'),
('71e5c638-dc6e-4001-bc27-d566d8b0946d','由建寧回三山道中重陽','喻良能','宋','宋诗','song-poetry','','[]','征鞍初自富沙還，亂葉殷紅點碧山。',64,'全唐诗/poet.song.144000.json','["征鞍初自富沙還，亂葉殷紅點碧山。", "客裏黄花驚度節，鏡中白髮巧摧顔。", "三休磴道惟頻嘆，一飯茆簷得暫閒。", "爲想成均新榜帖，阿奴才力勝黄間。"]'),
('3d4c07b3-e7d4-4780-a530-09e4c3e3be9d','通判孫宗丞分餉溫柑次馬撫幹詠橘韻作詩爲謝','喻良能','宋','宋诗','song-poetry','','[]','珍果分柑不作疎，李衡千顆直堪奴。',64,'全唐诗/poet.song.144000.json','["珍果分柑不作疎，李衡千顆直堪奴。", "初嘗蔌蔌泉流齒，未摘青青香滿株。", "可是騷人憐楚樹，只應仙種自蓬壺。", "龍城當日親封殖，還有霜苞似此無。"]'),
('ca2d532d-9490-4ec1-bdbf-e22d80633b51','園中口占','喻良能','宋','宋诗','song-poetry','','[]','舂鉏野鳬疑水鄉，湖陰山色仍蒼蒼。',64,'全唐诗/poet.song.144000.json','["舂鉏野鳬疑水鄉，湖陰山色仍蒼蒼。", "西風三徑有佳致，朔雪橫枝多暗香。", "長統遊戲自足樂，少游贏餘非所望。", "開林貼石興未已，瓜時逼人須趣裝。"]'),
('de55e0c5-4b5a-44c4-b83d-7b048c498279','聞交代將至喜而成篇','喻良能','宋','宋诗','song-poetry','','[]','三年泮水冷無氊，贏得蕭蕭雪滿顛。',64,'全唐诗/poet.song.144000.json','["三年泮水冷無氊，贏得蕭蕭雪滿顛。", "晚景不妨供綵戲，他鄉安敢廢詩篇。", "賸將杯酒澆行色，速賃雙童擔近編。", "任是身歸落鴈後，鄉心先抵磬湖邊。"]'),
('ed7083be-19c5-4fd8-98c8-014c39797b62','府學職事置酒九仙以餞予行','喻良能','宋','宋诗','song-poetry','','[]','玉友金朋三十三，携尊相屬向晴嵐。',64,'全唐诗/poet.song.144000.json','["玉友金朋三十三，携尊相屬向晴嵐。", "含毫共賦黄初句，揮麈仍追正始談。", "再用清烟噴白澤，更霏香霧噀黄柑。", "俊游勝事真堪畫，華髮飄蕭只自慚。"]'),
('98190f07-743a-4a78-856f-9a00b77b3cff','鉛山','喻良能','宋','宋诗','song-poetry','','[]','三月春風暖更飄，滿山嫩綠正嬌嬈。',64,'全唐诗/poet.song.144000.json','["三月春風暖更飄，滿山嫩綠正嬌嬈。", "幾聲勸我脫破袴，何處撩人婆餠焦。", "甘旨僅能供素髮，涓埃未有答皇朝。", "吾廬漸近亦堪喜，試把白醪傾綠瓢。"]'),
('80b3b2d6-ddd3-4607-ab1b-20ccdd72c7d4','中秋終日霧雨予還自都下宿分水嶺夜漏約七八刻月出烏飯草薦山之東徘徊窗牖間欣然把酒對之因賦長句','喻良能','宋','宋诗','song-poetry','','[]','烏飯山邊白玉團，瑞光千丈溢清寒。',64,'全唐诗/poet.song.144000.json','["烏飯山邊白玉團，瑞光千丈溢清寒。", "斜穿逆旅茆茨室，正照先生苜蓿盤。", "聊向青天思太白，却吟飛鵲憶曹瞞。", "今宵不擬逢明月，更向尊前仔細看。"]'),
('982efb3e-693e-4779-87bc-d98ec2ba69c3','重陽詠菊','喻良能','宋','宋诗','song-poetry','','[]','年年自赴重陽約，不待陶家詩句催。',64,'全唐诗/poet.song.144000.json','["年年自赴重陽約，不待陶家詩句催。", "便欲急呼歡伯賞，未知誰遣白衣來。", "紅萸有韻岳連湛，素蘂無香賜望回。", "何事杜陵嗔竹葉，却教從此不須開。"]'),
('813feaef-f848-41c0-b027-54cd54d18d6d','送伯壽兄之官上虞','喻良能','宋','宋诗','song-poetry','','[]','平生藝苑筆同耕，兄弟須知似友生。',64,'全唐诗/poet.song.144000.json','["平生藝苑筆同耕，兄弟須知似友生。", "三載方尋夜雨約，六旬又作越中行。", "舉杯不學銷魂別，側耳惟聽報政聲。", "從此西岡數登眺，白雲飛處總關情。"]'),
('441d567b-6e67-4e94-8b03-1b0f81076e74','賢良馬叔度和周內翰送予倅越詩見貽次韻奉酬','喻良能','宋','宋诗','song-poetry','','[]','一鳴一息幾千秋，風翼端宜汗漫游。',64,'全唐诗/poet.song.144000.json','["一鳴一息幾千秋，風翼端宜汗漫游。", "筆底珠璣誰得似，胸中雲夢復何求。", "談餘正始人加勝，詩比黄初語更遒。", "西笑定應參儤直，東游聊復伴遨頭。"]'),
('0cbdd182-f6d6-4b97-a442-dc767bc36fa3','叔度賢良再用游字韻見貽復次韻謝之','喻良能','宋','宋诗','song-poetry','','[]','夕郎分閫鎮東秋，幕下揮毫秦少游。',64,'全唐诗/poet.song.144000.json','["夕郎分閫鎮東秋，幕下揮毫秦少游。", "一代風流今不泯，百年文物尚堪求。", "交情莫逆人誰似，吟事方殷歲又遒。", "他日約君爲伯仲，三間瓦屋住東頭。"]'),
('9a860cbf-aa1b-4667-803f-219b742a4d46','次韻馬叔度再用前韻見寄','喻良能','宋','宋诗','song-poetry','','[]','善弈從來數弈秋，勝游今作子長游。',64,'全唐诗/poet.song.144000.json','["善弈從來數弈秋，勝游今作子長游。", "才多已覺懸河似，詩妙無勞入海求。", "畫月裁雲寧底巧，奔泉抉石一何遒。", "誰知傾盖成膠漆，笑殺如新到白頭。"]'),
('0e9cc884-de46-4906-859b-110e5d5f4b9b','過嚴瀨寄陸守務觀','喻良能','宋','宋诗','song-poetry','','[]','翰墨場中老伏波，揮毫快馬下晴坡。',64,'全唐诗/poet.song.144000.json','["翰墨場中老伏波，揮毫快馬下晴坡。", "三年睿主思獻納，千里疲民頼撫摩。", "瀟灑郡齋方在望，飄摇征棹未能過。", "擬求墨妙輝衡宇，應有黄庭換白鵝。"]'),
('12a3189b-966e-4809-b53c-f03150c6f4b8','齋宿凈明寺小飲易安齋口占','喻良能','宋','宋诗','song-poetry','','[]','凈明齋宿近初庚，西蜀東吳一世英。',64,'全唐诗/poet.song.144000.json','["凈明齋宿近初庚，西蜀東吳一世英。", "行徑九盤山犖确，流泉百折玉琮琤。", "頻飛兕斝顔俱渥，細聽犀談座爲傾。", "觴詠直多幽興足，未應不飲似公榮。"]'),
('a6897f46-7782-4068-9d66-e3cc74451d17','挽縣尉陳元圭','喻良能','宋','宋诗','song-poetry','','[]','平生自負氣雄豪，落筆文詞湧怒濤。',64,'全唐诗/poet.song.144000.json','["平生自負氣雄豪，落筆文詞湧怒濤。", "蚤歲賢關幾雁塔，暮年花縣未牛刀。", "凜然風義誰能並，偉甚衣冠衆所高。", "我欲臨風新執紼，忍於繪事看青袍。"]'),
('da8455db-2d47-4cba-b514-288863e42735','題確山梵安寺','喻良能','宋','宋诗','song-poetry','','[]','確山風物似齊山，誰著精藍亂石間。',64,'全唐诗/poet.song.144000.json','["確山風物似齊山，誰著精藍亂石間。", "僧梵四時看紫翠，軒窗終日對孱顔。", "暫容借榻松風愜，更欲題詩蘚壁慳。", "老我還思十年事，飛來峰上曉躋攀。"]'),
('272c328f-d6d6-42ab-8ca2-62ff5385fd14','鑑湖道中口占','喻良能','宋','宋诗','song-poetry','','[]','軋軋籃輿鑑水濱，水紋如染草如茵。',64,'全唐诗/poet.song.144000.json','["軋軋籃輿鑑水濱，水紋如染草如茵。", "繁紅零落徐娘老，遠翠低徊西子顰。", "猶及殘春追勝賞，不妨餘事作詩人。", "胸中磊磈須澆洗，未厭傷多酒入脣。"]'),
('97cea2cf-19f4-4b0f-b77a-9aa7bd76f19d','次韻王龜齡謁大禹祠酌菲飲泉','喻良能','宋','宋诗','song-poetry','','[]','不到稽山已十年，夢中物色故依然。',64,'全唐诗/poet.song.144000.json','["不到稽山已十年，夢中物色故依然。", "憶尋絕境經幽寺，曾向東風酌妙泉。", "書穴雨餘雲撲地，鑑湖春晝水連天。", "別來喬木高多少，想見嬌鶑自在遷。"]'),
('bedef5e7-6222-4489-8337-b8241319161f','題東山謝安石故居','喻良能','宋','宋诗','song-poetry','','[]','江邊瀟灑東山寺，知是曾經謝傅游。',64,'全唐诗/poet.song.144000.json','["江邊瀟灑東山寺，知是曾經謝傅游。", "一代英姿餘信史，千年陳迹付東流。", "暮雲初致蒼生恨，遠翠如凝妓女愁。", "好古嗟予生苦晚，停橈明月滿滄洲。"]'),
('4b09c7ab-a699-4628-93fa-c657c3cc4a6e','既游東山乘月登舟至曹娥江','喻良能','宋','宋诗','song-poetry','','[]','虞江波上一帆風，天水澄明夜色空。',64,'全唐诗/poet.song.144000.json','["虞江波上一帆風，天水澄明夜色空。", "古體詩成巖影裏，新醅酒酌月明中。", "吚啞兩槳止還作，欵乃數聲西復東。", "塵滓此時無一點，恍疑身在水晶宮。"]'),
('a6f27e0d-e918-46a4-9f8d-584a1d20950b','題歸宗寺','喻良能','宋','宋诗','song-poetry','','[]','寺因逸少曾爲宅，峯自秦皇已得名。',64,'全唐诗/poet.song.144000.json','["寺因逸少曾爲宅，峯自秦皇已得名。", "不獨山南稱最古，故應江左號尤清。", "路趨絳闕山梁險，奩隠金輪石鏡明。", "誰信塵埃倦游客，西風還許杖藜行。"]'),
('0a3d5221-d8c2-427b-87e4-7173ab806674','次陸務觀韻題姚復之秀才適齋','喻良能','宋','宋诗','song-poetry','','[]','姚子神情處處便，牀頭周易杖頭錢。',64,'全唐诗/poet.song.144000.json','["姚子神情處處便，牀頭周易杖頭錢。", "逢僧與語閒終日，遣客歸休醉欲眠。", "應覺此生如寄耳，何妨一室且蕭然。", "無心更覓封侯事，納履誰能博一編。"]'),
('3a0d0259-d863-483b-aff1-d619742a70c0','追和陳子高贈王法曹韻','喻良能','宋','宋诗','song-poetry','','[]','肯學少陵對馬連，肯同太白謝汪倫。',64,'全唐诗/poet.song.144000.json','["肯學少陵對馬連，肯同太白謝汪倫。", "聊將文字飲一盞，不待月影成三人。", "門前車馬鬧遲日，陌上綺羅嬌暮春。", "想見流觴多樂事，酒酣人問斗升嗔。"]'),
('8b6557d3-7071-4967-b1a4-8fa16b64b630','喜待制王丈歸自夔門','喻良能','宋','宋诗','song-poetry','','[]','三年遥望瞿塘峽，獨立西風首重回。',64,'全唐诗/poet.song.144000.json','["三年遥望瞿塘峽，獨立西風首重回。", "一騎翩翩飛詔去，片帆渺渺下江來。", "平生不願侯萬戶，今日重欣酒一杯。", "聞道日邊催覲速，不須歸路更徘徊。"]'),
('b790296b-eaeb-4622-940a-30654361a7a3','次韻林參議小雪快晴','喻良能','宋','宋诗','song-poetry','','[]','著地晶瑩月在沙，忍寒聊作短歌誇。',64,'全唐诗/poet.song.144000.json','["著地晶瑩月在沙，忍寒聊作短歌誇。", "煖肌未辦裁駝褐，露趾唯應有革鞾。", "細點竹梢添爽灑，偶經梅蘂映橫斜。", "何當既積還消後，剩取清泠試葉嘉。"]'),
('bc89ac12-0292-4aa3-aeda-a5c029578267','大雪','喻良能','宋','宋诗','song-poetry','','[]','山陰境中寒雪飛，山川明秀見應稀。',64,'全唐诗/poet.song.144000.json','["山陰境中寒雪飛，山川明秀見應稀。", "嚴威不貸乘興棹，餘彩併入繙書帷。", "黄竹應歌姬滿曲，素花又舞謝莊衣。", "東郊薪者寒到骨，縱有狐裘那忍披。"]'),
('9c0c3783-f86f-413a-bbf4-137ae2cc3b06','送王共父','喻良能','宋','宋诗','song-poetry','','[]','西蜀東吳萬里程，偶然相值兩浮萍。',64,'全唐诗/poet.song.144000.json','["西蜀東吳萬里程，偶然相值兩浮萍。", "黑頭君已登三館，白髮吾方醉六經。", "夜幌論文燈耿耿，春堤把袖草青青。", "艅艎小別須回棹，不用陽關腸斷聽。"]'),
('9241462a-3c2e-42e5-8e26-c8f6e6efb4fb','沿檄舟行出五雲關','喻良能','宋','宋诗','song-poetry','','[]','畫舫朱簾出曉關，便風飛過幾重灣。',64,'全唐诗/poet.song.144000.json','["畫舫朱簾出曉關，便風飛過幾重灣。", "路經僧舍漁村畔，身在烟霏霧靄間。", "驚浪沸晴輸遠浦，亂雲拖粉露崇山。", "偶因王事從心賞，詩語匆匆不暇刪。"]'),
('849240a2-de22-4788-9e00-4354f2a1328e','挽周判院','喻良能','宋','宋诗','song-poetry','','[]','昔年臚唱下彤墀，名壓人頭似牧之。',64,'全唐诗/poet.song.144000.json','["昔年臚唱下彤墀，名壓人頭似牧之。", "風動鱣堂昭武日，化行雉徑敬亭時。", "曾無簪筆朝端用，何以修文地下爲。", "我老不堪供執紼，獨將雙淚逗瑶巵。"]'),
('045485c9-1dcd-4273-b3c2-23979341c38f','次韻林明府何主簿唱酬之什','喻良能','宋','宋诗','song-poetry','','[]','向來十載願識韓，一日下車許追攀。',64,'全唐诗/poet.song.144000.json','["向來十載願識韓，一日下車許追攀。", "美句已出黄初右，清談尚餘正始間。", "煩公筆底瀾翻水，洗我胸中磊磈山。", "更挽何郎入詩社，三人俱有綵衣斑。"]'),
('867cc386-5e03-4b15-91f2-9ed96231799c','林明府携所和詩見過次韻奉酬','喻良能','宋','宋诗','song-poetry','','[]','退之初過玉川家，春徑無泥草带沙。',64,'全唐诗/poet.song.144000.json','["退之初過玉川家，春徑無泥草带沙。", "幾點飛來溪柳絮，一番開盡海棠花。", "窗間細雨青衫濕，袖裏新詩醉墨斜。", "客散酒闌還掩戶，可堪明月滿天涯。"]'),
('b131de0d-b95b-4ce8-8e5b-680b356c2524','帥參宴客於蓬萊閣林參議有詩次韻呈府公','喻良能','宋','宋诗','song-poetry','','[]','久以嘉謀贊邇英，暫分東淛慰蒼生。',64,'全唐诗/poet.song.144000.json','["久以嘉謀贊邇英，暫分東淛慰蒼生。", "閒携僚吏揮金盞，更遣娉婷吹玉笙。", "霖雨千巖垂欲作，孤舟野水未妨橫。", "匪因衮繡歸黄閤，還念知章在四明。"]'),
('77a5b07b-7c10-4ef1-a636-f8da3f70c175','次韻王待制劉侍郎倡和','喻良能','宋','宋诗','song-poetry','','[]','衮衣猶未趣東歸，吳會先傳蜀道詩。',64,'全唐诗/poet.song.144000.json','["衮衣猶未趣東歸，吳會先傳蜀道詩。", "急峽高江追子美，清風明月笑嚴維。", "花圍白帝行春日，香藹黄堂坐嘯時。", "顧我迂疎堪底用，强顔薪粟效支離。"]'),
('60230e4b-95d5-4441-8768-d0dca2e4f5be','次韻林致甫參議西園宴集','喻良能','宋','宋诗','song-poetry','','[]','西園瀟灑似蓬丘，容我追隨飛蓋游。',64,'全唐诗/poet.song.144000.json','["西園瀟灑似蓬丘，容我追隨飛蓋游。", "一一娉婷供笑語，雙雙鸂鶒對沈浮。", "嵁岩窈窕如天造，洞壑清泠與目謀。", "欲識清歡兼卜夜，東山月色足淹留。"]'),
('480aeba6-7194-4dae-90ee-d679a0e80966','讀林公懿誠竹軒集次韻卷首一篇','喻良能','宋','宋诗','song-poetry','','[]','南渡詩流復數誰，爲虞作樂只聞夔。',64,'全唐诗/poet.song.144000.json','["南渡詩流復數誰，爲虞作樂只聞夔。", "細看出脇穿心句，想見裁雲畫月時。", "此集自應傳異域，吾生還恨不同期。", "先唐作者誰堪並，奴僕微之輩牧之。"]'),
('fe664583-3137-4b22-9363-8e8f6053b2e1','次韻林參議七月七日見示新作','喻良能','宋','宋诗','song-poetry','','[]','曉雨初過溽暑收，微雲澹月作新秋。',64,'全唐诗/poet.song.144000.json','["曉雨初過溽暑收，微雲澹月作新秋。", "清風政對三休閣，絕景還思八詠樓。", "緱嶺當年乘白鶴，銀河此夕渡癡牛。", "壽觴一舉烘堂樂，凈洗胸中萬斛愁。"]'),
('5f90037d-4243-4b77-af08-e419deb5ecec','次韻奉酬林明府詠梅','喻良能','宋','宋诗','song-poetry','','[]','政足廉平詩更佳，鐵腸還解賦梅花。',64,'全唐诗/poet.song.144000.json','["政足廉平詩更佳，鐵腸還解賦梅花。", "律傳和靖未多葉，名接水曹今幾家。", "丹粉詎須煩巧妙，清新止爲寫橫斜。", "擬携卷軸江東去，乞與詩仙作意誇。"]'),
('4a93e6d2-5048-4a6a-8a07-d4f3458198c2','偶成','喻良能','宋','宋诗','song-poetry','','[]','寓居東青城北端，夏室陰陰簟色寒。',64,'全唐诗/poet.song.144000.json','["寓居東青城北端，夏室陰陰簟色寒。", "瓜盤那復集蠅蚋，研沼似欲生波瀾。", "奇奇怪怪石幾壑，謖謖蒼蒼竹數竿。", "枕扇衣斑自不惡，時文思索媿空餐。"]'),
('3dbf9957-f9ce-4404-a8c8-5891a3010352','裴園小集鄭汝諧同年有詩次韻奉酬','喻良能','宋','宋诗','song-poetry','','[]','慈恩鴈塔題名處，回首端如夢寐中。',64,'全唐诗/poet.song.144000.json','["慈恩鴈塔題名處，回首端如夢寐中。", "千里遠從當日別，一樽重喜此時同。", "飛騰我久欽公輩，潦倒君當恕此翁。", "異日尚期塵史冊，事功那敢廢磨礲。"]'),
('0434b478-db32-4b5a-bf82-ca47f4389688','次韻宇文舍人見貽之作','喻良能','宋','宋诗','song-poetry','','[]','不見褚公今二年，重來青眼尚依然。',64,'全唐诗/poet.song.144000.json','["不見褚公今二年，重來青眼尚依然。", "偃松篇美天猶和，正殿班清人孰先。", "今日赤墀煩暫立，他年黄閣徑須遷。", "白頭賓客無聊甚，只待吹噓送上天。"]'),
('3dff379e-a4b2-4f29-b07c-7fde7df1f5de','張使君生辰','喻良能','宋','宋诗','song-poetry','','[]','綠茸紅糝細團枝，天上麒麟瑞此時。',64,'全唐诗/poet.song.144000.json','["綠茸紅糝細團枝，天上麒麟瑞此時。", "風度冕旒嘗見問，威名草木自應知。", "當年玉燕生燕國，他日金貂侍漢墀。", "再拜祝公何所似，勝游長與赤松期。"]'),
('957b14d8-1ed6-4c39-8ee0-f02655865a7b','讀初寮集呈王宗丞','喻良能','宋','宋诗','song-poetry','','[]','初寮文律冠中京，晚歲深嚴三折肱。',64,'全唐诗/poet.song.144000.json','["初寮文律冠中京，晚歲深嚴三折肱。", "清處月中仍聚雪，高時風裏政摶鵬。", "家聲不墜推王粲，句法能傳有杜陵。", "剩作詩文追漢魏，非公誰不閼溪藤。"]'),
('f65d759f-3a64-4efa-b8db-9fef42be4450','記六月二十日湖上所見','喻良能','宋','宋诗','song-poetry','','[]','羽客相携六一泉，炎歊立變曉凉天。',64,'全唐诗/poet.song.144000.json','["羽客相携六一泉，炎歊立變曉凉天。", "陳朝古檜參天瘦，和靖孤墳傍竹偏。", "却向蘇堤剝新芡，更尋蕭寺聽寒蟬。", "長吟小醉歸來晚，足底清風似欲仙。"]'),
('3b4ff56b-be62-4467-b39c-5d3405d4ae99','六月晦日同樓少府由錢塘門至上竺遂遊下中竺憩冷泉亭塗中記所歷','喻良能','宋','宋诗','song-poetry','','[]','聯輿緩步踏葱蒼，十里荷香雜稻香。',64,'全唐诗/poet.song.144000.json','["聯輿緩步踏葱蒼，十里荷香雜稻香。", "庚暑此時無一點，秋風明月灑長廊。", "林間巖洞侵衣潤，水際亭臺徹骨凉。", "何處山泉落簷溜，恍疑飛雨曉浪浪。"]'),
('06e28c16-854d-4a2b-bd44-c61fbd0b0589','次韻范伯廉機宜病起見寄','喻良能','宋','宋诗','song-poetry','','[]','夫君自是穎囊錐，何事翻爲滄海遺。',64,'全唐诗/poet.song.144000.json','["夫君自是穎囊錐，何事翻爲滄海遺。", "造化小兒聊戲劇，山林大藥豈無資。", "得閒因病還應樂，信手揮毫却有詩。", "休歎銀盃成羽化，會須拔劍撥年衰。"]'),
('a96bda32-152d-4fb3-bca8-ffd83dbeab53','中秋示仲文弟','喻良能','宋','宋诗','song-poetry','','[]','古來佳節是中秋，今比重陽許燕游。',64,'全唐诗/poet.song.144000.json','["古來佳節是中秋，今比重陽許燕游。", "已覺冰輪無限好，不須玉斧更重修。", "三飛驚鵲紛無定，一點閒雲凈不留。", "况有阿連同綵戲，何妨呼酒互相酬。"]'),
('cbc31762-1416-452b-be9e-d364fb6cf9f9','次韻王宮教見貽之什','喻良能','宋','宋诗','song-poetry','','[]','家住濤江東復東，渺然雲浪接晴空。',64,'全唐诗/poet.song.144000.json','["家住濤江東復東，渺然雲浪接晴空。", "半生仕路崎嶇裏，十畝家山杳靄中。", "來往未成三徑樂，笑談還喜一樽同。", "强將俚語賡妍倡，曹鄶端慚齒衛風。"]'),
('a1ca6675-0783-491f-9eb8-d8d4e1b88565','長至憶天衣舊遊寄王狀元','喻良能','宋','宋诗','song-poetry','','[]','去年連轡到朝陽，紅日初添一線長。',64,'全唐诗/poet.song.144000.json','["去年連轡到朝陽，紅日初添一線長。", "八俊偶同人已羨，四難俱得計真良。", "澆腸竹葉驚深碧，插鬢梅花咤淺黄。", "回首只今深似夢，雲山烟水正相望。"]'),
('8b83aa79-782f-4f9c-ae17-023d120e0997','次韻奉酬黄泰之狀元見寄','喻良能','宋','宋诗','song-poetry','','[]','千佛經中第一人，明光前殿奏雄文。',64,'全唐诗/poet.song.144000.json','["千佛經中第一人，明光前殿奏雄文。", "論心詎止稱三益，識面端能勝百聞。", "疇昔清談如扣玉，只今佳句欲凌雲。", "高情已出蘇州右，未用清香掃地焚。"]'),
('4e43b8f3-f328-43da-aaa3-3373e51c9ac8','挽吳春卿舍人','喻良能','宋','宋诗','song-poetry','','[]','出處平生似昔賢，高風勁節凜朝端。',64,'全唐诗/poet.song.144000.json','["出處平生似昔賢，高風勁節凜朝端。", "回天議論心無歉，脫腕文章世所難。", "斫鐵叫天蠻獠服，調羹滿鉢里閭歡。", "定應直筆書英躅，留與千秋後代看。"]'),
('fc98b297-69fb-4122-81ec-039912cb7718','除夕','喻良能','宋','宋诗','song-poetry','','[]','夜永燈明歲又除，依然坐冷乏氍毹。',64,'全唐诗/poet.song.144000.json','["夜永燈明歲又除，依然坐冷乏氍毹。", "平生潦倒如中散，大半交游今左符。", "未辦黄精除白髮，漸驚玉水點銀鬚。", "欲論舊事無人共，閒把香醪細細𣂏。"]'),
('7e3dbcf2-167f-4a63-9351-6fee72a192c9','過東亭湖','喻良能','宋','宋诗','song-poetry','','[]','籃輿詰旦過東亭，日出烟銷十里平。',64,'全唐诗/poet.song.144000.json','["籃輿詰旦過東亭，日出烟銷十里平。", "翠袖舞風菰葉舉，紅粧照水藕花生。", "恨無釣艇浮深碧，頼有吟毫賦曉晴。", "歸對老人誇勝賞，從今不數鑑湖清。"]'),
('7b3d7b65-16cc-4c27-8f99-decd1e9a1092','席上','喻良能','宋','宋诗','song-poetry','','[]','奉常珍重末僚情，許以疎慵簉俊英。',64,'全唐诗/poet.song.144000.json','["奉常珍重末僚情，許以疎慵簉俊英。", "已辦初筵酬物色，更將餘事到詩盟。", "貪吟不惜揮貂筆，忍醉何妨釂兕觥。", "細踏芳菲過腴潤，桃蹊紅雨報新晴。"]'),
('5e6d4a82-e3fb-4ea3-b13d-c3c6c9aa08ab','送陳給事帥四川  其一','喻良能','宋','宋诗','song-poetry','','[]','四海繁華一蜀都，君王謀帥意渠渠。',64,'全唐诗/poet.song.144000.json','["四海繁華一蜀都，君王謀帥意渠渠。", "百城赤子煩摩撫，一代長材獲展舒。", "玉壘倚空充屏翰，鐵衣如洗護儲胥。", "袴鞾帕首郊迎處，想見旌麾入境初。"]'),
('912d1182-969e-409b-9500-41d635fa2238','送陳給事帥四川  其二','喻良能','宋','宋诗','song-poetry','','[]','禮樂詩書一世英，碧油青鬢二難并。',64,'全唐诗/poet.song.144000.json','["禮樂詩書一世英，碧油青鬢二難并。", "慣看詞翰流三峽，剩有精神驅五兵。", "暫向坤維聊鎮撫，却歸天闕致昇平。", "明年春水如天日，綵鷁乘風向帝京。"]'),
('9143e3c8-4738-40e5-85d7-514b1b5bf8d6','姜春坊以詩編見貽借題雪堂圖韻作詩爲謝','喻良能','宋','宋诗','song-poetry','','[]','紅顔話別浦邊秋，白髮同爲帝里留。',64,'全唐诗/poet.song.144000.json','["紅顔話別浦邊秋，白髮同爲帝里留。", "璧水庸庸參末坐，春坊犖犖冠名流。", "功名君且登麟閣，出處吾行具釣舟。", "餉我一編清似玉，五言端的繼蘇州。"]'),
('cc21794b-1609-442e-8878-5de942d452cb','李大著惠示詩卷次韻首篇爲謝獻之','喻良能','宋','宋诗','song-poetry','','[]','辱贈舂容卷軸新，懸知蚤歲擅詩聲。',64,'全唐诗/poet.song.144000.json','["辱贈舂容卷軸新，懸知蚤歲擅詩聲。", "千林有韻霜風勁，一點無塵霽月清。", "細味班香兼宋艷，自慚白俗與元輕。", "欲哦惡語賡妍倡，一夜昏花對短檠。"]'),
('120dae7a-2690-445d-b351-1e08175ed99e','史丞相生辰  其一','喻良能','宋','宋诗','song-poetry','','[]','姓名久已覆金甌，一品師臣德業優。',64,'全唐诗/poet.song.144000.json','["姓名久已覆金甌，一品師臣德業優。", "黼扆尚詢黄髮舊，衮衣難伴赤松遊。", "松筠勁節高三事，桃李濃陰徧九州。", "蕭葉楊門端可繼，只今衮衮富公侯。"]'),
('2a17ffe0-a9ab-4a16-9d8f-82210f8013fa','史丞相生辰  其二','喻良能','宋','宋诗','song-poetry','','[]','長才蚤立太平基，奧學曾爲帝者師。',64,'全唐诗/poet.song.144000.json','["長才蚤立太平基，奧學曾爲帝者師。", "謀叶不資同列斷，規存長許後人隨。", "金魚玉带今誰似，橘綠橙黄景最宜。", "再拜祝公千萬壽，三江細酌入瑶巵。"]'),
('9908afbd-2b2a-4e7d-b78d-7f6d0809b6da','洪右相生辰  其一','喻良能','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','鳳將南呂入筩聲，節近中秋協氣橫。',64,'全唐诗/poet.song.144000.json','["鳳將南呂入筩聲，節近中秋協氣橫。", "玉燕呈祥生碩德，金甌覆字佐昇平。", "望同北斗泰山重，操與秋霜烈日爭。", "昨夜清臺占越分，中台星带老人明。"]'),
('512e7164-a623-4ee4-b83b-61852f16eb2c','洪右相生辰  其二','喻良能','宋','宋诗','song-poetry','','[]','黄閤調元鬢未霜，祇應書考似汾陽。',64,'全唐诗/poet.song.144000.json','["黄閤調元鬢未霜，祇應書考似汾陽。", "懇辭閶闔沙堤路，暫樂蓬萊燕寢香。", "茂烈未饒周叔虎，英詞寧謝漢班揚。", "會看繡衮重催起，快卷三江入壽觴。"]'),
('229968ff-ba4f-4341-b931-8a102f0caf91','次韻和宗郎中中秋不飲','喻良能','宋','宋诗','song-poetry','','[]','暮烟收盡玉盤生，是處同欣此夜晴。',64,'全唐诗/poet.song.144000.json','["暮烟收盡玉盤生，是處同欣此夜晴。", "雲斷三山凝紫翠，星稀萬里湛虛明。", "低臨朱箔千尋白，高並銀潢一派清。", "頼有綵衣堪醉舞，殘樽深夜更重傾。"]'),
('e0c233c8-a10e-4f0c-b967-0d1c7d586828','挽司理奉議樓公','喻良能','宋','宋诗','song-poetry','','[]','老爛爲儒山澤臞，半生辛苦就名譽。',64,'全唐诗/poet.song.144000.json','["老爛爲儒山澤臞，半生辛苦就名譽。", "三千白髮身無事，一點青燈夜讀書。", "真率杯盤如洛會，崎嶇巖壑似陶廬。", "欲知老淚揮難盡，灑徧霜飆更濕裾。"]'),
('39a76116-0970-4136-bbb3-6fab5f332cbc','次馬撫幹韻贈黄泰之狀元','喻良能','宋','宋诗','song-poetry','','[]','褎然射策向明光，紫禁春深日正長。',64,'全唐诗/poet.song.144000.json','["褎然射策向明光，紫禁春深日正長。", "風細御爐烟冉冉，天晴宮柳絮茫茫。", "玉階親奉唐虞問，綵筆濃薰班馬香。", "千佛經中名第一，鴻文端不數長楊。"]'),
('a944c431-44b3-4869-bc83-1dfa41de9a8e','次韻王侍御題詩史堂','喻良能','宋','宋诗','song-poetry','','[]','欲識當年泣鬼神，詩皆絹婦與虀辛。',64,'全唐诗/poet.song.144000.json','["欲識當年泣鬼神，詩皆絹婦與虀辛。", "洗空千古無凡馬，稱到於今有幾人。", "肯與齊梁充後乘，只應蘇李是前身。", "豐碑更著最佳處，傳示宜過一萬春。"]'),
('2999d1ac-1eaf-4b7f-9381-78fe1b39a5cc','十月二十三日携家遊裴園','喻良能','宋','宋诗','song-poetry','','[]','笋輿趁曉踏銅駝，休暇仍逢景色和。',64,'全唐诗/poet.song.144000.json','["笋輿趁曉踏銅駝，休暇仍逢景色和。", "閒挈壺觴游翠靄，盡呼兒女看滄波。", "茫茫烟渚羣鷗下，隠隠晴虹短棹過。", "最是小春奇絕處，梅花破萼未全多。"]'),
('a01baa4e-3d4d-4800-a435-9dc9a93cac08','謝中書施舍人宴集','喻良能','宋','宋诗','song-poetry','','[]','紫微高義篤同年，邃宇開筵近臘寒。',64,'全唐诗/poet.song.144000.json','["紫微高義篤同年，邃宇開筵近臘寒。", "綠蟻醅濃粘玉盞，紫駝峯美照金盤。", "醺酣上頰生春意，文字清談卜夜闌。", "更辱盤飱餽黄髮，顧慚珍報乏琅玕。"]'),
('3ff751fc-1bbb-46fc-b40f-cdc4a4689765','試諸生直廬書事','喻良能','宋','宋诗','song-poetry','','[]','長日初隨綵線還，陰陰簾幕曲欄干。',64,'全唐诗/poet.song.144000.json','["長日初隨綵線還，陰陰簾幕曲欄干。", "白袍三百近洙泗，青桂兩株如廣寒。", "下筆萬蠶爭食葉，爲文三峽瀉驚湍。", "誰知潦倒真無補，不媿無氈媿素餐。"]'),
('8089fc99-ad20-4bc6-99c7-bbb540cd230f','安撫大資李參政生辰  其一','喻良能','宋','宋诗','song-poetry','','[]','仙李盤根幾百秋，我公勳業比伊周。',64,'全唐诗/poet.song.144000.json','["仙李盤根幾百秋，我公勳業比伊周。", "推恩已解宏元化，戢患猶能庇七州。", "不日定爲黄閤老，他年應伴赤松游。", "三江願得渾爲酒，壽斝年年給獻酬。"]'),
('d56648ce-ea0b-417d-8f5d-203b96883d38','安撫大資李參政生辰  其二','喻良能','宋','宋诗','song-poetry','','[]','崧嶽生申占臘前，預將和氣作春妍。',64,'全唐诗/poet.song.144000.json','["崧嶽生申占臘前，預將和氣作春妍。", "蟠桃結實三千歲，蓮葉成巢幾百年。", "聊向蓬萊開燕寢，即紆衮繡畫凌烟。", "只應便是神仙事，方丈瀛洲却未然。"]'),
('b245847e-1d54-4731-87b2-09ebaf0b63c1','次韻宋嗣宗梅花  其一','喻良能','宋','宋诗','song-poetry','','[]','野外江頭一樹垂，正當霜後臘前時。',64,'全唐诗/poet.song.144000.json','["野外江頭一樹垂，正當霜後臘前時。", "清如弘景松臨閣，韻似淵明菊映籬。", "鐵石廣平曾作賦，風流水部亦哦詩。", "却愁折向粧臺下，莫遣佳人取次知。"]'),
('862b3d6d-1dc7-42df-ba9e-a82561ea90d0','次韻宋嗣宗梅花  其二','喻良能','宋','宋诗','song-poetry','','[]','洗盡紅粧見玉顔，一年相別此時看。',64,'全唐诗/poet.song.144000.json','["洗盡紅粧見玉顔，一年相別此時看。", "房陵粉水休爭白，姑射冰肌巧耐寒。", "自愛一枝橫竹外，未須千樹繞江干。", "東風也是相欺得，已作和羹一點酸。"]'),
('10107af7-72d0-43b8-8c7c-9dccb7751c42','次韻謝察院田寺丞倡酬之作','喻良能','宋','宋诗','song-poetry','','[]','兩翁辭采偶同時，春草還應夢謝池。',64,'全唐诗/poet.song.144000.json','["兩翁辭采偶同時，春草還應夢謝池。", "出月穿天端有意，掀雷抉電豈無期。", "推門不作孤吟苦，擊鉢猶嫌得句遲。", "顧我無才難入社，焚香時許誦清詩。"]'),
('90d100c3-b7bb-49b6-b18d-34956964c8da','平湖','喻良能','宋','宋诗','song-poetry','','[]','平湖瀲瀲浸葱蒼，畫出風烟十畝强。',64,'全唐诗/poet.song.144000.json','["平湖瀲瀲浸葱蒼，畫出風烟十畝强。", "蜜曲六從霜後熟，玉芙蓉向露中芳。", "新開石洞連松碧，低結萸房映菊黄。", "最愛隄邊秦地柳，一回春到一回長。"]'),
('13e5af2b-b49f-4709-bc3c-a9db6b1bab98','思歸','喻良能','宋','宋诗','song-poetry','','[]','五載懷歸不得歸，故園想像每依依。',64,'全唐诗/poet.song.144000.json','["五載懷歸不得歸，故園想像每依依。", "蠶生村落桑黄長，麥熟田家稚子肥。", "谷鳥緩歌金縷曲，籜龍渾著老萊衣。", "一篇未就張衡賦，漫向成均詠式微。"]'),
('c0f45338-315e-4869-aee5-d17477bc03db','挽周子及','喻良能','宋','宋诗','song-poetry','','[]','灑落孤標迥不羣，胸羅星宿富多文。',64,'全唐诗/poet.song.144000.json','["灑落孤標迥不羣，胸羅星宿富多文。", "兩科擢第未爲貴，八事籌邊堪策勳。", "鯁亮諫辭端似賈，崎嶇宦路僅勝蕡。", "我慚不執雲溪紼，空望雲溪溪上雲。"]'),
('a6e3236d-9372-4c7c-83ec-0afec4354f83','顯謨左司周公元吉將漕湖北一時名流賦詩餞行予與左司同出於詹事周公之門爲同門同居班列二年爲同朝同考類試於貢闈爲同寮三者既同契好彌篤於其行也作長句以送之','喻良能','宋','宋诗','song-poetry','','[]','微雲疎雨凉新秋，皇皇玉節摻不留。',64,'全唐诗/poet.song.144000.json','["微雲疎雨凉新秋，皇皇玉節摻不留。", "夫君不憚原隰險，聖主坐寬宵旰憂。", "巴音聊復祖行色，楚水恨不尾仙舟。", "籍籍預傳新漕輓，汗青未數富民侯。"]'),
('14d214e3-7d92-440a-8355-3643649a3cf0','黄泰之郎中以潮陽詩見貽次韻一篇奉酬','喻良能','宋','宋诗','song-poetry','','[]','千里潮陽喜政成，五年重會帝王城。',64,'全唐诗/poet.song.144000.json','["千里潮陽喜政成，五年重會帝王城。", "尺書不寄頭俱白，一笑相逢意已傾。", "輝采共看新列宿，風流猶記古州瀛。", "詩編總是驚人語，怪得年來太瘦生。"]'),
('a44694ca-c7bb-48af-9cb4-50f062707166','贈樓尉','喻良能','宋','宋诗','song-poetry','','[]','誰識尊前戲綵身，鬚髯如棘鬢如銀。',64,'全唐诗/poet.song.144000.json','["誰識尊前戲綵身，鬚髯如棘鬢如銀。", "久爲朝士空餐甚，又見秋聲滿耳新。", "元亮祇思三逕樂，子雲何事九衢塵。", "襟期蘭契如君少，未可匆匆動去輪。"]'),
('a93abadb-c1b3-4ddc-b802-71f7971d2586','挽提宮知丞周公','喻良能','宋','宋诗','song-poetry','','[]','妙齡馳譽滿東吳，落筆驊騮走坦途。',64,'全唐诗/poet.song.144000.json','["妙齡馳譽滿東吳，落筆驊騮走坦途。", "四十年來鳴道學，一千人內最羣儒。", "二松不負經綸志，三逕真成隠遯娛。", "老我與君端莫逆，遺文時閲漫長吁。"]'),
('6e4753cd-3627-4340-b190-acf2d35bc5ef','送曾大卿將漕江東','喻良能','宋','宋诗','song-poetry','','[]','公去何嘗負二宜，要持玉節瑞明時。',64,'全唐诗/poet.song.144000.json','["公去何嘗負二宜，要持玉節瑞明時。", "江畿列郡皆爭睹，臺閣名流總賦詩。", "鵰鶚暫爲雲外舉，鳳凰終集上林枝。", "近臣侍從多虛位，會見回帆春色隨。"]'),
('fc7f3c57-e2ef-468c-afe7-204801f8f3d4','悼吳居厚','喻良能','宋','宋诗','song-poetry','','[]','學問從來著月評，慈恩何事欠題名。',64,'全唐诗/poet.song.144000.json','["學問從來著月評，慈恩何事欠題名。", "賢哉難老堂雖就，惜也陳情表未成。", "疇昔幾回同把酒，於今一涕獨霑纓。", "張公當日稱操履，江漢傷心晝夜傾。"]'),
('86cb4991-4c23-41fb-aea9-8c251be9b83d','由之流溪回亭午苦熱小憩牧馬寺','喻良能','宋','宋诗','song-poetry','','[]','長途畏日欲流金，聊向招提覓快襟。',64,'全唐诗/poet.song.144000.json','["長途畏日欲流金，聊向招提覓快襟。", "翠合苔痕人寂寂，凉生柏影院深深。", "苦無俗物敗佳思，况有寒泉醒客心。", "一餉清風寄蘄竹，又飛征蓋指城陰。"]'),
('2635e329-018e-4c64-a05b-775d0450e3f0','九日偕成均同官北山登高二首','喻良能','宋','宋诗','song-poetry','','[]','輕霞朝日兩微茫，沙路駸駸十里强。',64,'全唐诗/poet.song.144000.json','["輕霞朝日兩微茫，沙路駸駸十里强。", "照水有情楓葉赤，倚崖無數菊花黄。", "興酣爭舉凌雲筆，醉熟重浮灧海觴。", "明日蝶愁人亦懶，未須歸去苦匆忙。"]'),
('11ce38cb-8efa-4ca5-a62b-6e123c95eaba','之官括蒼道出涵碧因題四韻以繼賓客劉公之後塵云','喻良能','宋','宋诗','song-poetry','','[]','平生性僻耽山水，不願加封萬戶侯。',64,'全唐诗/poet.song.144000.json','["平生性僻耽山水，不願加封萬戶侯。", "但得雙魚長到眼，未須萬壑更爭流。", "只今奇絕齊三洞，自昔流傳徧九州。", "記得當年小盤礴，坐令炎赫變清秋。"]'),
('ade8aed4-1476-4812-ab48-73572c41528f','再遊東陽','喻良能','宋','宋诗','song-poetry','','[]','十年不到還重來，往事一夢真悠哉。',64,'全唐诗/poet.song.144000.json','["十年不到還重來，往事一夢真悠哉。", "尋幽已訪涵碧寺，乘興欲上吳寧臺。", "蒼松怪石雖飽覽，黄鈿拒霜猶未開。", "白雲西來入我念，又馭兩腋清風迴。"]'),
('65c40c60-8f8d-4369-8314-a350e6a0fa25','松峭山傍偃松昔嘗過之爲賦長句今三十有六年矣復至其下慨然有感因次韻','喻良能','宋','宋诗','song-poetry','','[]','人日肩輿度曉峯，長松偃蹇倚晴空。',64,'全唐诗/poet.song.144000.json','["人日肩輿度曉峯，長松偃蹇倚晴空。", "幾年不見根如鐵，老境重來鬢似蓬。", "獨樹未須誇老杜，五楸那復論韓公。", "青幢翠蓋貌難似，想見霏霏烟雨濛。"]'),
('c0938020-f8b4-490d-ae5d-55d403c38798','遊下巖過松峭祠傍偃松又賦長句','喻良能','宋','宋诗','song-poetry','','[]','誰將秋色替雲峯，萬里炎歊一洗空。',64,'全唐诗/poet.song.144000.json','["誰將秋色替雲峯，萬里炎歊一洗空。", "細雨復青池上草，西風頓白鬢邊蓬。", "聊同吾黨二三子，來訪山中十八公。", "更擬夜深乘月到，要看香霧共冥濛。"]'),
('3e33cbf7-95fa-4b48-b206-79d71c11edf7','州宅','喻良能','宋','宋诗','song-poetry','','[]','古栝提封接日畿，專城皓首有光輝。',64,'全唐诗/poet.song.144000.json','["古栝提封接日畿，專城皓首有光輝。", "全家飽煖君恩重，屬邑豐登公事稀。", "一簇樓臺居洞府，四時風景對屏幃。", "多慚郎省無裨補，丐外猶能占翠微。"]'),
('6ba84c61-a1d8-4bec-b4d5-163fac4094a5','次韻奉酬王給事見貽之什','喻良能','宋','宋诗','song-poetry','','[]','誰知州宅似精廬，山繞簷楹水繞除。',64,'全唐诗/poet.song.144000.json','["誰知州宅似精廬，山繞簷楹水繞除。", "堂靜惠風長細細，樓高烟雨又疎疎。", "貧如坡老工餐菊，性似邊韶懶讀書。", "頼有嵩山王給事，作詩貽贈問何如。"]'),
('d38ad3e0-704c-4caf-ab2c-5192572a99cd','簽廳落成爲賦長句','喻良能','宋','宋诗','song-poetry','','[]','幕中英俊許誰先，一一驊騮擬著鞭。',64,'全唐诗/poet.song.144000.json','["幕中英俊許誰先，一一驊騮擬著鞭。", "老我漫誇森畫㦸，夫君端稱泛紅蓮。", "鳩工已見成輪奐，載酒何妨醉聖賢。", "聞道公餘多暇隙，定持椽筆籋雲烟。"]'),
('ebe7d9bb-c3f1-416d-9852-963244798196','對廳口號','喻良能','宋','宋诗','song-poetry','','[]','歡聲喜氣溢黄堂，解慍風清化日長。',64,'全唐诗/poet.song.144000.json','["歡聲喜氣溢黄堂，解慍風清化日長。", "簪紱盡傾千里目，冕旒遥祝萬年觴。", "韻敲碧玉檀欒嫩，色鬭紅粧菡萏香。", "共慶龐恩新浹洽，聖君文母壽無疆。"]'),
('4a06d8d3-4cb7-4148-967a-1a941dbecf24','十一月十日同幕府諸公游郡圃葉撫屬得梅花一枝馬撫屬有詩因次韻','喻良能','宋','宋诗','song-poetry','','[]','橫枝十月要清詩，南國今年爾許遲。',64,'全唐诗/poet.song.144000.json','["橫枝十月要清詩，南國今年爾許遲。", "夢繞故山千疊疊，眼看新萼一枝枝。", "欲知影瘦香微處，未稱天寒日暮時。", "却憶玉溪當日樹，淺霜深雪總相宜。"]'),
('25f44a06-a511-4efd-a7a0-2a2d772ab046','次韻木藴之狀元義烏道中一首','喻良能','宋','宋诗','song-poetry','','[]','奔走塵埃老未休，每思上下兩巖稠。',64,'全唐诗/poet.song.144000.json','["奔走塵埃老未休，每思上下兩巖稠。", "關心簿領三書考，回首家山兩換秋。", "搘腹自憐鷦鼴小，江湖誰計鴈鳬留。", "又遮西日長安去，慚媿平生馬少游。"]'),
('63776350-87af-42d9-8922-72cda1e0cc12','送黄機宜叔愚歸省四明','喻良能','宋','宋诗','song-poetry','','[]','灑落孤標第一流，笑談傾座氣橫秋。',64,'全唐诗/poet.song.144000.json','["灑落孤標第一流，笑談傾座氣橫秋。", "聊參機密東州幕，曾與風流玉局游。", "聽雨忽驚形夢寐，臨風那肯更遲留。", "橘堂想像多佳致，恨不追參李郭舟。"]'),
('aad375b3-acc1-4e1e-a1a8-31adaee34641','愛山','喻良能','宋','宋诗','song-poetry','','[]','公子漫誇金谷富，先生祇愛玉川貧。',64,'全唐诗/poet.song.144000.json','["公子漫誇金谷富，先生祇愛玉川貧。", "山中矯矯七君子，堂上皤皤四老人。", "時引壺觴聊自醉，肯教鵝鴨惱比隣。", "深紅淺白兼穠紫，看取林園十畝春。"]'),
('92417886-fb42-4db6-aa1c-aeb5ec38c3e1','彥禮知丞上巳過訪流觴於愛山之曲水','喻良能','宋','宋诗','song-poetry','','[]','年來曲水競流觴，元巳夫君訪草堂。',64,'全唐诗/poet.song.144000.json','["年來曲水競流觴，元巳夫君訪草堂。", "波撼石麟杯斚亂，風翻花片笑談香。", "哦松適意清篇富，閉戶端憂白日長。", "更約來年春好處，重來相與醉滄浪。"]'),
('2dbcaac6-99a6-42b7-a0ac-e34639b45c8c','次王待制維舟弄水亭韻','喻良能','宋','宋诗','song-poetry','','[]','萬里浮江更絕湖，扁舟東入霅川圖。',64,'全唐诗/poet.song.144000.json','["萬里浮江更絕湖，扁舟東入霅川圖。", "莫言舊菊荒三徑，須信中流待一壺。", "今日詩筒煩遠寄，昔年樽酒記相呼。", "立朝大節人能說，月在青天影自孤。"]'),
('d9e3fc76-2edd-4ecb-a898-63c1a266dfa0','三月二十四再到永祐陵','喻良能','宋','宋诗','song-poetry','','[]','扁舟投曉出重城，春浪初肥綠滿汀。',64,'全唐诗/poet.song.144000.json','["扁舟投曉出重城，春浪初肥綠滿汀。", "竹裏幾聲泥滑滑，河邊十里草青青。", "人家艾葉驚飛燕，水面楊花點翠萍。", "漸近昭陵佳氣集，五雲松柏喜重經。"]'),
('33c41d74-3d05-426a-b57b-23acb130799c','己酉中秋','喻良能','宋','宋诗','song-poetry','','[]','磬湖秋半溢清波，一歲月明今夕多。',64,'全唐诗/poet.song.144000.json','["磬湖秋半溢清波，一歲月明今夕多。", "剩辦新詩娛老境，滿傾太白醉冰娥。", "一天風露寒衣袂，舉室兒童雜笑歌。", "不是鈷潭奇絕處，未妨丁夜更娑婆。"]'),
('45afa4d9-7602-4def-82bb-6e7dd3977f89','盆池','喻良能','宋','宋诗','song-poetry','','[]','小鑿方池供醉吟，纔添斗水浪偏深。',64,'全唐诗/poet.song.144000.json','["小鑿方池供醉吟，纔添斗水浪偏深。", "瑩心未數寒泉井，明目何須寸碧岑。", "樹影落時清浸玉，魚鱗動處細浮金。", "年來點檢曾經汲，唯有澆花趁日陰。"]'),
('81daee75-2788-47ac-86e0-50f0c68bcaa2','中秋愛山翫月','喻良能','宋','宋诗','song-poetry','','[]','年年秋半在長安，今夕園林且盡歡。',64,'全唐诗/poet.song.144000.json','["年年秋半在長安，今夕園林且盡歡。", "一笑團欒人似月，十分瀲灧酒生瀾。", "徧簪丹桂香巾袂，盡吸清輝澡肺肝。", "飲罷月斜吟興動，揮毫風露一天寒。"]'),
('4e865a7e-9185-484c-a16b-0f7c64cece25','次韻何茂恭重陽前二日見過','喻良能','宋','宋诗','song-poetry','','[]','西風籬落興悠然，秋影橫江鴈貼天。',64,'全唐诗/poet.song.144000.json','["西風籬落興悠然，秋影橫江鴈貼天。", "短髮未成吹帽飲，高吟先贈把茱篇。", "黄花一笑小重九，青眼相看又四年。", "欲試烟波釣竿手，南湖同上月明船。"]'),
('f4f83301-781a-4c31-bba6-d8411d94b000','磬湖之側累拳石爲山巖谷幽邃有巫廬台霅之趣因成短篇','喻良能','宋','宋诗','song-poetry','','[]','背湖臨檻碧崔嵬，萬壑千巖咫尺開。',64,'全唐诗/poet.song.144000.json','["背湖臨檻碧崔嵬，萬壑千巖咫尺開。", "坐覺巫峯天際落，忽驚廬阜眼中來。", "地偏未害心還遠，潭小何妨水自回。", "竟日相看兩不厭，老夫真箇似童孩。"]'),
('02ee8913-a216-4fc1-8797-c0eb7347b857','次韻奉酬參議林郎中見貽之作','喻良能','宋','宋诗','song-poetry','','[]','紫宸疇昔幸同朝，去國俄驚數舍遥。',64,'全唐诗/poet.song.144000.json','["紫宸疇昔幸同朝，去國俄驚數舍遥。", "輕細難沾時服賜，氤氳正想御香飄。", "年加頼有斑衣戲，心靜真同桂隠招。", "龍瑞此時探禹穴，天津何日渡京橋。"]'),
('ecd48361-fa41-4e20-a0a2-0422d9f3744d','自題木假山','喻良能','宋','宋诗','song-poetry','','[]','根幹輪囷蔽馬牛，何年飄泊寄滄洲。',64,'全唐诗/poet.song.144000.json','["根幹輪囷蔽馬牛，何年飄泊寄滄洲。", "幽巖邃壑漁罾得，百巧千奇雲浪鎪。", "好喚老泉來作記，肯將居士與同遊。", "畢宏韋偃丹青妙，畫得天然意緒不。"]'),
('4ddb7291-921b-4bbb-be97-4903580d1897','次韵奉酬茂恭送茉莉重臺白蓮','喻良能','宋','宋诗','song-poetry','','[]','異暑歊然金欲流，縞裙練帨兩宜秋。',64,'全唐诗/poet.song.144000.json','["異暑歊然金欲流，縞裙練帨兩宜秋。", "笑他山谷誇黄鈿，欲學令狐賦白樓。", "粉筆有心爭試巧，紅粧無面可障羞。", "明來自足映茆屋，况有詩輕萬戶侯。"]'),
('5418fab5-c551-46fe-9444-0e2398fc94ac','亦好園海棠秋開紅英滿樹','喻良能','宋','宋诗','song-poetry','','[]','微雲澹日映寒流，畫出西園一幅秋。',64,'全唐诗/poet.song.144000.json','["微雲澹日映寒流，畫出西園一幅秋。", "白帝幻成紅玉蘂，金風吹綻碧枝頭。", "睡餘艷艷真妃子，夢罷愔愔一解愁。", "熟賞細看須著句，爲君重賦紫綿揉。"]'),
('f9be1689-b350-4740-8d36-fb3aea1cce74','次韻張持荷桂花','喻良能','宋','宋诗','song-poetry','','[]','別駕風流繼竹林，名園幽榭水雲深。',64,'全唐诗/poet.song.144000.json','["別駕風流繼竹林，名園幽榭水雲深。", "勻鋪葉底森森碧，細糝枝頭粟粟金。", "酒酌香浮杯面蟻，詩成霜灑月中砧。", "清芬冉冉仍多韻，不比晴窗一穗沉。"]'),
('58f239b6-75f6-46d5-ad35-de7a85426976','庚戌中秋病起言懷','喻良能','宋','宋诗','song-poetry','','[]','病來十日不飲酒，起對中秋良可人。',64,'全唐诗/poet.song.144000.json','["病來十日不飲酒，起對中秋良可人。", "銀漢迢迢清未了，金波瀲瀲浄無塵。", "艷歌未暇成三疊，美醖何妨釂十分。", "記得昔年當此景，厭厭夜飲在成均。"]'),
('e7252e2e-c43c-4ed9-861f-4e7c56b5e8f5','九日亦好園小集','喻良能','宋','宋诗','song-poetry','','[]','疎雨蕭蕭岩桂香，西風驅冷作重陽。',64,'全唐诗/poet.song.144000.json','["疎雨蕭蕭岩桂香，西風驅冷作重陽。", "池塘秋草還爭綠，籬落寒花未肯黄。", "又是一年新度節，何妨九客共飛觴。", "園亭低小殽蔬陋，不比龍山吟帽狂。"]'),
('6feede22-38d1-47fd-9bcd-64dff800a314','雪  其一','喻良能','宋','宋诗','song-poetry','','[]','密雪乘風逞素肌，穿窗透隙入簾幃。',64,'全唐诗/poet.song.144000.json','["密雪乘風逞素肌，穿窗透隙入簾幃。", "漫空隠隠瓊瑰屑，亂眼紛紛鷗鷺飛。", "三客新成梁苑賦，六花又舞謝莊衣。", "回思拜表明光罷，携得香烟滿袖歸。"]'),
('31b0fac2-30ce-4d3e-bb3d-818538d50057','雪  其二','喻良能','宋','宋诗','song-poetry','','[]','長風永夜攪青冥，曉起寒光亂眼凝。',64,'全唐诗/poet.song.144000.json','["長風永夜攪青冥，曉起寒光亂眼凝。", "回旋舞空端入畫，飄蕭著水自成冰。", "松篁被練三千士，岡阜瑶臺十二層。", "茆舍倍添薪火費，只因無事讀書燈。"]'),
('88985e0d-4796-4666-90bd-995993d4b5f7','題淵明祠堂','喻良能','宋','宋诗','song-poetry','','[]','宅邊雖有五柳樹，歸去已荒三徑園。',64,'全唐诗/poet.song.144000.json','["宅邊雖有五柳樹，歸去已荒三徑園。", "平生胸中羞五斗，偶爾城市羨華軒。", "盈樽濁酒自可漉，得趣古琴那用絃。", "欲知耿耿忠憤意，甲子斷自永初年。"]'),
('7f29d2a9-1240-48ec-b8b4-e4b15a6dfced','輦下言懷','喻良能','宋','宋诗','song-poetry','','[]','馬蹄重踏帝京塵，七載江湖飽問津。',64,'全唐诗/poet.song.144000.json','["馬蹄重踏帝京塵，七載江湖飽問津。", "白髮有人疑甲子，清齋無日不庚申。", "不才詎敢誣明主，厚祿那能羨故人。", "乞得泮宮閩粵去，未妨閒處著吾身。"]'),
('19cc27b9-3a86-4347-9a21-bdf0710acc48','桐汭','喻良能','宋','宋诗','song-poetry','','[]','東汭波吞岸，西桐水見沙。',120,'全唐诗/poet.song.144000.json','["東汭波吞岸，西桐水見沙。", "祠山千古盛，州宅四時嘉。", "前直三峰峻，旁連大洞呀。", "黄南清港曲，織女小橋斜。", "野店籬爲戶，春山繭作花。", "烏羊難入饌，青果頗宜茶。", "綳錦饒新筍，槍旗富嫩芽。", "靈山古佛地，丹井列仙家。", "鐵冶名猶壯，金牛跡尚漥。", "滯留三載久，詩板滿煙霞。"]'),
('de85540a-7201-40dc-ad3c-be0b06afc733','試院中秋效諸進士作月湧大江流','喻良能','宋','宋诗','song-poetry','','[]','團月臨清夜，平分一半秋。',72,'全唐诗/poet.song.144000.json','["團月臨清夜，平分一半秋。", "輪侵斜漢迥，色湧大江流。", "皎皎驚飛鵲，亭亭喘卧牛。", "一川寒練靜，十頃素光浮。", "碎彩通袁渚，餘輝謝庾樓。", "翻思杜陵老，岸草泊檣舟。"]'),
('7fb161ce-84bc-4462-a134-0a5a10cbc652','由上饒之貴溪舟中書事','喻良能','宋','宋诗','song-poetry','','[]','日月三秋杪，江山萬象殊。',288,'全唐诗/poet.song.144000.json','["日月三秋杪，江山萬象殊。", "小舟浮舴艋，廣信出闉闍。", "草木關詩律，雲煙入畫圖。", "水清沙可數，景好句難摹。", "汀際寒鳴鴈，檣端晚噪烏。", "樵村人語靜，商櫂夜燈孤。", "冷水尋宵泊，焦灘就曉餔。", "霧銷分浦溆，風定少帆蒲。", "愛日生篷背，奇峯湧坐隅。", "芙蓉多落蔕，楊柳有枯株。", "楓葉紅綃翦，蘆花白雪鋪。", "翩翩兩行鷺，泛泛一雙鳬。", "斷岸幾千尺，誅茅間一區。", "鷀巖清港急，龍瀨碧濤麤。", "斷已憑三老，那能貴一壺。", "酒壚勞問訊，漁艇費招呼。", "鮮鯽還堪買，香醪亦任沽。", "不妨成酩酊，聊復免馳驅。", "汭口真蕭鎮，錢倉豈舊爐。", "藂篁驚外裹，怪石覺中刳。", "漸喜三吳近，寧辭十里紆。", "波平如瀉鏡，罡密似連珠。", "嘯咏知誰和，欹眠只自娛。", "市聲喧弋邑，山雨鬧蓮湖。"]'),
('faba5b09-bb4f-4c0c-8213-8a483048150d','爲柴懷叔殿院題世綵堂','喻良能','宋','宋诗','song-poetry','','[]','慶積門闌久，祥鍾家世醲。',120,'全唐诗/poet.song.144000.json','["慶積門闌久，祥鍾家世醲。", "乘驄驚創見，戲綵覺重逢。", "鮐耋頻三喜，孫曾見八龍。", "年齡開九秩，孫子享千鍾。", "奕葉今榮耀，蟬聯舊素封。", "家風追萬石，眉壽擬三松。", "畫棟侵銀漢，平池浸碧峯。", "同心木芍藥，並蔕水芙蓉。", "委曲顔常悅，騫騰色愈恭。", "會須陶謝手，覓句細形容。"]'),
('f099e1de-64b6-46df-8955-55eba0e8f119','題東林寺','喻良能','宋','宋诗','song-poetry','','[]','江湖大蘭若，廬阜一東林。',144,'全唐诗/poet.song.144000.json','["江湖大蘭若，廬阜一東林。", "砌遶琮琤水，門羅翠碧岑。", "煙雲千古色，松檜四時陰。", "岸幘銷塵慮，凭欄凈客心。", "殿成神運力，泉出虎跑音。", "溪在思元亮，堂荒憶醉吟。", "圖傳三笑粲，閣擁五杉森。", "貝葉應難訪，經臺已莫尋。", "僧袈何代朽，佛影幾時沉。", "晉輦黄埃久，殷碑蒼蘚深。", "不妨閒弔古，誰復爲沾襟。", "香火惟蓮社，傳流直至今。"]'),
('8631fd76-8801-42b6-97fe-f7eac4dbe0fa','送參議李器之','喻良能','宋','宋诗','song-poetry','','[]','人間今北海，天上謫仙人。',96,'全唐诗/poet.song.144000.json','["人間今北海，天上謫仙人。", "雄論堪醫國，新詩可泣神。", "摇毫雲落紙，揮麈坐生春。", "芸閣登吟慣，綾衾入直頻。", "三十辭故里，二載宦全閩。", "婉畫裨南閫，英名動北辰。", "惠風吹別思，細草碾征輪。", "行矣躋華要，聲猷日日新。"]'),
('9a5e655b-2a53-4414-a70e-d5107ae75c55','釋奠禮成上安撫大觀文十四韻','喻良能','宋','宋诗','song-poetry','','[]','鉅宋中興日，全閩極治年。',168,'全唐诗/poet.song.144000.json','["鉅宋中興日，全閩極治年。", "保釐須碩德，鎮撫頼真賢。", "燕寢何曾逸，儒宮最所先。", "上丁將蕆事，仲月乃修虔。", "鉶鼎參罍洗，犧尊間豆籩。", "低昂衮繡服，拜起冕旒前。", "庭燎明如晝，爐薰滃似煙。", "曏風人引領，觀禮士填咽。", "闔郡讙聲沸，熙朝盛事傳。", "僖公甘避路，常相敢差肩。", "宜有新詩播，庸昭美化宣。", "陋儒何幸會，典禮獲周旋。", "南紀非工部，中和豈子淵。", "斐然形頌述，深媿采芹篇。"]'),
('c2b40d86-c025-49e1-a107-b2e7cef4cedd','夜宿浮石山崇福寺上方題壁','喻良能','宋','宋诗','song-poetry','','[]','窈窕尋支徑，縈紆度密林。',96,'全唐诗/poet.song.144000.json','["窈窕尋支徑，縈紆度密林。", "岸回溪更駛，峯轉塢逾深。", "僧梵雲邊寺，鐘魚竹裏音。", "解鞍生妙興，倚檻凈煩襟。", "永夜凉飆動，初秋爽氣侵。", "巖空寒溜滴，壁靜候蟲吟。", "香篆窺孤宿，燈花伴獨斟。", "不諳塵外趣，誰識此時心。"]'),
('e32fbcba-669e-42e6-bcfc-a37485237d30','湖上用王茂材同年韻','喻良能','宋','宋诗','song-poetry','','[]','木落長空浄，秋深爽氣多。',72,'全唐诗/poet.song.144000.json','["木落長空浄，秋深爽氣多。", "澹煙浮遠樹，晶日泊平蓑。", "小艇浮深碧，孤筇曳慢坡。", "菊花簪雪鬢，桑落灧金荷。", "妙興追潘岳，清游軼永和。", "何當命菱角，唱我醉時歌。"]'),
('3608ff5a-e2c0-4f4f-8dd8-bd6fe4877ab9','過分水嶺初出建寧界','喻良能','宋','宋诗','song-poetry','','[]','辛卯踰閩嶠，淳熙出建關。',168,'全唐诗/poet.song.144000.json','["辛卯踰閩嶠，淳熙出建關。", "瀰漫第五渡，險絕百重山。", "近夏凉風發，新晴麗景還。", "翠烟飛縹緲，好鳥語綿蠻。", "密樹青羅幄，連峯碧玉環。", "野英紛剨剨，巖溜碎潺潺。", "小艇橫清泚，飛橋截碧灣。", "機舂流水激，架厂石崖慳。", "紫笋和泥采，青梅带葉攀。", "未能供旨味，聊得悅慈顔。", "取醉三盃適，欹眠一餉閒。", "自憐霜鬢白，人羨綵衣斑。", "物色揮毫裏，家山隠几間。", "狂歌聊爾耳，同志儻吾刪。"]'),
('a93ab357-2318-4b0f-ba57-46dfd52a48d0','送江充之郎中知溫州','喻良能','宋','宋诗','song-poetry','','[]','巖廊拱神聖，岳牧用才良。',120,'全唐诗/poet.song.144000.json','["巖廊拱神聖，岳牧用才良。", "委寄晉藩鎮，飛騰漢省郎。", "縑推非矯激，綿蕝豈尋常。", "花粲揮毫玉，風生漱齒霜。", "兒童騎截竹，父老候甘棠。", "五馬晴薰細，雙旌曉月凉。", "清香凝燕寢，春草夢池塘。", "乳哺蘇民瘼，生薪束吏行。", "謝樓山色凈，孤嶼海天長。", "信美毋多戀，遄歸覲建章。"]'),
('d039674c-890a-4150-89dc-12c5b6d5b1b7','送趙達明太社知江州','喻良能','宋','宋诗','song-poetry','','[]','天上佳公子，人間少吏師。',96,'全唐诗/poet.song.144000.json','["天上佳公子，人間少吏師。", "文華紳笏服，名字冕旒知。", "剸决監州日，舂容栗社時。", "未成持從橐，聊復把州麾。", "京邑期蒙福，湓城望寵綏。", "朱轓臨境土，竹馬走童兒。", "去獸同均輩，蠲逋繼濬之。", "政成遄入覲，獻納日論思。"]'),
('efad8a8e-0e23-4c3e-b715-60c219a11a52','東宮生辰','喻良能','宋','宋诗','song-poetry','','[]','寶歷天重啟，皇圖日寖昌。',240,'全唐诗/poet.song.144000.json','["寶歷天重啟，皇圖日寖昌。", "九重資燕翼，萬國仰元良。", "玉律秋初杪，金飈歲正穰。", "前星輝采盛，少海慶源長。", "甲觀祥煙滃，春宮協氣翔。", "千秋佳節勝，四莢瑞蓂芳。", "瓜棗欣初獻，蟠桃慶乍嘗。", "庭羅六佾舞，天薦九霞觴。", "銀榜彌生耀，銅扉粲有光。", "讙聲連紫極，喜氣溢穹蒼。", "冊錫雕珉煥，旗頒青輅揚。", "衣惟珍黻冕，音不嗜宮商。", "問寢同周發，隆師過漢莊。", "猷爲規禹啟，翰墨掩鍾王。", "化被賓詹屬，恩沾左右坊。", "善三今獨冠，明兩古難方。", "陸贄言猶采，宣尼訓敢忘。", "本支綿百世，羽翼貳巖廊。", "宿忝宮僚舊，曾霑兌澤滂。", "願斟滄海酒，歲祝壽無疆。"]'),
('7e48d5ae-0a5b-470b-ba08-be3ebe0922f5','留別王狀元二十四韻','喻良能','宋','宋诗','song-poetry','','[]','才大文章伯，忠純社稷臣。',288,'全唐诗/poet.song.144000.json','["才大文章伯，忠純社稷臣。", "七州鍾秀異，孤嶼賦精神。", "德藴圭璋潤，胸涵海嶽春。", "麟經頻得雋，槐市早稱珍。", "宿弊時方革，皇綱上正親。", "大廷清問降，空臆讜言陳。", "力補嚴宸衮，深攖睿主鱗。", "一元追董相，多詐恥平津。", "文擅無雙價，臚傳第一人。", "聲華飛宇宙，風采聳簪紳。", "貴紙寧堪數，回天僅足倫。", "施行均令甲，奬諭見絲綸。", "未覆金甌墨，聊爲綠水賓。", "愛民如赤子，束吏似生薪。", "鑑水書題徧，稽山賦詠頻。", "却梅清節著，誣狗滯寃伸。", "賤子嗟何幸，同年蓋宿因。", "糟糠聊攝局，山水獲聯茵。", "醇酎容霑醉，新詩許效顰。", "獨蒙青眼舊，端異白頭新。", "酬倡幾千首，從游殆十旬。", "笑談將契闊，肝胆政輪囷。", "帝夢方思說，天民竚起莘。", "不才雖苦窳，終始願陶鈞。"]'),
('71f06441-b254-4a81-a07b-7793c9b696f9','亦好園羣花盛開戲成  其一','喻良能','宋','宋诗','song-poetry','','[]','小圃初乾曉雨，雜花爭試新粧。',28,'全唐诗/poet.song.144000.json','["小圃初乾曉雨，雜花爭試新粧。", "揉色似觀濯錦，吹香如過河陽。"]'),
('d8b04858-0324-4d67-b042-8ec37d7c07a7','亦好園羣花盛開戲成  其二','喻良能','宋','宋诗','song-poetry','','[]','三歲無諸國裏，青春不是花時。',28,'全唐诗/poet.song.144000.json','["三歲無諸國裏，青春不是花時。", "今日小園春半，百般紅紫芳菲。"]'),
('cf861b2e-205a-4af0-bd91-ecf55215084b','題李通判斷橋圖  其一','喻良能','宋','宋诗','song-poetry','','[]','平生心地夷坦，一旦足跟嶮巇。',28,'全唐诗/poet.song.144000.json','["平生心地夷坦，一旦足跟嶮巇。", "不是籃輿安穩，只應神物護持。"]'),
('838af69f-fd16-40f0-acef-7b17e03c4596','題李通判斷橋圖  其二','喻良能','宋','宋诗','song-poetry','','[]','橋上笋輿岌岌，橋下浪波沄沄。',28,'全唐诗/poet.song.144000.json','["橋上笋輿岌岌，橋下浪波沄沄。", "但覺往來無惱，不知觀者傷神。"]'),
('4c3650fa-3ffd-4d9a-bf7f-18e876bb12ae','書趙德莊詞後','喻良能','宋','宋诗','song-poetry','','[]','老眼看書成霧，介菴墨妙金篦。',28,'全唐诗/poet.song.144000.json','["老眼看書成霧，介菴墨妙金篦。", "波底斜陽紅濕，絕勝彩筆新題。"]'),
('3983206c-ff0d-4890-84e7-c2cc3d86e6d2','訪何茂恭於南湖作三絕句  其一','喻良能','宋','宋诗','song-poetry','','[]','十里相望烟樹，旬月不絕籃輿。',28,'全唐诗/poet.song.144000.json','["十里相望烟樹，旬月不絕籃輿。", "漱石枕流戲綵，浮家泛宅南湖。"]'),
('dd20ea37-c937-46d3-a966-194026f536fa','訪何茂恭於南湖作三絕句  其二','喻良能','宋','宋诗','song-poetry','','[]','南湖綠髮居士，恰少磬湖八年。',28,'全唐诗/poet.song.144000.json','["南湖綠髮居士，恰少磬湖八年。", "掀雷抉電傑句，出月穿天大篇。"]'),
('786682f2-5744-4e1e-83ee-64a12de7e06d','訪何茂恭於南湖作三絕句  其三','喻良能','宋','宋诗','song-poetry','','[]','啼饑妻子眼底，厚祿故人日邊。',28,'全唐诗/poet.song.144000.json','["啼饑妻子眼底，厚祿故人日邊。", "一錢不直誰念，五十無聞自憐。"]'),
('8d124fe3-11fb-4217-a61f-b26c90370dd6','茂恭見和再用前韻奉酬  其一','喻良能','宋','宋诗','song-poetry','','[]','朗朗百間羊肸，森森千丈長輿。',28,'全唐诗/poet.song.144000.json','["朗朗百間羊肸，森森千丈長輿。", "一身宜著臺閣，半生流落江湖。"]'),
('82df4b93-639c-44f5-b012-00c560c275ba','茂恭見和再用前韻奉酬  其二','喻良能','宋','宋诗','song-poetry','','[]','憶昔永新番水，俱吏江左三年。',28,'全唐诗/poet.song.144000.json','["憶昔永新番水，俱吏江左三年。", "不作載苡馬援，聊爲留犢苗篇。"]'),
('b0bdc96a-1482-49a6-9239-408e3b95a7b1','茂恭見和再用前韻奉酬  其三','喻良能','宋','宋诗','song-poetry','','[]','少陵時時醉裏，子山日日愁邊。',28,'全唐诗/poet.song.144000.json','["少陵時時醉裏，子山日日愁邊。", "白髮新來滿鏡，故人萬一能憐。"]'),
('cdbfcf49-dd04-4295-8bda-3b4fdab5ba90','磬湖居士得片石于斗坡山其長五尺其廣一尺有咫聳拔孤秀縝密溫潤絕不類此間石疑自他山飛來因目之曰飛來石','喻良能','宋','宋诗','song-poetry','','[]','六丁驅石日本，墮落斗坡山中。',56,'全唐诗/poet.song.144000.json','["六丁驅石日本，墮落斗坡山中。", "一片蒼珪紫玉，幾回秋雨春風。", "不假鎸鑱刻削，自然巧妙嵌空。", "居士置之朝爽，是謂飛來小峯。"]'),
('18a74ec2-3d83-4101-8fbf-36c94d9c9fe4','題齊山翠微亭','喻良能','宋','宋诗','song-poetry','','[]','山深雲氣多，撥雲尋徑入。',24,'全唐诗/poet.song.144000.json','["山深雲氣多，撥雲尋徑入。", "但覺襟袖寒，不知濃翠濕。"]'),
